def resolve_task_feishu_link(link_override: str | None = None) -> str:
    candidates = [
        (link_override or "").strip(),
        os.getenv("AI_DA_GUAN_JIA_FEISHU_LINK", "").strip(),
        DEFAULT_FEISHU_LINK.strip(),
    ]
    for candidate in candidates:
        if candidate:
            return candidate
    return ""


