def ensure_dir(path: Path) -> Path:
    path.mkdir(parents=True, exist_ok=True)
    return path


def now_local() -> datetime:
    return datetime.now().astimezone()


def iso_now() -> str:
    return now_local().isoformat(timespec="seconds")


def load_text(path: Path) -> str:
    return path.read_text(encoding="utf-8")


def parse_frontmatter(text: str) -> dict[str, Any]:
    match = re.match(r"^---\n(.*?)\n---(?:\n|$)", text, re.DOTALL)
    if not match:
        return {}
    frontmatter = match.group(1)
    try:
        import yaml  # type: ignore

        payload = yaml.safe_load(frontmatter)
        if isinstance(payload, dict):
            return payload
    except Exception:
        pass

    result: dict[str, Any] = {}
    lines = frontmatter.splitlines()
    index = 0
    while index < len(lines):
        line = lines[index]
        if ":" not in line:
            index += 1
            continue
        key, raw_value = line.split(":", 1)
        key = key.strip()
        value = raw_value.strip()
        if value in {"|", ">", "|-", ">-"}:
            index += 1
            block: list[str] = []
            while index < len(lines) and (lines[index].startswith("  ") or not lines[index].strip()):
                stripped = lines[index].strip()
                if stripped:
                    block.append(stripped)
                index += 1
            result[key] = " ".join(block)
            continue
        result[key] = value.strip("\"'")
        index += 1
    return result


def read_skill_metadata(skill_md: Path) -> dict[str, Any] | None:
    try:
        payload = parse_frontmatter(load_text(skill_md))
    except Exception:
        return None
    name = str(payload.get("name") or "").strip()
    description = str(payload.get("description") or "").strip()
    if not name:
        return None
    metadata = payload.get("metadata") if isinstance(payload.get("metadata"), dict) else {}
    source = str(metadata.get("source") or "").strip() if isinstance(metadata, dict) else ""
    return {"name": name, "description": description, "source": source}


def discover_skill_files() -> list[Path]:
    if not SKILLS_ROOT.exists():
        return []
    files = list(SKILLS_ROOT.glob("*/SKILL.md"))
    files.extend(SKILLS_ROOT.glob(".system/*/SKILL.md"))
    return sorted(path.resolve() for path in files if path.is_file())


def discover_skills() -> list[dict[str, Any]]:
    skills: list[dict[str, Any]] = []
    seen: set[str] = set()
    for skill_md in discover_skill_files():
        metadata = read_skill_metadata(skill_md)
        if not metadata:
            continue
        name = metadata["name"]
        if name in seen:
            continue
        seen.add(name)
        profile = CORE_PROFILES.get(name)
        entry = {
            "name": name,
            "description": metadata["description"],
            "path": str(skill_md.parent),
            "is_core": profile is not None,
            "merged_super_skill": merged_super_skill_for(name),
            "is_merged_legacy_member": bool(merged_super_skill_for(name)),
            "role": profile.role if profile else "Discovered local skill. Read SKILL.md before use.",
            "strengths": profile.strengths if profile else ["Discover from SKILL.md on demand"],
            "weaknesses": profile.weaknesses if profile else ["No curated profile yet"],
            "boundary": profile.boundary if profile else "Read the skill before routing real work to it.",
        }
        skills.append(entry)
    return sorted(skills, key=lambda item: item["name"])


def merged_super_skill_for(name: str) -> str:
    for super_skill, members in MERGED_SUPER_SKILL_MEMBERS.items():
        if name in members:
            return super_skill
    return ""


def filter_effective_routing_skills(
    skills: list[dict[str, Any]],
    mentioned: list[str],
) -> tuple[list[dict[str, Any]], list[dict[str, str]]]:
    available = {str(item.get("name") or "") for item in skills}
    mentioned_set = set(mentioned)
    effective: list[dict[str, Any]] = []
    suppressed: list[dict[str, str]] = []
    for skill in skills:
        name = str(skill.get("name") or "")
        super_skill = merged_super_skill_for(name)
        if super_skill and super_skill in available and name not in mentioned_set:
            suppressed.append(
                {
                    "legacy_skill": name,
                    "super_skill": super_skill,
                    "reason": "suppressed_by_merged_super_skill_default",
                }
            )
            continue
        effective.append(skill)
    return effective, suppressed


def prepare_routing_candidates(
    prompt: str,
    *,
    skills: list[dict[str, Any]] | None = None,
    signals: dict[str, bool] | None = None,
    governance: dict[str, Any] | None = None,
) -> dict[str, Any]:
    skills_raw = skills or discover_skills()
    signals = signals or detect_signals(prompt)
    governance = governance or load_governance_signals()
    mentioned = explicit_mentions(prompt, [item["name"] for item in skills_raw])
    effective_skills, suppressed = filter_effective_routing_skills(skills_raw, mentioned)
    ranked = [score_candidate(prompt, skill, signals, mentioned, governance) for skill in effective_skills]
    ranked.sort(key=lambda item: item["total_score"], reverse=True)
    return {
        "skills_raw": skills_raw,
        "signals": signals,
        "governance": governance,
        "mentioned": mentioned,
        "effective_skills": effective_skills,
        "legacy_members_suppressed": suppressed,
        "ranked": ranked,
    }


def discover_top_level_skill_files() -> list[Path]:
    if not SKILLS_ROOT.exists():
        return []
    return sorted(path.resolve() for path in SKILLS_ROOT.glob("*/SKILL.md") if path.is_file())


def skill_layer(name: str) -> str:
    if name.startswith(("ai-", "jiyao-", "skill-")) or name in {"knowledge-orchestrator", "self-evolution-max", "guide-benchmark-learning"}:
        return "元治理层"
    if name.startswith("agency-"):
        return "专家角色层"
    if name.startswith(("feishu-", "notion-", "github-", "gh-")) or name in {
        "figma",
        "figma-implement-design",
        "playwright",
        "playwright-interactive",
        "openai-docs",
        "cloudflare-deploy",
        "linear",
        "atlas",
        "chatgpt-apps",
        "screenshot",
    }:
        return "平台/工具集成层"
    return "垂直工作流层"


def skill_resource_flags(skill_dir: Path) -> dict[str, bool]:
    return {
        "scripts": (skill_dir / "scripts").exists(),
        "references": (skill_dir / "references").exists(),
        "assets": (skill_dir / "assets").exists(),
        "agents": (skill_dir / "agents").exists(),
    }


def metadata_source_repo(source: str) -> str:
    value = source.strip()
    if not value:
        return ""
    return value.split(":", 1)[0].strip()


def git_origin_repo(skill_dir: Path) -> str:
    if not (skill_dir / ".git").exists():
        return ""
    completed = subprocess.run(
        ["git", "-C", str(skill_dir), "remote", "get-url", "origin"],
        capture_output=True,
        text=True,
        check=False,
    )
    if completed.returncode != 0:
        return ""
    raw = completed.stdout.strip()
    if raw.startswith("git@github.com:"):
        raw = raw.split(":", 1)[1]
    elif "github.com/" in raw:
        raw = raw.split("github.com/", 1)[1]
    raw = raw.removesuffix(".git").strip("/")
    return raw


def repo_storage_name(repo: str) -> str:
    return repo.replace("/", "__")


def hub_repo_dir(repo: str) -> Path:
    return HUB_REPOS_ROOT / repo_storage_name(repo)


def hostname_slug() -> str:
    raw = socket.gethostname().strip() or "unknown-host"
    return normalize_slug_part(raw)


def default_source_id() -> str:
    value = os.getenv("AI_DA_GUAN_JIA_SOURCE_ID", "").strip()
    if value:
        return normalize_slug_part(value)
    return hostname_slug()


def default_satellite_fleet_specs() -> list[dict[str, Any]]:
    return [dict(item) for item in DEFAULT_SATELLITE_FLEET_SPECS]


def default_satellite_spec_map() -> dict[str, dict[str, Any]]:
    return {
        str(item.get("satellite_id") or ""): dict(item)
        for item in default_satellite_fleet_specs()
        if str(item.get("satellite_id") or "")
    }


def remote_onboarding_artifact_path(source_id: str) -> Path | None:
    normalized_source = normalize_slug_part(source_id)
    for root in [REMOTE_HOSTS_V2_ROOT, REMOTE_HOSTS_ROOT]:
        path = root / normalized_source / "onboarding-result.json"
        if path.exists():
            return path.resolve()
    return None


def connected_source_ids() -> set[str]:
    payload = load_optional_json(HUB_CURRENT_ROOT / "source-status.json")
    if not isinstance(payload, dict):
        return set()
    rows = payload.get("rows")
    if not isinstance(rows, list):
        return set()
    connected: set[str] = set()
    for row in rows:
        if not isinstance(row, dict):
            continue
        source_id = normalize_slug_part(str(row.get("source_id") or ""))
        if source_id and str(row.get("status") or "") == "connected":
            connected.add(source_id)
    return connected


def normalized_satellite_dispatch_mode(value: Any) -> str:
    text = str(value or "").strip()
    if text in SATELLITE_DISPATCH_MODE_CHOICES:
        return text
    return SATELLITE_DEFAULT_DISPATCH_MODE


def normalize_satellite_alias(value: Any) -> str:
    text = str(value or "").strip().lower()
    if not text:
        return ""
    text = re.sub(r"[\s:_\-]+", "", text)
    for prefix in ["aidaguanjia", "ai大管家", "大管家"]:
        if text.startswith(prefix):
            text = text[len(prefix) :]
    for prefix in ["satellite", "卫星"]:
        if text.startswith(prefix):
            text = text[len(prefix) :]
    return text.strip()


def satellite_status_for_source(source_id: str) -> tuple[str, str]:
    artifact = remote_onboarding_artifact_path(source_id)
    artifact_path = str(artifact) if artifact is not None else ""
    connected = normalize_slug_part(source_id) in connected_source_ids()
    if connected:
        return "connected", artifact_path
    if artifact is not None:
        return "onboarded", artifact_path
    return "pending_onboarding", ""


def ensure_satellite_registry_current_files() -> None:
    ensure_dir(SATELLITES_CURRENT_ROOT)
    if not SATELLITE_REGISTRY_PATH.exists():
        write_json(SATELLITE_REGISTRY_PATH, [])


def normalize_satellite_registry_rows(rows: list[dict[str, Any]]) -> tuple[list[dict[str, Any]], bool]:
    specs = default_satellite_spec_map()
    normalized_rows: list[dict[str, Any]] = []
    changed = False
    for row in rows:
        normalized = dict(row)
        satellite_id = normalize_slug_part(str(normalized.get("satellite_id") or ""))
        if not satellite_id:
            continue
        spec = specs.get(satellite_id, {})
        aliases = normalize_list(normalized.get("aliases"))
        merged_aliases = normalize_list(aliases + normalize_list(spec.get("aliases")) + [normalized.get("display_name", "")])
        status, onboarding_path = satellite_status_for_source(str(normalized.get("source_id") or spec.get("source_id") or ""))
        normalized_row = {
            "satellite_id": satellite_id,
            "display_name": str(normalized.get("display_name") or spec.get("display_name") or satellite_id),
            "aliases": merged_aliases,
            "clone_id": str(normalized.get("clone_id") or spec.get("clone_id") or f"clone-{satellite_id}"),
            "source_id": normalize_slug_part(str(normalized.get("source_id") or spec.get("source_id") or satellite_id)),
            "status": status,
            "default_when_unspecified": bool(
                normalized.get("default_when_unspecified")
                if "default_when_unspecified" in normalized
                else spec.get("default_when_unspecified")
            ),
            "bound_onboarding_artifact": onboarding_path,
            "dispatch_mode": normalized_satellite_dispatch_mode(normalized.get("dispatch_mode") or spec.get("dispatch_mode")),
            "role_kind": str(normalized.get("role_kind") or spec.get("role_kind") or ""),
            "authority_mode": str(normalized.get("authority_mode") or spec.get("authority_mode") or ""),
            "management_scope": normalize_list(normalized.get("management_scope") or spec.get("management_scope")),
            "contract_path": str(normalized.get("contract_path") or spec.get("contract_path") or ""),
        }
        if normalized_row != row:
            changed = True
        normalized_rows.append(normalized_row)
    normalized_rows.sort(key=lambda item: str(item.get("satellite_id") or ""))
    return normalized_rows, changed


def load_satellite_registry(*, persist: bool = True) -> list[dict[str, Any]]:
    ensure_satellite_registry_current_files()
    rows, changed = normalize_satellite_registry_rows(load_optional_json_list(SATELLITE_REGISTRY_PATH))
    if persist and changed:
        write_json(SATELLITE_REGISTRY_PATH, rows)
    return rows


def upsert_satellite_registry_row(rows: list[dict[str, Any]], new_row: dict[str, Any]) -> list[dict[str, Any]]:
    key = str(new_row.get("satellite_id") or "").strip()
    merged: list[dict[str, Any]] = []
    found = False
    for row in rows:
        if str(row.get("satellite_id") or "").strip() == key:
            merged.append(new_row)
            found = True
        else:
            merged.append(row)
    if not found:
        merged.append(new_row)
    merged.sort(key=lambda item: str(item.get("satellite_id") or ""))
    return merged


def pending_satellite_aliases(rows: list[dict[str, Any]]) -> list[str]:
    order_map = {
        str(item.get("satellite_id") or ""): index
        for index, item in enumerate(default_satellite_fleet_specs())
    }
    pending_rows = [row for row in rows if str(row.get("status") or "") == "pending_onboarding"]
    pending_rows.sort(key=lambda item: order_map.get(str(item.get("satellite_id") or ""), 999))
    return [str(row.get("display_name") or row.get("satellite_id") or "") for row in pending_rows]


def expected_sources_from_satellite_registry() -> list[str]:
    rows = load_satellite_registry(persist=False)
    if not rows:
        return []
    sources = ["main-hub"]
    for row in rows:
        if str(row.get("status") or "") in {"connected", "onboarded"}:
            sources.append(str(row.get("source_id") or ""))
    normalized: list[str] = []
    seen: set[str] = set()
    for source_id in sources:
        normalized_source = normalize_slug_part(source_id)
        if not normalized_source or normalized_source in seen:
            continue
        seen.add(normalized_source)
        normalized.append(normalized_source)
    return normalized


def persisted_expected_sources() -> list[str]:
    for path in [HUB_CURRENT_ROOT / "source-status.json", HUB_ROOT / "bootstrap-status.json", HUB_ROOT / "source-topology.json"]:
        payload = load_optional_json(path)
        if not isinstance(payload, dict):
            continue
        candidates = [normalize_slug_part(item) for item in normalize_list(payload.get("expected_sources")) if str(item).strip()]
        if candidates:
            return candidates
    return []


def resolve_expected_sources(values: list[str] | None = None) -> list[str]:
    if values:
        sources = [normalize_slug_part(item) for item in values if str(item).strip()]
    else:
        raw = os.getenv("AI_DA_GUAN_JIA_EXPECTED_SOURCES", "").strip()
        if raw:
            sources = [normalize_slug_part(item) for item in raw.split(",") if item.strip()]
        else:
            sources = expected_sources_from_satellite_registry() or persisted_expected_sources() or list(DEFAULT_EXPECTED_SOURCES)
    if "main-hub" not in sources:
        sources.insert(0, "main-hub")
    normalized: list[str] = []
    seen: set[str] = set()
    for source in sources:
        if not source or source in seen:
            continue
        seen.add(source)
        normalized.append(source)
    return normalized


def ensure_satellite_rdagent_current_files() -> None:
    ensure_dir(SATELLITE_RDAGENT_CURRENT_ROOT)
    if not SATELLITE_RDAGENT_RUNTIME_BINDINGS_PATH.exists():
        write_json(SATELLITE_RDAGENT_RUNTIME_BINDINGS_PATH, [])


def normalize_rdagent_os_name(value: Any) -> str:
    text = normalize_prompt(str(value or ""))
    if text in {"darwin", "macos", "mac", "osx"}:
        return "darwin"
    if text in {"linux", "ubuntu", "debian"} or "linux" in text or "ubuntu" in text:
        return "linux"
    return text or "unknown"


def normalize_rdagent_arch(value: Any) -> str:
    text = normalize_prompt(str(value or "")).replace("_", "").replace("-", "")
    if text in {"x8664", "amd64"}:
        return "x86_64"
    if text in {"arm64", "aarch64"}:
        return "arm64"
    return str(value or "").strip() or "unknown"


def source_status_row(source_id: str) -> dict[str, Any]:
    payload = load_optional_json(HUB_CURRENT_ROOT / "source-status.json")
    rows = payload.get("rows", []) if isinstance(payload.get("rows"), list) else []
    normalized_source = normalize_slug_part(source_id)
    for row in rows:
        if not isinstance(row, dict):
            continue
        if normalize_slug_part(str(row.get("source_id") or "")) == normalized_source:
            return row
    return {}


def historical_machine_profile_candidates(source_id: str) -> list[dict[str, Any]]:
    normalized_source = normalize_slug_part(source_id)
    if not normalized_source:
        return []
    candidate_paths: list[Path] = []
    direct_paths = [
        HUB_OUTBOX_ROOT / "sources" / normalized_source / "latest" / "machine-profile.json",
    ]
    for path in direct_paths:
        if path.exists():
            candidate_paths.append(path)
    candidate_paths.extend(
        sorted((HUB_OUTBOX_ROOT / "sources" / normalized_source / "snapshots").glob("*/*/machine-profile.json"), reverse=True)
    )
    candidate_paths.extend(sorted(HUB_REPOS_ROOT.glob(f"*/sources/{normalized_source}/latest/machine-profile.json"), reverse=True))
    candidate_paths.extend(sorted(HUB_REPOS_ROOT.glob(f"*/sources/{normalized_source}/snapshots/*/*/machine-profile.json"), reverse=True))
    migration_root = PROJECT_ROOT / "output" / "migration"
    if migration_root.exists():
        candidate_paths.extend(
            sorted(
                migration_root.glob(
                    f"*/secret/codex/skills-raw/ai-da-guan-jia/artifacts/ai-da-guan-jia/hub/outbox/sources/{normalized_source}/latest/machine-profile.json"
                ),
                reverse=True,
            )
        )
        candidate_paths.extend(
            sorted(
                migration_root.glob(
                    f"*/secret/codex/skills-raw/ai-da-guan-jia/artifacts/ai-da-guan-jia/hub/outbox/sources/{normalized_source}/snapshots/*/*/machine-profile.json"
                ),
                reverse=True,
            )
        )
        candidate_paths.extend(
            sorted(
                migration_root.glob(
                    f"*/secret/codex/skills-raw/ai-da-guan-jia/artifacts/ai-da-guan-jia/hub/repos/*/sources/{normalized_source}/latest/machine-profile.json"
                ),
                reverse=True,
            )
        )
        candidate_paths.extend(
            sorted(
                migration_root.glob(
                    f"*/secret/codex/skills-raw/ai-da-guan-jia/artifacts/ai-da-guan-jia/hub/repos/*/sources/{normalized_source}/snapshots/*/*/machine-profile.json"
                ),
                reverse=True,
            )
        )
    rows: list[dict[str, Any]] = []
    seen_paths: set[str] = set()
    for path in candidate_paths:
        resolved = str(path.resolve())
        if resolved in seen_paths or not path.exists():
            continue
        seen_paths.add(resolved)
        payload = load_optional_json(path)
        if not isinstance(payload, dict) or not payload:
            continue
        rows.append(
            {
                "source_id": normalized_source,
                "hostname": str(payload.get("hostname") or ""),
                "user": str(payload.get("user") or ""),
                "platform": normalize_rdagent_os_name(payload.get("platform")),
                "arch": normalize_rdagent_arch(payload.get("arch")),
                "python": str(payload.get("python") or ""),
                "generated_at": str(payload.get("generated_at") or ""),
                "evidence_path": resolved,
            }
        )
    rows.sort(key=lambda item: (str(item.get("generated_at") or ""), str(item.get("evidence_path") or "")), reverse=True)
    return rows


def normalize_satellite_rdagent_binding_rows(rows: list[dict[str, Any]]) -> tuple[list[dict[str, Any]], bool]:
    normalized_rows: list[dict[str, Any]] = []
    changed = False
    for row in rows:
        requested_alias = str(row.get("requested_alias") or RDAGENT_FIN_QUANT_DEFAULT_ALIAS).strip() or RDAGENT_FIN_QUANT_DEFAULT_ALIAS
        resolution = resolve_satellite_assignment(requested_alias)
        control_plane_source_id = str(row.get("control_plane_source_id") or resolution.get("resolved_source_id") or "").strip()
        if not control_plane_source_id:
            continue
        runtime_source_id = normalize_slug_part(str(row.get("runtime_source_id") or ""))
        derived_remote = tool_glue_remote_host_metadata(runtime_source_id) if runtime_source_id else {}
        derived_probe = derived_remote.get("probe", {}) if isinstance(derived_remote.get("probe"), dict) else {}
        runtime_host = str(row.get("runtime_host") or derived_remote.get("host") or "").strip()
        runtime_user = str(row.get("runtime_user") or derived_remote.get("user") or "").strip()
        runtime_workspace_root = str(
            row.get("runtime_workspace_root")
            or row.get("workspace_root")
            or derived_remote.get("workspace_root")
            or RDAGENT_FIN_QUANT_DEFAULT_WORKSPACE_ROOT
        ).strip()
        runtime_port_raw = row.get("runtime_port")
        if runtime_port_raw in {"", None}:
            runtime_port_raw = derived_remote.get("port") or RDAGENT_FIN_QUANT_DEFAULT_PORT
        normalized_row = {
            "binding_id": str(row.get("binding_id") or f"{control_plane_source_id}:rdagent-fin-quant"),
            "scenario": RDAGENT_FIN_QUANT_SCENARIO,
            "requested_alias": requested_alias,
            "control_plane_satellite_id": str(row.get("control_plane_satellite_id") or resolution.get("resolved_satellite_id") or ""),
            "control_plane_source_id": control_plane_source_id,
            "runtime_label": str(row.get("runtime_label") or "rd-agent-fin-quant-runtime"),
            "runtime_source_id": runtime_source_id,
            "runtime_host": runtime_host,
            "runtime_user": runtime_user,
            "runtime_port": int(runtime_port_raw or RDAGENT_FIN_QUANT_DEFAULT_PORT),
            "runtime_workspace_root": runtime_workspace_root,
            "runtime_conda_home": str(row.get("runtime_conda_home") or RDAGENT_FIN_QUANT_DEFAULT_CONDA_HOME).strip(),
            "runtime_env_name": str(row.get("runtime_env_name") or RDAGENT_FIN_QUANT_DEFAULT_ENV_NAME).strip(),
            "runtime_data_root": str(row.get("runtime_data_root") or RDAGENT_FIN_QUANT_DEFAULT_DATA_ROOT).strip(),
            "os_name": normalize_rdagent_os_name(row.get("os_name") or derived_probe.get("os_name") or ""),
            "arch": normalize_rdagent_arch(row.get("arch") or derived_probe.get("arch") or ""),
            "docker_required": bool(row.get("docker_required") if "docker_required" in row else True),
            "notes": str(row.get("notes") or "").strip(),
            "status": str(row.get("status") or ("bound" if runtime_host else "pending_host_authorization")).strip(),
            "updated_at": str(row.get("updated_at") or iso_now()),
        }
        if normalized_row != row:
            changed = True
        normalized_rows.append(normalized_row)
    normalized_rows.sort(key=lambda item: (str(item.get("control_plane_source_id") or ""), str(item.get("binding_id") or "")))
    return normalized_rows, changed


def load_satellite_rdagent_runtime_bindings(*, persist: bool = True) -> list[dict[str, Any]]:
    ensure_satellite_rdagent_current_files()
    rows, changed = normalize_satellite_rdagent_binding_rows(load_optional_json_list(SATELLITE_RDAGENT_RUNTIME_BINDINGS_PATH))
    if persist and changed:
        write_json(SATELLITE_RDAGENT_RUNTIME_BINDINGS_PATH, rows)
    return rows


def satellite_rdagent_runtime_binding_for_alias(requested_alias: str | None = None) -> dict[str, Any]:
    resolution = resolve_satellite_assignment(requested_alias or RDAGENT_FIN_QUANT_DEFAULT_ALIAS)
    control_plane_source_id = str(resolution.get("resolved_source_id") or "")
    if not control_plane_source_id:
        return {}
    for row in load_satellite_rdagent_runtime_bindings(persist=False):
        if str(row.get("control_plane_source_id") or "") == control_plane_source_id:
            return row
    return {}


def upsert_satellite_rdagent_runtime_binding(rows: list[dict[str, Any]], new_row: dict[str, Any]) -> list[dict[str, Any]]:
    key = str(new_row.get("binding_id") or "").strip()
    merged: list[dict[str, Any]] = []
    found = False
    for row in rows:
        if str(row.get("binding_id") or "").strip() == key:
            merged.append(new_row)
            found = True
        else:
            merged.append(row)
    if not found:
        merged.append(new_row)
    merged.sort(key=lambda item: (str(item.get("control_plane_source_id") or ""), str(item.get("binding_id") or "")))
    return merged


def artifact_shape(skill_dir: Path) -> dict[str, bool]:
    return {
        "SKILL.md": (skill_dir / "SKILL.md").exists(),
        "scripts": (skill_dir / "scripts").exists(),
        "references": (skill_dir / "references").exists(),
        "assets": (skill_dir / "assets").exists(),
        "agents": (skill_dir / "agents").exists(),
    }


def skill_cluster(name: str) -> str:
    if name in {"ai-da-guan-jia", "ai-metacognitive-core", "routing-playbook", "self-evolution-max", "guide-benchmark-learning"} or name.startswith("jiyao-"):
        return "AI大管家治理簇"
    if name.startswith("skill-") or name == "strategy-skill-template":
        return "技能生产簇"
    if skill_layer(name) == "平台/工具集成层":
        return "平台簇"
    if name.startswith("agency-"):
        return "agency簇"
    return "垂直workflow簇"


def skill_type(name: str) -> str:
    layer = skill_layer(name)
    if layer == "元治理层":
        return "governance"
    if layer == "平台/工具集成层":
        return "platform"
    if name.startswith("agency-"):
        return "persona"
    return "workflow"


def resource_completeness(resources: dict[str, bool]) -> str:
    enabled = [key for key, value in resources.items() if value]
    if len(enabled) == 4:
        return "full-stack"
    if len(enabled) >= 2:
        return "partial"
    if enabled:
        return "minimal"
    return "empty"


def ease_of_use_judgment(item: dict[str, Any]) -> str:
    if item["type"] == "persona":
        return "更像角色说明，需 hardening 才顺手"
    if item["resource_score"] == 4:
        return "闭环强，适合高频调用"
    if item["layer"] == "平台/工具集成层" and item["resource_score"] >= 2:
        return "平台边界清楚，日常较顺手"
    if item["resource_score"] <= 1:
        return "轻结构，顺手度依赖记忆"
    return "可用，但仍需更清楚的组合手册"


def boundary_note(name: str) -> str:
    notes = {
        "figma": "与 figma-implement-design 共享设计入口，需要按总入口 vs 1:1 实现分流。",
        "figma-implement-design": "与 figma 的边界在 1:1 设计实现，而不是泛 Figma 上下文读取。",
        "jiyao-youyao-haiyao": "与 zaiyao 的边界在复杂度；简单自治优先用本 skill。",
        "jiyao-youyao-haiyao-zaiyao": "只有复杂多阶段任务才升级到 zaiyao。",
        "knowledge-orchestrator": "不要与 Notion 研究型 skill 混成同一个入口。",
        "youquant-backtest": "与 youquant-backtest-automation 存在明确重叠，应优先收敛。",
        "youquant-backtest-automation": "与 youquant-backtest 存在明确重叠，应优先收敛。",
    }
    return notes.get(name, "")


def build_review_inventory() -> list[dict[str, Any]]:
    inventory: list[dict[str, Any]] = []
    for skill_md in discover_top_level_skill_files():
        metadata = read_skill_metadata(skill_md)
        if not metadata:
            continue
        resources = skill_resource_flags(skill_md.parent)
        metadata_repo = metadata_source_repo(str(metadata.get("source") or ""))
        git_repo = git_origin_repo(skill_md.parent)
        source_repo = metadata_repo or git_repo
        source_type = "metadata.source" if metadata_repo else "git-origin" if git_repo else "local-native"
        item = {
            "name": metadata["name"],
            "directory_name": skill_md.parent.name,
            "description": metadata["description"],
            "path": str(skill_md.parent),
            "layer": skill_layer(metadata["name"]),
            "cluster": skill_cluster(metadata["name"]),
            "type": skill_type(metadata["name"]),
            "resources": resources,
            "resource_score": sum(1 for value in resources.values() if value),
            "resource_completeness": resource_completeness(resources),
            "source": str(metadata.get("source") or ""),
            "source_repo": source_repo,
            "source_type": source_type,
            "git_origin_repo": git_repo,
        }
        item["ease_of_use_judgment"] = ease_of_use_judgment(item)
        item["boundary_note"] = boundary_note(item["name"])
        inventory.append(
            item
        )
    return sorted(inventory, key=lambda item: item["name"])


def load_review_state() -> dict[str, Any]:
    return load_state_file(REVIEW_STATE_PATH)


def save_review_state(payload: dict[str, Any]) -> None:
    save_state_file(REVIEW_STATE_PATH, payload)


def default_state_payload() -> dict[str, Any]:
    return {
        "status": "idle",
        "latest_run_id": "",
        "pending_action_ids": [],
        "carryover_pending_action_ids": [],
    }


def load_state_file(path: Path) -> dict[str, Any]:
    if not path.exists():
        return default_state_payload()
    try:
        payload = read_json(path)
    except Exception:
        return default_state_payload()
    if not isinstance(payload, dict):
        return default_state_payload()
    merged = default_state_payload()
    merged.update(payload)
    return merged


def save_state_file(path: Path, payload: dict[str, Any]) -> None:
    ensure_dir(path.parent)
    merged = default_state_payload()
    merged.update(payload)
    write_json(path, merged)


def load_governance_review_state() -> dict[str, Any]:
    return load_state_file(GOVERNANCE_REVIEW_STATE_PATH)


def save_governance_review_state(payload: dict[str, Any]) -> None:
    save_state_file(GOVERNANCE_REVIEW_STATE_PATH, payload)


def generate_review_run_id(timestamp: datetime | None = None) -> str:
    stamp = (timestamp or now_local()).strftime("%Y%m%d-%H%M%S")
    return f"adagj-review-{stamp}"


def allocate_review_run_id(created_at: str) -> str:
    dt = parse_datetime(created_at)
    base = generate_review_run_id(dt)
    candidate = base
    index = 1
    while (REVIEWS_ROOT / dt.strftime("%Y-%m-%d") / candidate).exists():
        candidate = f"{base}-{index:02d}"
        index += 1
    return candidate


def review_run_dir_for(run_id: str, created_at: str | None = None) -> Path:
    dt = parse_datetime(created_at)
    return ensure_dir(REVIEWS_ROOT / dt.strftime("%Y-%m-%d") / run_id)


def generate_governance_review_run_id(timestamp: datetime | None = None) -> str:
    stamp = (timestamp or now_local()).strftime("%Y%m%d-%H%M%S")
    return f"adagj-governance-review-{stamp}"


def allocate_governance_review_run_id(created_at: str) -> str:
    dt = parse_datetime(created_at)
    base = generate_governance_review_run_id(dt)
    candidate = base
    index = 1
    while (GOVERNANCE_REVIEWS_ROOT / dt.strftime("%Y-%m-%d") / candidate).exists():
        candidate = f"{base}-{index:02d}"
        index += 1
    return candidate


def governance_review_run_dir_for(run_id: str, created_at: str | None = None) -> Path:
    dt = parse_datetime(created_at)
    return ensure_dir(GOVERNANCE_REVIEWS_ROOT / dt.strftime("%Y-%m-%d") / run_id)


def latest_review_inventory() -> list[dict[str, Any]]:
    if not REVIEWS_ROOT.exists():
        return []
    review_dirs = sorted([path for path in REVIEWS_ROOT.glob("*/*") if path.is_dir()], key=lambda item: str(item))
    for run_dir in reversed(review_dirs):
        inventory_path = run_dir / "inventory.json"
        if not inventory_path.exists():
            continue
        payload = read_json(inventory_path)
        if isinstance(payload, dict):
            items = payload.get("skills")
            if isinstance(items, list):
                return items
    return []


def generate_skill_scout_run_id(timestamp: datetime | None = None) -> str:
    stamp = (timestamp or now_local()).strftime("%Y%m%d-%H%M%S")
    return f"adagj-skill-scout-{stamp}"


def allocate_skill_scout_run_id(created_at: str) -> str:
    dt = parse_datetime(created_at)
    base = generate_skill_scout_run_id(dt)
    candidate = base
    index = 1
    while (SKILL_SCOUT_ROOT / dt.strftime("%Y-%m-%d") / candidate).exists():
        candidate = f"{base}-{index:02d}"
        index += 1
    return candidate


