def merge_registry_rows(
    defaults: list[dict[str, Any]],
    existing: list[dict[str, Any]],
    key: str,
    *,
    allow_extra: bool = True,
) -> list[dict[str, Any]]:
    existing_map = {
        str(item.get(key) or "").strip(): item
        for item in existing
        if isinstance(item, dict) and str(item.get(key) or "").strip()
    }
    rows: list[dict[str, Any]] = []
    for default in defaults:
        row_id = str(default.get(key) or "").strip()
        merged = dict(default)
        if row_id and row_id in existing_map:
            merged.update(existing_map[row_id])
        rows.append(merged)
    if allow_extra:
        default_ids = {str(item.get(key) or "").strip() for item in defaults if str(item.get(key) or "").strip()}
        extra_rows = [
            item
            for item in existing
            if isinstance(item, dict)
            and str(item.get(key) or "").strip()
            and str(item.get(key) or "").strip() not in default_ids
        ]
        rows.extend(sorted(extra_rows, key=lambda item: str(item.get(key) or "")))
    return rows


def canonical_thread_row(
    canonical_thread: str,
    *,
    theme_id: str,
    disposition: str,
    goal_id: str = "G1",
    strategy_slot: str = "",
    experiment_slot: str = "",
    next_experiment: str = "",
    next_blocker: str = "",
    window_aliases: list[str] | None = None,
    wave: str = "",
    notes: str = "",
    benchmark: bool = False,
    program_order: int = 999,
) -> dict[str, Any]:
    return {
        "canonical_thread": canonical_thread,
        "window_aliases": window_aliases or [],
        "goal_id": goal_id,
        "theme_id": theme_id,
        "strategy_slot": strategy_slot,
        "experiment_slot": experiment_slot,
        "disposition": disposition,
        "next_experiment": next_experiment,
        "next_blocker": next_blocker,
        "wave": wave,
        "notes": notes,
        "benchmark": benchmark,
        "program_order": program_order,
    }


