def normalized_theme_id(value: Any) -> str:
    text = str(value or "").strip()
    if not text or text in LEGACY_GOAL_THEME_IDS:
        return ""
    return text


def infer_theme_id(task_text: str, goal_id: str = "", selected_skills: list[str] | None = None) -> str:
    text = normalize_prompt(task_text)
    selected_skills = selected_skills or []
    business_keywords = ["业务", "客户", "销售", "营收", "订单", "pipeline", "finance", "收入", "交付", "转化"]
    coevolution_keywords = [
        "人机",
        "协同",
        "共进化",
        "共识",
        "少打扰",
        "自治",
        "mvp",
        "experiment",
        "workflow",
        "工作流",
        "ai大管家",
        "共同治理",
    ]
    governance_keywords = ["治理", "review", "taxonomy", "盘点", "skill", "策略", "governance", "提权", "降权", "scorecard"]
    if any(keyword in text for keyword in business_keywords):
        return "theme-business"
    if any(keyword in text for keyword in coevolution_keywords):
        return ACTIVE_THEME_ID
    if any(skill in {"ai-da-guan-jia", "jiyao-youyao-haiyao-zaiyao"} for skill in selected_skills) and any(
        keyword in text for keyword in ["想法", "表达", "收束", "验证", "共识", "少打扰"]
    ):
        return ACTIVE_THEME_ID
    if any(keyword in text for keyword in governance_keywords):
        return "theme-governance"
    if goal_id == "G2":
        return ACTIVE_THEME_ID
    return "theme-governance"


def infer_strategy_axis_refs(task_text: str, goal_id: str = "", selected_skills: list[str] | None = None) -> dict[str, str]:
    theme_id = infer_theme_id(task_text, goal_id=goal_id, selected_skills=selected_skills)
    text = normalize_prompt(task_text)
    strategy_id = ""
    experiment_id = ""
    if theme_id == ACTIVE_THEME_ID:
        if any(keyword in text for keyword in ["连续表达", "低打断", "收着听", "先听", "收束"]):
            strategy_id = "strategy-human-ai-low-interruption-convergence"
            experiment_id = "experiment-human-ai-low-interruption-round-001"
        elif any(keyword in text for keyword in ["mvp", "快证", "实验", "试点", "最小可控"]):
            strategy_id = "strategy-human-ai-mvp-fast-validation"
            experiment_id = "experiment-human-ai-mvp-fast-validation-001"
        elif any(keyword in text for keyword in ["共识", "先聊清楚", "自动化", "固化"]):
            strategy_id = "strategy-human-ai-consensus-before-automation"
            experiment_id = "experiment-human-ai-consensus-before-automation-001"
        else:
            strategy_id = MOTHER_STRATEGY_ID
    elif theme_id == FRONTSTAGE_FOCUS_THEME_ID:
        if any(keyword in text for keyword in ["治理体系研究", "治理体系", "scaffold", "三层治理", "主题层"]):
            strategy_id = GOVERNANCE_OPERATING_CORE_STRATEGY_ID
            experiment_id = GOVERNANCE_OPERATING_CORE_EXPERIMENT_ID
        elif any(keyword in text for keyword in ["分形设计", "耗散结构", "联邦对象治理", "本体论", "ontology"]):
            strategy_id = GOVERNANCE_ONTOLOGY_STRATEGY_ID
            experiment_id = GOVERNANCE_ONTOLOGY_EXPERIMENT_ID
        elif any(keyword in text for keyword in ["信息聚合", "三端一网", "transport", "emit", "github", "仪表盘", "多维表"]):
            strategy_id = GOVERNANCE_TRANSPORT_STRATEGY_ID
            experiment_id = GOVERNANCE_TRANSPORT_EXPERIMENT_ID
        else:
            strategy_id = GOVERNANCE_MOTHER_STRATEGY_ID
    return {
        "theme_id": theme_id,
        "strategy_id": strategy_id,
        "experiment_id": experiment_id,
        "workflow_id": "",
    }


def build_canonical_thread_registry() -> list[dict[str, Any]]:
    existing = load_optional_json_list(strategy_canonical_thread_registry_path())
    defaults = seed_canonical_thread_registry_rows()
    default_ids = {
        str(item.get("canonical_thread") or "").strip()
        for item in defaults
        if str(item.get("canonical_thread") or "").strip()
    }
    rows = list(defaults)
    rows.extend(
        [
            item
            for item in existing
            if isinstance(item, dict)
            and str(item.get("canonical_thread") or "").strip()
            and str(item.get("canonical_thread") or "").strip() not in default_ids
        ]
    )
    normalized_rows: list[dict[str, Any]] = []
    for item in rows:
        disposition = str(item.get("disposition") or "").strip()
        if disposition not in CANONICAL_THREAD_DISPOSITIONS:
            disposition = "candidate_pool"
        normalized_rows.append(
            {
                "canonical_thread": str(item.get("canonical_thread") or ""),
                "window_aliases": normalize_list(item.get("window_aliases")),
                "goal_id": str(item.get("goal_id") or "G1"),
                "theme_id": str(item.get("theme_id") or ""),
                "strategy_slot": str(item.get("strategy_slot") or ""),
                "experiment_slot": str(item.get("experiment_slot") or ""),
                "disposition": disposition,
                "next_experiment": str(item.get("next_experiment") or ""),
                "next_blocker": str(item.get("next_blocker") or ""),
                "wave": str(item.get("wave") or ""),
                "notes": str(item.get("notes") or ""),
                "benchmark": bool(item.get("benchmark", False)),
                "program_order": int(item.get("program_order", 999)),
            }
        )
    normalized_rows.sort(
        key=lambda item: (
            CANONICAL_THREAD_DISPOSITIONS.index(item["disposition"]),
            int(item.get("program_order", 999)),
            item["canonical_thread"],
        )
    )
    return normalized_rows


def canonical_thread_program_summary(canonical_threads: list[dict[str, Any]]) -> dict[str, Any]:
    counts = {name: 0 for name in CANONICAL_THREAD_DISPOSITIONS}
    for item in canonical_threads:
        counts[str(item.get("disposition") or "candidate_pool")] += 1
    frontstage_titles = [
        str(item.get("canonical_thread") or "")
        for item in canonical_threads
        if str(item.get("disposition") or "") == "frontstage_now"
    ]
    return {
        "frontstage_focus_theme_id": FRONTSTAGE_FOCUS_THEME_ID,
        "registry_active_theme_id": ACTIVE_THEME_ID,
        "frontstage_cap": 3,
        "workflow_generation_enabled": False,
        "benchmark_thread": BENCHMARK_THREAD_TITLE,
        "disposition_counts": counts,
        "frontstage_titles": frontstage_titles,
        "wave_order": THREAD_PROGRAM_WAVE_ORDER,
        "out_of_program_threads": OUT_OF_PROGRAM_THREAD_TITLES,
    }


def governance_wave_one_complete(strategy_registry: list[dict[str, Any]]) -> bool:
    strategy_states = {
        str(item.get("strategy_id") or "").strip(): str(item.get("validation_state") or "").strip()
        for item in strategy_registry
        if str(item.get("strategy_id") or "").strip()
    }
    return all(strategy_states.get(strategy_id) in TERMINAL_STRATEGY_STATES for strategy_id in GOVERNANCE_FRONTSTAGE_STRATEGY_IDS)


def wave_transition_summary(
    strategy_registry: list[dict[str, Any]],
    canonical_threads: list[dict[str, Any]],
) -> dict[str, Any]:
    wave_one_complete = governance_wave_one_complete(strategy_registry)
    wave_two_candidates = sorted(
        [
            item
            for item in canonical_threads
            if str(item.get("wave") or "").strip() == "wave_2" and str(item.get("disposition") or "").strip() == "candidate_pool"
        ],
        key=lambda item: (int(item.get("program_order", 999)), str(item.get("canonical_thread") or "")),
    )
    next_candidate = wave_two_candidates[0] if wave_one_complete and wave_two_candidates else {}
    return {
        "wave_1_complete": wave_one_complete,
        "next_focus_theme_id": str(next_candidate.get("theme_id") or ""),
        "next_focus_thread": str(next_candidate.get("canonical_thread") or ""),
        "next_focus_note": str(next_candidate.get("next_experiment") or ""),
        "next_focus_blocker": str(next_candidate.get("next_blocker") or ""),
    }


def match_canonical_thread(task_text: str, canonical_threads: list[dict[str, Any]]) -> dict[str, Any] | None:
    text = normalize_prompt(task_text)
    if not text:
        return None
    for item in canonical_threads:
        names = [str(item.get("canonical_thread") or "")]
        names.extend(normalize_list(item.get("window_aliases")))
        for name in names:
            probe = normalize_prompt(name)
            if probe and probe in text:
                return item
    return None


def display_thread_theme(value: Any) -> str:
    text = str(value or "").strip()
    if not text:
        return "none"
    if text in LEGACY_GOAL_THEME_IDS:
        return f"legacy-goal:{text}"
    return text


def normalize_experiment_verdict(value: Any, verification_status: str = "") -> str:
    text = str(value or "").strip().lower()
    if text in EXPERIMENT_VERDICT_CHOICES:
        return text
    verification = str(verification_status or "").strip().lower()
    if verification in {"completed", "done", "passed", "success"}:
        return "passed"
    if verification in {"blocked_needs_user", "needs_user"}:
        return "blocked_needs_user"
    if verification in {"blocked", "blocked_system"}:
        return "blocked_system"
    if verification in {"failed", "error"}:
        return "failed"
    return "pending_real_round"


def strategy_axis_from_sources(
    task_text: str,
    goal_id: str = "",
    selected_skills: list[str] | None = None,
    *,
    theme_id: str = "",
    strategy_id: str = "",
    experiment_id: str = "",
    workflow_id: str = "",
    experiment_verdict: str = "",
    verification_status: str = "",
) -> dict[str, str]:
    inferred = infer_strategy_axis_refs(task_text, goal_id=goal_id, selected_skills=selected_skills)
    return {
        "theme_id": str(theme_id or inferred["theme_id"] or "").strip(),
        "strategy_id": str(strategy_id or inferred["strategy_id"] or "").strip(),
        "experiment_id": str(experiment_id or inferred["experiment_id"] or "").strip(),
        "workflow_id": str(workflow_id or inferred["workflow_id"] or "").strip(),
        "experiment_verdict": normalize_experiment_verdict(experiment_verdict, verification_status=verification_status),
    }


def build_reflection_summary(evolution: dict[str, Any]) -> str:
    gained = first_non_empty_line("\n".join(normalize_list(evolution.get("effective_patterns"))))
    wasted = first_non_empty_line("\n".join(normalize_list(evolution.get("wasted_patterns"))))
    next_iterate = first_non_empty_line("\n".join(normalize_list(evolution.get("evolution_candidates"))))
    parts = []
    if gained:
        parts.append(f"gained={gained}")
    if wasted:
        parts.append(f"wasted={wasted}")
    if next_iterate:
        parts.append(f"next={next_iterate}")
    return " | ".join(parts) or "no_reflection_recorded"


def strategic_goal_for_item(item: dict[str, Any]) -> str:
    cluster = str(item.get("cluster") or "")
    name = str(item.get("name") or "")
    if cluster == "AI大管家治理簇" or name.startswith(("ai-", "jiyao-", "skill-")):
        return "G1"
    if name in {"agency-agents-orchestrator", "knowledge-orchestrator", "routing-playbook"}:
        return "G2"
    return "G3" if name.startswith("agency-") else "G1"


def strategic_goal_for_run(record: dict[str, Any]) -> str:
    task = normalize_prompt(str(record.get("task_text") or ""))
    if any(word in task for word in ["治理", "taxonomy", "github", "命名", "盘点", "review"]):
        return "G1"
    if any(word in task for word in ["自治", "thread", "initiative", "招兵买马", "strategy"]):
        return "G2"
    if any(word in task for word in ["激励", "scorecard", "提权", "降权", "自治权", "资源权"]):
        return "G3"
    return "G1"


def strategic_gap_candidates(inventory: list[dict[str, Any]]) -> list[dict[str, Any]]:
    names = {item["name"] for item in inventory}
    candidates: list[dict[str, Any]] = []
    wanted = [
        ("workflow-hardening", "G1", "治理操作系统化", "缺少把高频 persona skill 加厚为可验证工作流的中层能力。"),
        ("skill-deduper", "G1", "治理操作系统化", "缺少专门负责重复命名、边界冲突、合并策略的器官。"),
        ("strategy-governor", "G2", "受控自治与提案推进", "缺少围绕战略目标做 initiative 和 thread proposal 的常驻器官。"),
        ("agent-incentive-governor", "G3", "AI 组织激励系统", "缺少 scorecard、提权、降权和资源杠杆的治理器官。"),
    ]
    for name, goal_id, goal_title, reason in wanted:
        if name not in names:
            candidates.append(
                {
                    "candidate_skill": name,
                    "goal_id": goal_id,
                    "goal_title": goal_title,
                    "reason": reason,
                    "action": "recruit_or_incubate",
                }
            )
    return candidates


def build_theme_registry() -> list[dict[str, Any]]:
    existing = load_optional_json_list(strategy_theme_registry_path())
    return merge_registry_rows(seed_theme_registry_rows(), existing, "id", allow_extra=False)


def build_strategy_registry(created_at: str | None = None) -> list[dict[str, Any]]:
    existing = load_optional_json_list(strategy_strategy_registry_path())
    return merge_registry_rows(seed_strategy_registry_rows(created_at=created_at), existing, "strategy_id")


def build_experiment_registry(created_at: str | None = None) -> list[dict[str, Any]]:
    existing = load_optional_json_list(strategy_experiment_registry_path())
    return merge_registry_rows(seed_experiment_registry_rows(created_at=created_at), existing, "experiment_id")


def build_workflow_registry(strategy_registry: list[dict[str, Any]]) -> list[dict[str, Any]]:
    passed_strategy_ids = {
        str(item.get("strategy_id") or "").strip()
        for item in strategy_registry
        if str(item.get("strategy_id") or "").strip()
        and str(item.get("validation_state") or "").strip() in {"passed", "validated"}
        and str(item.get("strategy_id") or "").strip() not in FROZEN_WORKFLOW_STRATEGY_IDS
    }
    existing = load_optional_json_list(strategy_workflow_registry_path())
    rows = []
    for item in existing:
        strategy_id = str(item.get("strategy_id") or "").strip()
        if not strategy_id or strategy_id not in passed_strategy_ids:
            continue
        rows.append(
            {
                "workflow_id": str(item.get("workflow_id") or ""),
                "title": str(item.get("title") or ""),
                "strategy_id": strategy_id,
                "trigger": str(item.get("trigger") or ""),
                "inputs": normalize_list(item.get("inputs")),
                "verification_rule": str(item.get("verification_rule") or ""),
                "human_boundary": str(item.get("human_boundary") or ""),
                "reuse_signal": str(item.get("reuse_signal") or ""),
                "cost_class": str(item.get("cost_class") or ""),
                "updated_at": str(item.get("updated_at") or iso_now()),
            }
        )
    rows.sort(key=lambda item: str(item.get("workflow_id") or ""))
    return rows


def sync_strategy_axis_from_evolution(evolution: dict[str, Any], run_dir: Path) -> dict[str, Any]:
    verification = normalize_verification_result(evolution.get("verification_result"))
    axis = strategy_axis_from_sources(
        str(evolution.get("task_text") or ""),
        selected_skills=normalize_list(evolution.get("skills_selected")),
        theme_id=str(evolution.get("theme_id") or ""),
        strategy_id=str(evolution.get("strategy_id") or ""),
        experiment_id=str(evolution.get("experiment_id") or ""),
        workflow_id=str(evolution.get("workflow_id") or ""),
        experiment_verdict=str(evolution.get("experiment_verdict") or ""),
        verification_status=str(verification.get("status") or ""),
    )
    evolution.update(axis)
    timestamp = str(evolution.get("created_at") or iso_now())
    theme_registry = build_theme_registry()
    strategy_registry = build_strategy_registry(created_at=timestamp)
    experiment_registry = build_experiment_registry(created_at=timestamp)
    summary = {
        "theme_id": axis["theme_id"],
        "strategy_id": axis["strategy_id"],
        "experiment_id": axis["experiment_id"],
        "workflow_id": axis["workflow_id"],
        "experiment_verdict": axis["experiment_verdict"],
        "strategy_updated": False,
        "mother_strategy_updated": False,
    }
    if axis["experiment_id"]:
        experiment_map = {str(item.get("experiment_id") or ""): dict(item) for item in experiment_registry}
        row = experiment_map.get(
            axis["experiment_id"],
            {
                "experiment_id": axis["experiment_id"],
                "title": axis["experiment_id"],
                "theme_id": axis["theme_id"],
                "strategy_id": axis["strategy_id"],
                "assumption": "Backfilled from a real evolution round.",
                "mvp_scope": "Closed-loop validation from a recorded task run.",
                "evidence_ref": "",
                "verdict": "pending_real_round",
                "next_action": "",
                "created_at": timestamp,
            },
        )
        row["theme_id"] = axis["theme_id"] or str(row.get("theme_id") or "")
        row["strategy_id"] = axis["strategy_id"] or str(row.get("strategy_id") or "")
        row["evidence_ref"] = str((run_dir / "evolution.json").resolve())
        row["verdict"] = axis["experiment_verdict"]
        row["next_action"] = first_non_empty_line("\n".join(normalize_list(evolution.get("evolution_candidates")))) or str(
            row.get("next_action") or ""
        )
        row["latest_run_id"] = str(evolution.get("run_id") or "")
        row["latest_verification_status"] = str(verification.get("status") or "")
        row["updated_at"] = timestamp
        if axis["experiment_verdict"] != "pending_real_round":
            row["resolved_at"] = timestamp
        experiment_map[axis["experiment_id"]] = row
        experiment_registry = sorted(experiment_map.values(), key=lambda item: str(item.get("experiment_id") or ""))
    if axis["strategy_id"]:
        strategy_map = {str(item.get("strategy_id") or ""): dict(item) for item in strategy_registry}
        strategy_row = strategy_map.get(axis["strategy_id"])
        if strategy_row:
            strategy_row["theme_id"] = axis["theme_id"] or str(strategy_row.get("theme_id") or "")
            strategy_row["last_run_id"] = str(evolution.get("run_id") or "")
            strategy_row["last_experiment_id"] = axis["experiment_id"]
            strategy_row["last_verdict"] = axis["experiment_verdict"]
            strategy_row["last_evidence_ref"] = str((run_dir / "evolution.json").resolve())
            strategy_row["updated_at"] = timestamp
            if axis["experiment_verdict"] == "passed":
                strategy_row["validation_state"] = "validated"
            elif axis["experiment_verdict"] == "learned":
                strategy_row["validation_state"] = "learning"
            elif axis["experiment_verdict"] == "failed":
                strategy_row["validation_state"] = "tested_failed"
            elif axis["experiment_verdict"] == "blocked_needs_user":
                strategy_row["validation_state"] = "blocked_needs_user"
            elif axis["experiment_verdict"] == "blocked_system":
                strategy_row["validation_state"] = "blocked_system"
            summary["strategy_updated"] = True
            mother_strategy_id = str(strategy_row.get("mother_strategy_id") or "")
            if mother_strategy_id:
                mother_row = strategy_map.get(mother_strategy_id)
                if mother_row:
                    mother_row["last_child_strategy_id"] = axis["strategy_id"]
                    mother_row["last_child_experiment_id"] = axis["experiment_id"]
                    mother_row["last_child_verdict"] = axis["experiment_verdict"]
                    mother_row["last_reflection_run_id"] = str(evolution.get("run_id") or "")
                    mother_row["last_reflection_summary"] = build_reflection_summary(evolution)
                    if mother_strategy_id == GOVERNANCE_MOTHER_STRATEGY_ID and governance_wave_one_complete(list(strategy_map.values())):
                        mother_row["validation_state"] = "validated"
                    mother_row["updated_at"] = timestamp
                    summary["mother_strategy_updated"] = True
            strategy_map[axis["strategy_id"]] = strategy_row
            strategy_registry = sorted(strategy_map.values(), key=lambda item: str(item.get("strategy_id") or ""))
    workflow_registry = build_workflow_registry(strategy_registry)
    write_json(strategy_theme_registry_path(), theme_registry)
    write_json(strategy_strategy_registry_path(), strategy_registry)
    write_json(strategy_experiment_registry_path(), experiment_registry)
    write_json(strategy_workflow_registry_path(), workflow_registry)
    write_strategy_operating_system()
    return summary


def build_production_metrics(
    theme_registry: list[dict[str, Any]],
    strategy_registry: list[dict[str, Any]],
    experiment_registry: list[dict[str, Any]],
    workflow_registry: list[dict[str, Any]],
    active_threads: list[dict[str, Any]],
    recent_runs: list[dict[str, Any]],
) -> dict[str, Any]:
    active_theme_ids = {
        str(item.get("id") or "").strip()
        for item in theme_registry
        if str(item.get("status") or "").strip() == "active" and str(item.get("id") or "").strip()
    }
    mapped_active_threads = [
        item
        for item in active_threads
        if item.get("status") != "archived" and normalized_theme_id(item.get("theme"))
    ]
    active_theme_focus_denominator = len(mapped_active_threads)
    active_theme_focus_numerator = len(
        [item for item in mapped_active_threads if normalized_theme_id(item.get("theme")) in active_theme_ids]
    )
    completed_runs = 0
    interrupted_runs = 0
    for record in recent_runs:
        status = str(record.get("result_status") or record.get("status") or "").strip().lower()
        verification = normalize_verification_result(record.get("verification_result"))
        verification_status = str(verification.get("status") or "").strip().lower()
        if status in {"completed", "done", "passed", "success"} or verification_status in {"completed", "done", "passed", "success"}:
            completed_runs += 1
        if status in {"blocked_needs_user", "needs_user"} or verification_status in {"blocked_needs_user", "needs_user"}:
            interrupted_runs += 1
    resolved_experiments = []
    for item in experiment_registry:
        verdict = str(item.get("verdict") or "").strip()
        resolved_at = str(item.get("resolved_at") or "").strip()
        created_at = str(item.get("created_at") or "").strip()
        if verdict in TERMINAL_EXPERIMENT_VERDICTS and resolved_at and created_at:
            resolved_experiments.append((parse_datetime(resolved_at) - parse_datetime(created_at)).total_seconds() / 3600)
    reused_workflows = len([item for item in workflow_registry if str(item.get("reuse_signal") or "").strip() == "reused"])
    return {
        "theme_layer": {
            "proposal_acceptance": {
                "approved": len([item for item in theme_registry if str(item.get("proposal_state") or "") == "approved"]),
                "total": len(theme_registry),
            },
            "active_theme_focus": {
                "threads_under_active_theme": active_theme_focus_numerator,
                "threads_with_real_theme": active_theme_focus_denominator,
            },
        },
        "strategy_layer": {
            "idea_to_verdict_cycle_time_hours": (
                round(sum(resolved_experiments) / len(resolved_experiments), 2) if resolved_experiments else None
            ),
            "mother_strategy_reuse": len(
                [item for item in strategy_registry if str(item.get("mother_strategy_id") or "").strip()]
            ),
        },
        "execution_layer": {
            "verified_closure_rate": round(completed_runs / max(1, len(recent_runs)), 2),
            "human_interruption_count": interrupted_runs,
            "workflow_reuse_rate": round(reused_workflows / max(1, len(workflow_registry)), 2) if workflow_registry else 0.0,
        },
    }


def build_strategy_map(
    goals: list[dict[str, Any]],
    inventory: list[dict[str, Any]],
    theme_registry: list[dict[str, Any]],
    strategy_registry: list[dict[str, Any]],
    experiment_registry: list[dict[str, Any]],
    workflow_registry: list[dict[str, Any]],
    production_metrics: dict[str, Any],
    canonical_threads: list[dict[str, Any]],
) -> dict[str, Any]:
    counts = {"G1": 0, "G2": 0, "G3": 0}
    for item in inventory:
        counts[strategic_goal_for_item(item)] = counts.get(strategic_goal_for_item(item), 0) + 1
    canonical_summary = canonical_thread_program_summary(canonical_threads)
    wave_transition = wave_transition_summary(strategy_registry, canonical_threads)
    return {
        "generated_at": iso_now(),
        "stage_theme": "从强执行体升级为受控自治的 AI 治理系统",
        "highest_goal": "让 AI大管家 从任务路由器进化成战略提案者 + 组织编排者 + 治理审计者。",
        "goals": goals,
        "skill_distribution_by_goal": counts,
        "goal_axis": ["G1", "G2", "G3"],
        "production_axis": {
            "stages": PRODUCTION_AXIS_STAGES,
            "theme_policy": "proposal_first",
            "seed_theme_ids": [item["id"] for item in theme_registry],
            "first_active_theme": ACTIVE_THEME_ID,
            "frontstage_focus_override": {
                "theme_id": canonical_summary["frontstage_focus_theme_id"],
                "registry_active_theme_id": canonical_summary["registry_active_theme_id"],
                "workflow_generation_enabled": canonical_summary["workflow_generation_enabled"],
                "wave_1_complete": wave_transition["wave_1_complete"],
                "next_focus_theme_id": wave_transition["next_focus_theme_id"],
                "next_focus_thread": wave_transition["next_focus_thread"],
                "next_focus_note": wave_transition["next_focus_note"],
                "next_focus_blocker": wave_transition["next_focus_blocker"],
            },
            "canonical_thread_program": canonical_summary,
            "counts": {
                "themes": len(theme_registry),
                "strategies": len(strategy_registry),
                "experiments": len(experiment_registry),
                "workflows": len(workflow_registry),
            },
            "metrics": production_metrics,
        },
        "method_priority": ["低失真", "验真闭环", "速度", "自动化率"],
    }


