def build_active_threads(
    goals: list[dict[str, Any]],
    *,
    recent_runs: list[dict[str, Any]] | None = None,
    limit: int = 20,
) -> list[dict[str, Any]]:
    threads: list[dict[str, Any]] = []
    canonical_threads = build_canonical_thread_registry()
    records = recent_runs if recent_runs is not None else iter_evolution_records(limit=limit)
    for record in records[:limit]:
        verification = normalize_verification_result(record.get("verification_result"))
        status = str(verification.get("status") or "")
        open_questions = normalize_list(verification.get("open_questions"))
        thread_status = (
            "archived"
            if status in {"completed", "done", "passed", "success", "blocked_needs_user", "blocked_system"} and not open_questions
            else "active"
        )
        task_text = str(record.get("task_text") or "")
        selected_skills = normalize_list(record.get("skills_selected"))
        goal_id = strategic_goal_for_run(record)
        axis_refs = strategy_axis_from_sources(
            task_text,
            goal_id=goal_id,
            selected_skills=selected_skills,
            theme_id=str(record.get("theme_id") or ""),
            strategy_id=str(record.get("strategy_id") or ""),
            experiment_id=str(record.get("experiment_id") or ""),
            workflow_id=str(record.get("workflow_id") or ""),
            experiment_verdict=str(record.get("experiment_verdict") or ""),
            verification_status=str(verification.get("status") or ""),
        )
        canonical_match = match_canonical_thread(task_text, canonical_threads)
        threads.append(
            {
                "run_id": str(record.get("run_id") or ""),
                "thread_id": f"thread-{str(record.get('run_id') or '')}" if str(record.get("run_id") or "").strip() else "",
                "task_text": task_text,
                "goal_id": goal_id,
                "theme": axis_refs["theme_id"],
                "strategy_id": axis_refs["strategy_id"],
                "experiment_id": axis_refs["experiment_id"],
                "workflow_id": axis_refs["workflow_id"],
                "status": thread_status,
                "selected_skills": selected_skills,
                "open_questions": open_questions,
                "canonical_thread": str(canonical_match.get("canonical_thread") or "") if canonical_match else "",
                "disposition": str(canonical_match.get("disposition") or "") if canonical_match else "",
                "next_blocker": str(canonical_match.get("next_blocker") or "") if canonical_match else "",
            }
        )
    return threads


def build_skill_gap_report(
    inventory: list[dict[str, Any]],
    initiatives: list[dict[str, Any]],
    recent_runs: list[dict[str, Any]],
) -> dict[str, Any]:
    missing_middle = missing_middle_layer_capabilities(inventory)
    overlaps = boundary_overlap_pairs(inventory)
    frequently_used = recent_selected_skill_counts(limit=80)
    under_hardened = sorted(
        [
            {
                "skill": item["name"],
                "use_count": frequently_used.get(item["name"], 0),
                "resource_score": item["resource_score"],
            }
            for item in inventory
            if frequently_used.get(item["name"], 0) >= 2 and item["resource_score"] <= 1
        ],
        key=lambda item: (item["use_count"], -item["resource_score"]),
        reverse=True,
    )
    return {
        "generated_at": iso_now(),
        "missing_middle_layers": missing_middle,
        "overlap_pairs": overlaps[:10],
        "under_hardened_high_use_skills": under_hardened[:12],
        "initiative_gaps": [item for item in initiatives if item["gap_level"] != "low"],
        "summary": "优先补 strategy-governor / workflow-hardening / skill-deduper / incentive governor 这类中层器官。",
    }


def proposal_object_expansion_status(records: list[dict[str, Any]] | None = None) -> dict[str, Any]:
    rows = records if records is not None else iter_evolution_records(limit=200)
    skill_sample_runs: list[str] = []
    workflow_sample_runs: list[str] = []
    clone_sample_runs: list[str] = []
    skill_fallback_runs: list[str] = []
    workflow_fallback_runs: list[str] = []
    clone_fallback_runs: list[str] = []
    for record in rows:
        run_id = str(record.get("run_id") or "").strip()
        task_text = normalize_prompt(str(record.get("task_text") or ""))
        if not run_id:
            continue
        route_payload = load_route_payload_for_record(record)
        is_skill_sample = "phase4-skill-recruitment-sample" in run_id or "skill recruitment proposal sample" in task_text
        is_workflow_sample = "phase4-workflow-hardening-sample" in run_id or "workflow hardening proposal sample" in task_text
        is_clone_sample = "phase4-clone-training-sample" in run_id or "clone training recommendation sample" in task_text
        if is_skill_sample:
            if run_id not in skill_sample_runs:
                skill_sample_runs.append(run_id)
        elif normalize_list(route_payload.get("skill_recruitment_suggestion")) and run_id not in skill_fallback_runs:
            skill_fallback_runs.append(run_id)
        if is_workflow_sample:
            if run_id not in workflow_sample_runs:
                workflow_sample_runs.append(run_id)
        elif normalize_list(route_payload.get("workflow_hardening_suggestion")) and run_id not in workflow_fallback_runs:
            workflow_fallback_runs.append(run_id)
        if is_clone_sample:
            if run_id not in clone_sample_runs:
                clone_sample_runs.append(run_id)
        elif normalize_list(route_payload.get("clone_training_recommendation")) and run_id not in clone_fallback_runs:
            clone_fallback_runs.append(run_id)
    skill_runs = skill_sample_runs or skill_fallback_runs[:1]
    workflow_runs = workflow_sample_runs or workflow_fallback_runs[:1]
    clone_runs = clone_sample_runs or clone_fallback_runs[:1]
    return {
        "skill_recruitment_run_ids": skill_runs,
        "workflow_hardening_run_ids": workflow_runs,
        "clone_training_run_ids": clone_runs,
        "phase4_complete": bool(skill_runs and workflow_runs and clone_runs),
    }


