def build_agent_scorecard(inventory: list[dict[str, Any]], recent_runs: list[dict[str, Any]]) -> list[dict[str, Any]]:
    selected_counts = recent_selected_skill_counts(limit=120)
    verification_counts: dict[str, list[dict[str, Any]]] = {}
    skill_run_map: dict[str, list[dict[str, Any]]] = {}
    for record in recent_runs:
        verification = normalize_verification_result(record.get("verification_result"))
        for skill in normalize_list(record.get("skills_selected")):
            verification_counts.setdefault(skill, []).append(verification)
            skill_run_map.setdefault(skill, []).append(record)
    rows: list[dict[str, Any]] = []
    for item in inventory:
        name = item["name"]
        verifications = verification_counts.get(name, [])
        records = skill_run_map.get(name, [])
        proposal_metrics = aggregate_proposal_metrics(records)
        completed = len(
            [
                v for v in verifications
                if str(v.get("status") or "").strip().lower() in {"completed", "done", "passed", "success"}
            ]
        )
        evidence_total = sum(len(normalize_list(v.get("evidence"))) for v in verifications)
        open_questions_total = sum(len(normalize_list(v.get("open_questions"))) for v in verifications)
        selected_total = max(1, len(verifications))
        closure_quality = round(completed / selected_total, 2)
        verification_strength = round(evidence_total / selected_total + proposal_metrics["proposal_quality"] * 0.5, 2)
        distortion_rate = round(open_questions_total / selected_total, 2)
        reuse_contribution = selected_counts.get(name, 0)
        strategic_alignment = 1.0 if strategic_goal_for_item(item) in {"G1", "G2", "G3"} else 0.5
        if proposal_metrics["proposal_support_count"] > 0:
            strategic_alignment = round(min(1.0, strategic_alignment + proposal_metrics["proposal_target_binding_rate"] * 0.15), 2)
        human_interruption_cost = 1.0 if "授权" in item.get("boundary", "") or "human" in item.get("boundary", "").lower() else 0.4
        if proposal_metrics["proposal_support_count"] > 0:
            human_interruption_cost = round(
                max(0.2, human_interruption_cost - proposal_metrics["proposal_boundary_discipline"] * 0.15),
                2,
            )
        rows.append(
            {
                "skill": name,
                "closure_quality": closure_quality,
                "verification_strength": verification_strength,
                "reuse_contribution": reuse_contribution,
                "distortion_rate": distortion_rate,
                "strategic_alignment": strategic_alignment,
                "human_interruption_cost": human_interruption_cost,
                "proposal_support_count": proposal_metrics["proposal_support_count"],
                "proposal_support_rate": proposal_metrics["proposal_support_rate"],
                "proposal_quality": proposal_metrics["proposal_quality"],
                "proposal_target_binding_rate": proposal_metrics["proposal_target_binding_rate"],
                "proposal_boundary_discipline": proposal_metrics["proposal_boundary_discipline"],
                "proposal_governance_score": proposal_metrics["proposal_governance_score"],
            }
        )
    rows.sort(key=lambda item: (item["closure_quality"], item["verification_strength"], item["reuse_contribution"]), reverse=True)
    return rows


def build_routing_credit(scorecard: list[dict[str, Any]]) -> list[dict[str, Any]]:
    credits: list[dict[str, Any]] = []
    for item in scorecard:
        proposal_bonus = round(
            float(item.get("proposal_quality") or 0.0) * 7
            + float(item.get("proposal_support_rate") or 0.0) * 3
            + float(item.get("proposal_target_binding_rate") or 0.0) * 2
            + float(item.get("proposal_boundary_discipline") or 0.0) * 2,
            2,
        )
        composite = round(
            item["closure_quality"] * 40
            + item["verification_strength"] * 15
            + min(item["reuse_contribution"], 10) * 3
            + item["strategic_alignment"] * 20
            - item["distortion_rate"] * 10
            - item["human_interruption_cost"] * 8,
            2,
        )
        composite = round(
            composite + proposal_bonus,
            2,
        )
        credits.append(
            {
                "skill": item["skill"],
                "routing_credit": composite,
                "proposal_bonus": proposal_bonus,
                "explanation": (
                    "奖励真闭环、强验真、战略对齐和可复用贡献；惩罚高失真和高人类打扰成本。"
                    if proposal_bonus <= 0
                    else "奖励真闭环、强验真、战略对齐和可复用贡献；当 proposal 具备 evidence gate、target binding 和 boundary discipline 时，再给予 bounded proposal bonus。"
                ),
            }
        )
    credits.sort(key=lambda item: item["routing_credit"], reverse=True)
    return credits


def build_autonomy_tiers(scorecard: list[dict[str, Any]], routing_credit: list[dict[str, Any]]) -> list[dict[str, Any]]:
    credits = {item["skill"]: item["routing_credit"] for item in routing_credit}
    tiers: list[dict[str, Any]] = []
    for item in scorecard:
        credit = credits.get(item["skill"], 0.0)
        proposal_quality = float(item.get("proposal_quality") or 0.0)
        proposal_support_count = int(item.get("proposal_support_count") or 0)
        trusted_gate = proposal_support_count == 0 or proposal_quality >= 0.45
        guarded_gate = proposal_support_count == 0 or proposal_quality >= 0.7
        if credit >= 55 and item["distortion_rate"] <= 0.3 and guarded_gate:
            tier = "guarded-autonomy"
        elif credit >= 35 and trusted_gate:
            tier = "trusted-suggest"
        elif credit >= 15:
            tier = "suggest"
        else:
            tier = "observe"
        tiers.append(
            {
                "skill": item["skill"],
                "autonomy_tier": tier,
                "routing_credit": credit,
                "proposal_quality_gate_passed": guarded_gate if tier == "guarded-autonomy" else trusted_gate,
            }
        )
    tiers.sort(key=lambda item: (AUTONOMY_TIERS.index(item["autonomy_tier"]), -item["routing_credit"]))
    return tiers


