def auth_manifest_status(auth_manifest: dict[str, Any], surface: str) -> str:
    for item in auth_manifest.get("surfaces", []):
        if str(item.get("surface") or "") == surface:
            return str(item.get("status") or "blocked_system")
    return "blocked_system"


def build_browser_auth_surface(
    *,
    surface: str,
    credential_source: str,
    required_scopes_or_session: list[str],
    profile_paths: list[Path],
    evidence_paths: list[Path] | None,
    checked_at: str,
) -> dict[str, Any]:
    ready = any(path_has_payload(path) for path in profile_paths)
    if evidence_paths:
        ready = ready or any(path_has_payload(path) for path in evidence_paths)
    status = "ready" if ready else "blocked_login"
    evidence_refs = [
        str(path)
        for path in [*profile_paths, *(evidence_paths or [])]
        if path_has_payload(path)
    ]
    return {
        "surface": surface,
        "access_path": "browser_session",
        "status": status,
        "human_action_required": [] if ready else ["login_browser"],
        "credential_source": credential_source,
        "required_scopes_or_session": required_scopes_or_session,
        "last_check_at": checked_at,
        "blocking_reason": "" if ready else "missing_authenticated_browser_session",
        "diagnosis": {
            "state": "confirmed",
            "principal": "browser_session",
            "resource_id": "",
            "management_console_path": "",
            "confirmed_findings": (
                ["Local browser session evidence is present and can be reused without interrupting the user."]
                if ready
                else ["No reusable authenticated browser session was found in the expected local profiles."]
            ),
            "current_best_hypothesis": (
                ""
                if ready
                else "Try reusing a local browser profile first; ask the user to log in only if local reuse still fails."
            ),
            "superseded_reasons": [],
            "evidence_refs": evidence_refs,
            "next_ai_action": (
                "Reuse the existing local browser session and avoid interrupting the user."
                if ready
                else "Attempt one local browser-profile reuse path before requesting a user login."
            ),
        },
    }


def parse_json_output(text: str) -> dict[str, Any]:
    raw = str(text or "").strip()
    if not raw:
        return {}
    try:
        payload = json.loads(raw)
    except json.JSONDecodeError:
        return {}
    return payload if isinstance(payload, dict) else {}


def classify_feishu_km_probe(result: dict[str, Any]) -> dict[str, Any]:
    payload = parse_json_output(str(result.get("stdout") or ""))
    error_payload = payload.get("error") if isinstance(payload.get("error"), dict) else {}
    missing_scopes = normalize_list(error_payload.get("missing_scopes"))
    error_code = str(error_payload.get("code") or "").strip()
    app_id = feishu_km_app_id()
    principal = f"tenant_access_token via {app_id}" if app_id else "tenant_access_token via Open Platform cli app"
    if payload.get("ok") is True:
        return {
            "status": "ready",
            "missing_scopes": missing_scopes,
            "blocking_reason": "",
            "diagnosis": {
                "state": "confirmed",
                "principal": principal,
                "resource_id": app_id,
                "management_console_path": f"https://open.feishu.cn/app/{app_id}" if app_id else "https://open.feishu.cn/app",
                "confirmed_findings": [
                    "Open Platform credentials are valid and the current probe did not report a blocking platform error."
                ],
                "current_best_hypothesis": "",
                "superseded_reasons": [],
                "evidence_refs": [],
                "next_ai_action": "Continue with deeper Aily probes before asking the user to do anything.",
            },
        }
    haystack = "\n".join(
        [
            json.dumps(payload, ensure_ascii=False),
            str(result.get("stdout") or ""),
            str(result.get("stderr") or ""),
        ]
    ).lower()
    if missing_scopes or "99991672" in haystack or "scope" in haystack or "permission" in haystack:
        return {
            "status": "blocked_scope",
            "missing_scopes": missing_scopes,
            "blocking_reason": "missing_required_scopes",
            "diagnosis": {
                "state": "confirmed",
                "principal": principal,
                "resource_id": app_id,
                "management_console_path": f"https://open.feishu.cn/app/{app_id}/auth" if app_id else "https://open.feishu.cn/app",
                "confirmed_findings": [
                    "The Open Platform caller is valid, but required Aily scopes are still missing."
                ],
                "current_best_hypothesis": "Grant the missing scopes in Feishu Open Platform before retrying Aily probes.",
                "superseded_reasons": [],
                "evidence_refs": [],
                "next_ai_action": "Re-run auth-check, list-assets, list-skills, and ask after scopes are granted.",
            },
        }
    if error_code == "2320008" or "飞书机器人渠道" in haystack or "机器人渠道" in haystack or "应用信息" in haystack:
        return {
            "status": "blocked_system",
            "missing_scopes": missing_scopes,
            "blocking_reason": "wrong_aily_app_object_layer",
            "diagnosis": {
                "state": "confirmed",
                "principal": principal,
                "resource_id": "spring_* Aily app object (not the Open Platform cli_* client id)",
                "management_console_path": AILY_APP_MANAGEMENT_CONSOLE_URL,
                "confirmed_findings": [
                    "Aily data-knowledge app_id belongs to the Smart Partner Building Platform object layer rather than the Open Platform cli_* client id.",
                    "The current caller is authenticating with cli_* credentials while the target Aily runtime object is a spring_* app."
                ],
                "current_best_hypothesis": "Lock the exact spring app, then verify the app-identity API/SDK switch and publish state inside the Aily admin backend before asking the user to click anything.",
                "superseded_reasons": [
                    "`missing_aily_bot_channel_publish` was an earlier surface-level guess and is now superseded by the confirmed spring-vs-cli object-layer mismatch."
                ],
                "evidence_refs": [
                    str(path)
                    for path in [
                        AILY_ADMIN_LANDING_EVIDENCE,
                        AILY_APP_MANAGEMENT_EVIDENCE,
                        AILY_APP_KNOWLEDGE_MANAGE_EVIDENCE,
                    ]
                    if path.exists()
                ],
                "next_ai_action": "Inspect the Aily admin backend app list, match the enterprise knowledge Q&A spring app, and verify the application-identity API/SDK switch before requesting any human action.",
            },
        }
    if "asset" in haystack or "data asset" in haystack or "binding" in haystack or "知识资产" in haystack:
        return {
            "status": "blocked_asset_binding",
            "missing_scopes": missing_scopes,
            "blocking_reason": "missing_knowledge_asset_binding",
            "diagnosis": {
                "state": "hypothesis",
                "principal": principal,
                "resource_id": "Aily data asset binding",
                "management_console_path": AILY_APP_MANAGEMENT_CONSOLE_URL,
                "confirmed_findings": [
                    "The probe failed at the knowledge-asset or binding layer after authentication succeeded."
                ],
                "current_best_hypothesis": "Aily data assets or skills may not yet be bound to the target app object.",
                "superseded_reasons": [],
                "evidence_refs": [],
                "next_ai_action": "Inspect the Aily app bindings and skill/data-asset associations before asking the user for help.",
            },
        }
    return {
        "status": "blocked_system",
        "missing_scopes": missing_scopes,
        "blocking_reason": "probe_failed",
        "diagnosis": {
            "state": "hypothesis",
            "principal": principal,
            "resource_id": app_id,
            "management_console_path": AILY_ADMIN_CONSOLE_URL,
            "confirmed_findings": [
                "The probe failed, but the object layer has not been fully identified from the current error payload."
            ],
            "current_best_hypothesis": "Gather one more round of platform evidence before deciding whether this is a scope, asset-binding, or backend-object issue.",
            "superseded_reasons": [],
            "evidence_refs": [],
            "next_ai_action": "Collect a more specific backend or documentation signal before sending any human action request.",
        },
    }


def build_aily_auth_surface(checked_at: str) -> dict[str, Any]:
    if not FEISHU_KM_SCRIPT.exists():
        return {
            "surface": "ask_feishu_aily",
            "access_path": "open_platform_api",
            "status": "blocked_system",
            "human_action_required": ["install_feishu_km_skill"],
            "credential_source": str(FEISHU_KM_SCRIPT),
            "required_scopes_or_session": FEISHU_KM_REQUIRED_SCOPES,
            "last_check_at": checked_at,
            "blocking_reason": "missing_feishu_km_script",
            "diagnosis": {
                "state": "confirmed",
                "principal": "local_ai_tooling",
                "resource_id": str(FEISHU_KM_SCRIPT),
                "management_console_path": "",
                "confirmed_findings": ["The local feishu-km script is missing, so no Aily API probe can run yet."],
                "current_best_hypothesis": "Restore the local feishu-km skill before retrying Aily diagnostics.",
                "superseded_reasons": [],
                "evidence_refs": [],
                "next_ai_action": "Restore the missing feishu-km script locally.",
            },
        }
    if not feishu_km_credentials_present():
        return {
            "surface": "ask_feishu_aily",
            "access_path": "open_platform_api",
            "status": "blocked_system",
            "human_action_required": ["copy_app_id", "copy_app_secret", "grant_required_scopes"],
            "credential_source": "env:FEISHU_APP_ID, env:FEISHU_APP_SECRET",
            "required_scopes_or_session": FEISHU_KM_REQUIRED_SCOPES,
            "last_check_at": checked_at,
            "blocking_reason": "missing_app_credentials",
            "diagnosis": {
                "state": "confirmed",
                "principal": "Open Platform cli app credentials",
                "resource_id": "",
                "management_console_path": "https://open.feishu.cn/app",
                "confirmed_findings": ["Aily probes cannot start because FEISHU_APP_ID / FEISHU_APP_SECRET are not both present."],
                "current_best_hypothesis": "Collect the Open Platform app credentials first, then continue diagnosis on the AI side.",
                "superseded_reasons": [],
                "evidence_refs": [],
                "next_ai_action": "Request FEISHU_APP_ID and FEISHU_APP_SECRET from the user only after local checks are exhausted.",
            },
        }
    auth_result = run_command_capture(["python3", str(FEISHU_KM_SCRIPT), "auth-check"], cwd=PROJECT_ROOT, timeout=30)
    auth_probe = classify_feishu_km_probe(auth_result)
    auth_status = str(auth_probe.get("status") or "blocked_system")
    missing_scopes = normalize_list(auth_probe.get("missing_scopes"))
    blocking_reason = str(auth_probe.get("blocking_reason") or "")
    diagnosis = auth_probe.get("diagnosis") if isinstance(auth_probe.get("diagnosis"), dict) else {}
    if auth_status == "ready":
        probe_commands = [
            ["python3", str(FEISHU_KM_SCRIPT), "ask", "--message", "你好"],
            ["python3", str(FEISHU_KM_SCRIPT), "list-assets"],
            ["python3", str(FEISHU_KM_SCRIPT), "list-skills"],
        ]
        status = "ready"
        blocking_reason = ""
        diagnosis = auth_probe.get("diagnosis") if isinstance(auth_probe.get("diagnosis"), dict) else {}
        status_rank = {"ready": 0, "blocked_asset_binding": 1, "blocked_scope": 2, "blocked_system": 3}
        for command in probe_commands:
            probe_result = run_command_capture(command, cwd=PROJECT_ROOT, timeout=30)
            probe = classify_feishu_km_probe(probe_result)
            probe_status = str(probe.get("status") or "blocked_system")
            probe_missing_scopes = normalize_list(probe.get("missing_scopes"))
            probe_reason = str(probe.get("blocking_reason") or "")
            missing_scopes.extend(probe_missing_scopes)
            if status_rank.get(probe_status, 0) >= status_rank.get(status, 0):
                status = probe_status
                blocking_reason = probe_reason
                diagnosis = probe.get("diagnosis") if isinstance(probe.get("diagnosis"), dict) else diagnosis
    else:
        status = auth_status
    missing_scopes = sorted(set(missing_scopes))
    human_action_required: list[str]
    if status == "ready":
        human_action_required = []
    elif status == "blocked_scope":
        human_action_required = ["grant_required_scopes"]
    elif status == "blocked_system" and blocking_reason == "wrong_aily_app_object_layer":
        human_action_required = []
    else:
        human_action_required = []
    return {
        "surface": "ask_feishu_aily",
        "access_path": "open_platform_api",
        "status": status,
        "human_action_required": human_action_required,
        "credential_source": "env:FEISHU_APP_ID, env:FEISHU_APP_SECRET",
        "required_scopes_or_session": missing_scopes or FEISHU_KM_REQUIRED_SCOPES,
        "last_check_at": checked_at,
        "blocking_reason": blocking_reason,
        "diagnosis": diagnosis,
    }


def find_auth_surface(auth_manifest: dict[str, Any], surface: str) -> dict[str, Any]:
    for item in auth_manifest.get("surfaces", []):
        if str(item.get("surface") or "") == surface:
            return item
    return {}


def pressure_test_current_blocker(auth_manifest: dict[str, Any], mvp_verdict: dict[str, Any] | None = None) -> str:
    verdict = mvp_verdict if isinstance(mvp_verdict, dict) else {}
    if str(verdict.get("status") or "") == "pass_mvp":
        return ""
    aily_surface = find_auth_surface(auth_manifest, "ask_feishu_aily")
    for surface_name in ["feishu_wiki_doc", "feishu_minutes"]:
        surface = find_auth_surface(auth_manifest, surface_name)
        if surface and str(surface.get("status") or "") != "ready":
            return str(surface.get("blocking_reason") or "")
    blocking_gates = [str(item).strip() for item in verdict.get("blocking_gates", []) if str(item).strip()]
    primary_evidence_gates = [
        gate for gate in blocking_gates if gate in {"need_more_feishu_doc_reads", "need_more_collaboration_trace"}
    ]
    if primary_evidence_gates:
        return primary_evidence_gates[0]
    if (
        "need_kb_round_one_interview" in blocking_gates
        and aily_surface
        and str(aily_surface.get("status") or "") != "ready"
    ):
        return "enhancer_unavailable"
    if blocking_gates:
        return blocking_gates[0]
    if aily_surface and str(aily_surface.get("status") or "") != "ready":
        return "enhancer_unavailable"
    return ""


def derive_pressure_test_closure_state(auth_manifest: dict[str, Any], mvp_verdict: dict[str, Any]) -> str:
    verdict_status = str(mvp_verdict.get("status") or "")
    if verdict_status == "pass_mvp":
        return "completed"
    main_surfaces = [
        item
        for item in auth_manifest.get("surfaces", [])
        if str(item.get("surface") or "") in {"feishu_wiki_doc", "feishu_minutes"}
    ]
    main_statuses = [str(item.get("status") or "") for item in main_surfaces]
    if "blocked_system" in main_statuses:
        return "blocked_system"
    if any(status in {"blocked_scope", "blocked_asset_binding", "blocked_login"} for status in main_statuses):
        return "blocked_needs_user"
    blocking_gates = {str(item).strip() for item in mvp_verdict.get("blocking_gates", []) if str(item).strip()}
    if "need_user_micro_interview" in blocking_gates:
        return "blocked_needs_user"
    if str(find_auth_surface(auth_manifest, "ask_feishu_aily").get("blocking_reason") or "") == "wrong_aily_app_object_layer":
        return "failed_partial"
    if verdict_status == "blocked_system":
        return "blocked_system"
    if blocking_gates:
        return "failed_partial"
    return "failed_partial"


def detect_pressure_test_exploratory_mutations() -> list[dict[str, Any]]:
    mutations: list[dict[str, Any]] = []
    if MYAI_PLUGIN_DRAFT_EVIDENCE.exists():
        mutations.append(
            {
                "label": "myai_plugin_draft",
                "status": "exploratory_mutation",
                "summary": "Created a hidden MyAI plugin draft while exploring a side path that does not prove the Aily data-knowledge ask chain.",
                "evidence_refs": [str(MYAI_PLUGIN_DRAFT_EVIDENCE)],
            }
        )
    if OPEN_PLATFORM_VERSION_PUBLISH_EVIDENCE.exists():
        mutations.append(
            {
                "label": "open_platform_version_1_0_9_publish",
                "status": "exploratory_mutation",
                "summary": "Published Open Platform version 1.0.9 while testing release state; this does not prove that the Aily knowledge-Q&A path is wired correctly.",
                "evidence_refs": [str(OPEN_PLATFORM_VERSION_PUBLISH_EVIDENCE)],
            }
        )
    return mutations


def build_pressure_test_self_evaluation(
    auth_manifest: dict[str, Any],
    closure_state: str,
    mvp_verdict: dict[str, Any],
) -> dict[str, str]:
    blocker = pressure_test_current_blocker(auth_manifest, mvp_verdict)
    blocking_gates = {str(item).strip() for item in mvp_verdict.get("blocking_gates", []) if str(item).strip()}
    if blocker == "wrong_aily_app_object_layer":
        return {
            "gained": "已经确认旧的“机器人渠道发布”判断属于错层解释，并定位到 Aily 的 spring app 对象层与管理后台入口。",
            "wasted": "前半程把表层报错当成了最终根因，还做了 MyAI draft / 1.0.9 publish 这类 exploratory mutation，且 canonical 记录没有及时回写真相。",
            "next_iterate": "先锁定真实 spring app，再确认 Aily 管理后台中的 application-identity API/SDK 开关与发布状态，只有拿到精确页面和动作后才打断用户。",
        }
    if closure_state == "completed":
        enhancer_status = str(mvp_verdict.get("enhancer_status") or "")
        wasted = "ask.feishu / Aily 这条增强链仍未接入，所以增强型追问还没并入本轮协作协议。" if enhancer_status == "enhancer_unavailable" else "当前闭环已经成立，但仍可继续扩充更多长期材料。"
        next_iterate = "把 ask.feishu 增强追问接进来，或继续追加第二批高价值 Feishu seeds，让双原力协议更稳。" if enhancer_status == "enhancer_unavailable" else "继续用真实任务验证这份协作协议，并根据新证据微调。"
        return {
            "gained": "已经完成真实 Feishu 实读、双原力判断和最终协作协议，主闭环可以作为后续协作的可执行基线。",
            "wasted": wasted,
            "next_iterate": next_iterate,
        }
    if closure_state == "blocked_needs_user" and "need_user_micro_interview" in blocking_gates:
        return {
            "gained": "已经完成真实 Feishu 实读、首轮知识库采访的大部分自动采样，并把剩余缺口收敛到 1-3 个只能由用户主观定锚的短答问题。",
            "wasted": "知识库回答还不能完全替代你的主观体感，导致互为投射护栏和高成功率触发点仍差最后一层定锚。",
            "next_iterate": "只向用户发 1-3 个微采访短答，拿到后立即重跑综合，让 collaboration protocol 真正进入可复用状态。",
        }
    if closure_state == "failed_partial" and blocking_gates.intersection({"need_more_feishu_doc_reads", "need_more_collaboration_trace"}):
        return {
            "gained": "已经重建了新的证据链、seed frontier 和双原力协议框架，没有再把旧 baseline 直接当作人物真相。",
            "wasted": "AI 侧这轮真实 Feishu 实读还没达到闭环阈值，至少 2 个文档类源和 1 个协作 trace 仍未稳定入链。",
            "next_iterate": "继续完成核心种子解析和 Feishu 实读，先拿下 2 个文档类源与 1 个协作 trace，再进入 interview enrich。",
        }
    if closure_state == "failed_partial" and blocking_gates.intersection({"need_kb_round_one_interview", "need_more_interview_quality"}):
        return {
            "gained": "主闭环骨架已经到位，且知识库采访被正式纳入判定逻辑，不再把“有采访题”误当成“采访已完成”。",
            "wasted": "首轮知识库 8 题还没有以足够质量完整入链，所以这轮仍停在 almost-ready，而不是 fully-closed。",
            "next_iterate": "优先打通并补齐 8 题 ask.feishu 采访，让知识库回答进入 canonical run；只有剩下纯主观空缺时才请求用户短答。",
        }
    if closure_state == "blocked_system":
        return {
            "gained": "已经把飞书 read-first 授权、双原力 pressure test、以及 MVP baseline 接成一条真实可运行链路。",
            "wasted": "当前仍卡在系统或接线前置条件，远端 Feishu enrich 还没有真正发生。",
            "next_iterate": "继续补齐系统前置条件后，再按 seed frontier 进入第二轮 enrich 和综合。",
        }
    return {
        "gained": "已经把飞书 read-first 授权、双原力 pressure test、以及 MVP verdict 接成一条真实可运行链路。",
        "wasted": "当前结果仍受局部材料和外部系统状态约束，尚未构成完整历史理解。",
        "next_iterate": "继续补齐关键源材料并重跑下一轮综合。",
    }


def pressure_test_diagnosis_drift(auth_manifest: dict[str, Any]) -> list[dict[str, str]]:
    drift: list[dict[str, str]] = []
    for item in auth_manifest.get("surfaces", []):
        diagnosis = item.get("diagnosis") if isinstance(item.get("diagnosis"), dict) else {}
        for reason in normalize_list(diagnosis.get("superseded_reasons")):
            drift.append(
                {
                    "surface": str(item.get("surface") or ""),
                    "reason": reason,
                }
            )
    return drift


def build_yuanli_auth_manifest(
    *,
    checked_at: str,
    feishu_root_source: Path,
    feishu_catalog_file: Path,
    minutes_url: str,
) -> dict[str, Any]:
    minutes_profiles = transcript_browser_profile_candidates("feishu_minutes")
    surfaces = [
        build_browser_auth_surface(
            surface="feishu_wiki_doc",
            credential_source=str(FEISHU_READER_PROFILE_DIR),
            required_scopes_or_session=["authenticated browser session"],
            profile_paths=[FEISHU_READER_PROFILE_DIR, DEFAULT_CHROME_USER_DATA_DIR],
            evidence_paths=[feishu_root_source, feishu_catalog_file],
            checked_at=checked_at,
        ),
        build_browser_auth_surface(
            surface="feishu_bitable_inspect_export",
            credential_source=str(FEISHU_BITABLE_PROFILE_DIR),
            required_scopes_or_session=["authenticated browser session"],
            profile_paths=[FEISHU_BITABLE_PROFILE_DIR, FEISHU_READER_PROFILE_DIR, DEFAULT_CHROME_USER_DATA_DIR],
            evidence_paths=[],
            checked_at=checked_at,
        ),
        build_browser_auth_surface(
            surface="feishu_minutes",
            credential_source=str(minutes_profiles[0]) if minutes_profiles else str(FEISHU_READER_PROFILE_DIR),
            required_scopes_or_session=["authenticated browser session"],
            profile_paths=minutes_profiles or [FEISHU_READER_PROFILE_DIR, DEFAULT_CHROME_USER_DATA_DIR],
            evidence_paths=[],
            checked_at=checked_at,
        ),
        build_aily_auth_surface(checked_at),
    ]
    return {
        "mode": "read_first",
        "created_at": checked_at,
        "surfaces": surfaces,
        "targets": {
            "wiki_doc_root_source": str(feishu_root_source),
            "catalog_source": str(feishu_catalog_file),
            "minutes_url": minutes_url,
            "aily_scopes": FEISHU_KM_REQUIRED_SCOPES,
        },
    }


