def execute_get_biji_web_command(
    *,
    command: list[str],
    run_dir: Path,
    request_payload: dict[str, Any],
    operation: str,
    source_query: str,
    topic_id: str,
    run_id: str,
    link_for_index: str = "",
) -> int:
    result = run_command_capture(command, cwd=run_dir, timeout=max(30, int(request_payload.get("timeout_seconds", 300)) + 30))
    parsed = parse_labeled_lines(result.get("stdout", ""), result.get("stderr", ""))
    response_payload: dict[str, Any] = {
        "command_result": result,
        "parsed_output": parsed,
    }
    verification_note = "Command failed before producing structured evidence."
    success = int(result.get("returncode", 1)) == 0
    note_id = parsed.get("note_id", "")
    note_title = parsed.get("title", "")
    answer = ""
    hits: list[dict[str, Any]] = []
    if parsed.get("saved_result"):
        result_path = Path(parsed["saved_result"])
        if result_path.exists():
            response_payload["script_result"] = read_json(result_path)
            note_id = str(response_payload["script_result"].get("note_id") or note_id).strip()
            note_title = str(response_payload["script_result"].get("note_title") or note_title).strip()
    if parsed.get("saved_workflow_json"):
        workflow_path = Path(parsed["saved_workflow_json"])
        if workflow_path.exists():
            response_payload["workflow_result"] = read_json(workflow_path)
            note_id = str(response_payload["workflow_result"].get("note_id") or note_id).strip()
            note_title = str(response_payload["workflow_result"].get("note_title") or note_title).strip()
            response_payload["workflow_result_path"] = str(workflow_path.resolve())
    transcript_json = parsed.get("saved_transcript_json", "")
    transcript_txt = parsed.get("saved_transcript_txt", "")
    if operation == "get_biji.ingest_link":
        if success and transcript_txt:
            verification_note = "Get笔记 web ingestion succeeded and produced an original transcript artifact."
        elif success:
            verification_note = "Get笔记 web ingestion succeeded and produced a note artifact."
        elif "did not expose an original transcript" in str(result.get("stderr") or ""):
            verification_note = "Get笔记 imported the link but only exposed a summary note, not an original transcript."
        elif "not logged in" in str(result.get("stderr") or ""):
            verification_note = "Get笔记 session is not logged in."
    elif operation == "get_biji.fetch_original":
        if success and transcript_txt:
            verification_note = "Get笔记 original transcript fetch succeeded and produced transcript artifacts."
        elif "not logged in" in str(result.get("stderr") or ""):
            verification_note = "Get笔记 session is not logged in."
    record_payload = build_get_biji_record(
        source="get_biji_web",
        operation=operation,
        success=success,
        topic_id=topic_id,
        query=source_query,
        answer=answer,
        hits=hits,
        raw_response_path=run_dir / "get-biji-response.json",
        verification_note=verification_note,
        run_id=run_id,
        metadata={
            "note_id": note_id,
            "note_title": note_title,
            "transcript_json": transcript_json,
            "transcript_txt": transcript_txt,
            "script_path": str(GET_BIJI_TRANSCRIPT_SCRIPT),
            "stdout": result.get("stdout", ""),
            "stderr": result.get("stderr", ""),
            "deduped": False,
        },
        error="" if success else str(result.get("stderr") or result.get("stdout") or "").strip(),
    )
    write_get_biji_artifacts(run_dir, request_payload=request_payload, response_payload=response_payload, record_payload=record_payload)
    if link_for_index:
        store_get_biji_link_record(
            link_for_index,
            {
                "note_id": note_id,
                "note_title": note_title,
                "topic_id": topic_id,
                "operation": operation,
                "success": success,
                "transcript_json": transcript_json,
                "transcript_txt": transcript_txt,
                "raw_response_path": str((run_dir / "get-biji-response.json").resolve()),
                "record_path": str((run_dir / "get-biji-record.json").resolve()),
                "run_id": run_id,
            },
        )
    print(f"run_id: {run_id}")
    print(f"run_dir: {run_dir}")
    print(f"source: get_biji_web")
    print(f"operation: {operation}")
    print(f"success: {success}")
    if note_id:
        print(f"note_id: {note_id}")
    if note_title:
        print(f"title: {note_title}")
    if transcript_txt:
        print(f"transcript_txt: {transcript_txt}")
    print(f"verification_note: {verification_note}")
    return 0 if success else 1


def execute_get_biji_ingest_link(args: argparse.Namespace, run_dir: Path, run_id: str) -> int:
    verify_get_biji_transcript_tool()
    normalized_link = normalize_get_biji_link(args.link)
    request_payload = {
        "operation": "get_biji.ingest_link",
        "link": normalized_link,
        "mode": args.mode,
        "topic_id": str(args.topic_id or os.getenv("GET_BIJI_TOPIC_ID", "")).strip(),
        "timeout_seconds": int(args.timeout_seconds),
    }
    existing = lookup_get_biji_link(normalized_link)
    if existing:
        record_payload = build_get_biji_record(
            source="get_biji_web",
            operation="get_biji.ingest_link",
            success=bool(existing.get("success", True)),
            topic_id=str(existing.get("topic_id") or request_payload["topic_id"]).strip(),
            query=normalized_link,
            raw_response_path=run_dir / "get-biji-response.json",
            verification_note="Reused existing Get笔记 link mapping from local canonical index.",
            run_id=run_id,
            metadata={**existing, "deduped": True},
            error="" if existing.get("success", True) else "reused_failed_record",
        )
        write_get_biji_artifacts(
            run_dir,
            request_payload=request_payload,
            response_payload={"deduped": True, "existing_record": existing},
            record_payload=record_payload,
        )
        print(f"run_id: {run_id}")
        print(f"run_dir: {run_dir}")
        print("source: get_biji_web")
        print("operation: get_biji.ingest_link")
        print("deduped: true")
        print(f"note_id: {existing.get('note_id', '')}")
        print("verification_note: Reused existing Get笔记 link mapping from local canonical index.")
        return 0 if existing.get("success", True) else 1
    command = [
        "python3",
        str(GET_BIJI_TRANSCRIPT_SCRIPT),
        args.mode,
        "--link",
        normalized_link,
        "--output-dir",
        str(run_dir),
        "--timeout-seconds",
        str(args.timeout_seconds),
    ]
    return execute_get_biji_web_command(
        command=command,
        run_dir=run_dir,
        request_payload=request_payload,
        operation="get_biji.ingest_link",
        source_query=normalized_link,
        topic_id=request_payload["topic_id"],
        run_id=run_id,
        link_for_index=normalized_link,
    )


def execute_get_biji_fetch_original(args: argparse.Namespace, run_dir: Path, run_id: str) -> int:
    verify_get_biji_transcript_tool()
    request_payload = {
        "operation": "get_biji.fetch_original",
        "note_id": str(args.note_id).strip(),
        "topic_id": str(args.topic_id or os.getenv("GET_BIJI_TOPIC_ID", "")).strip(),
        "timeout_seconds": int(args.timeout_seconds),
    }
    command = [
        "python3",
        str(GET_BIJI_TRANSCRIPT_SCRIPT),
        "fetch-original",
        "--note-id",
        str(args.note_id).strip(),
        "--output-dir",
        str(run_dir),
    ]
    return execute_get_biji_web_command(
        command=command,
        run_dir=run_dir,
        request_payload=request_payload,
        operation="get_biji.fetch_original",
        source_query=str(args.note_id).strip(),
        topic_id=request_payload["topic_id"],
        run_id=run_id,
    )


def classify_get_biji_batch_item(record_payload: dict[str, Any]) -> dict[str, Any]:
    metadata = record_payload.get("metadata") if isinstance(record_payload.get("metadata"), dict) else {}
    verification_note = str(record_payload.get("verification_note") or "").strip()
    note_text = normalize_prompt(
        " ".join(
            [
                verification_note,
                str(record_payload.get("error") or ""),
                str(metadata.get("stderr") or ""),
            ]
        )
    )
    transcript_txt = str(metadata.get("transcript_txt") or "").strip()
    transcript_exists = bool(transcript_txt and Path(transcript_txt).expanduser().exists())
    note_id = str(metadata.get("note_id") or "").strip()
    deduped = bool(metadata.get("deduped"))
    if transcript_txt:
        return {
            "status": "transcript_ready",
            "blocking": False,
            "transcript_exists": transcript_exists,
            "note_id": note_id,
            "deduped": deduped,
            "reason": verification_note or "Transcript artifact is available.",
        }
    if "summary note, not an original transcript" in note_text or (
        bool(record_payload.get("success")) and note_id and not transcript_txt
    ):
        return {
            "status": "summary_only",
            "blocking": False,
            "transcript_exists": False,
            "note_id": note_id,
            "deduped": deduped,
            "reason": verification_note or "Imported note exists without an original transcript artifact.",
        }
    if "not logged in" in note_text:
        return {
            "status": "blocked_or_failed",
            "blocking": True,
            "transcript_exists": False,
            "note_id": note_id,
            "deduped": deduped,
            "reason": verification_note or "Get笔记 session is not logged in.",
        }
    return {
        "status": "blocked_or_failed",
        "blocking": False,
        "transcript_exists": False,
        "note_id": note_id,
        "deduped": deduped,
        "reason": verification_note or "Batch item failed without a recoverable transcript or summary result.",
    }


def summarize_get_biji_batch(results_payload: dict[str, Any]) -> str:
    request = results_payload.get("request", {})
    manifest = results_payload.get("manifest", {})
    stats = results_payload.get("stats", {})
    verification = results_payload.get("verification", {})
    lines = [
        "# Get笔记 B站批处理摘要",
        "",
        f"- `up_url`: `{manifest.get('up_url', request.get('up_url', ''))}`",
        f"- `requested_url`: `{request.get('up_url', '')}`",
        f"- `mode`: `{request.get('mode', '')}`",
        f"- `manifest_entries`: `{manifest.get('entry_count', 0)}`",
        f"- `planned_items`: `{stats.get('planned_items', 0)}`",
        f"- `transcript_ready`: `{stats.get('transcript_ready', 0)}`",
        f"- `summary_only`: `{stats.get('summary_only', 0)}`",
        f"- `blocked_or_failed`: `{stats.get('blocked_or_failed', 0)}`",
        f"- `skipped_existing`: `{stats.get('skipped_existing', 0)}`",
        "",
        "## Verification",
        "",
        f"- `transcript_check`: `{verification.get('transcript_check', {}).get('status', 'not_run')}`",
        f"- `knowledge_check`: `{verification.get('knowledge_check', {}).get('status', 'not_run')}`",
        f"- `feishu_check`: `{verification.get('feishu_check', {}).get('status', 'not_run')}`",
    ]
    failures = [item for item in results_payload.get("items", []) if item.get("status") == "blocked_or_failed"]
    if failures:
        lines.extend(["", "## Failed Items", ""])
        for item in failures[:10]:
            lines.append(f"- `{item.get('ordinal')}` {item.get('title', '')} -> {item.get('reason', '')}")
    return "\n".join(lines) + "\n"


class LinkHrefParser(HTMLParser):
    def __init__(self, predicate: Any) -> None:
        super().__init__()
        self.predicate = predicate
        self.entries: list[dict[str, Any]] = []
        self._stack: list[dict[str, Any]] = []

    def handle_starttag(self, tag: str, attrs: list[tuple[str, str | None]]) -> None:
        if tag.lower() != "a":
            return
        attr_map = {key: value or "" for key, value in attrs}
        href = str(attr_map.get("href") or "").strip()
        if not href or not self.predicate(href):
            return
        self._stack.append(
            {
                "href": href,
                "title_attr": clean_html_text(attr_map.get("title", "")),
                "texts": [],
            }
        )

    def handle_data(self, data: str) -> None:
        if not self._stack:
            return
        text = clean_html_text(data)
        if text:
            self._stack[-1]["texts"].append(text)

    def handle_endtag(self, tag: str) -> None:
        if tag.lower() != "a" or not self._stack:
            return
        item = self._stack.pop()
        title = item["title_attr"] or clean_html_text(" ".join(item["texts"]))
        self.entries.append({"href": item["href"], "title": title})


def load_feishu_claw_bridge_module():
    if not FEISHU_CLAW_BRIDGE_SCRIPT.exists():
        raise FileNotFoundError(f"Feishu claw bridge script not found: {FEISHU_CLAW_BRIDGE_SCRIPT}")
    module_name = "ai_da_guan_jia_feishu_claw_bridge"
    if module_name in sys.modules:
        return sys.modules[module_name]
    spec = importlib.util.spec_from_file_location(module_name, FEISHU_CLAW_BRIDGE_SCRIPT)
    if spec is None or spec.loader is None:
        raise RuntimeError(f"Unable to load Feishu claw bridge from {FEISHU_CLAW_BRIDGE_SCRIPT}")
    module = importlib.util.module_from_spec(spec)
    sys.modules[module_name] = module
    spec.loader.exec_module(module)
    return module


def fetch_text_document(
    url: str,
    *,
    timeout_seconds: float = 20.0,
    headers: dict[str, str] | None = None,
) -> dict[str, Any]:
    target = str(url or "").strip()
    if not target:
        return {"ok": False, "status_code": 0, "final_url": "", "headers": {}, "body": "", "error": "empty_url"}
    if target.startswith("file://"):
        path = Path(urllib_parse.urlsplit(target).path)
        if not path.exists():
            return {
                "ok": False,
                "status_code": 404,
                "final_url": target,
                "headers": {},
                "body": "",
                "error": f"file_not_found: {path}",
            }
        return {
            "ok": True,
            "status_code": 200,
            "final_url": target,
            "headers": {},
            "body": path.read_text(encoding="utf-8", errors="ignore"),
            "error": "",
        }
    if "://" not in target and Path(target).exists():
        path = Path(target)
        return {
            "ok": True,
            "status_code": 200,
            "final_url": str(path.resolve()),
            "headers": {},
            "body": path.read_text(encoding="utf-8", errors="ignore"),
            "error": "",
        }
    request_headers = {
        "User-Agent": "ai-da-guan-jia/0.1",
        "Accept": "text/html,application/xhtml+xml,application/json;q=0.9,*/*;q=0.8",
    }
    if headers:
        request_headers.update(headers)
    request = urllib_request.Request(target, headers=request_headers, method="GET")
    try:
        with urllib_request.urlopen(request, timeout=timeout_seconds) as response:
            body = response.read().decode("utf-8", errors="ignore")
            return {
                "ok": True,
                "status_code": getattr(response, "status", 200),
                "final_url": response.geturl(),
                "headers": dict(response.headers.items()),
                "body": body,
                "error": "",
            }
    except urllib_error.HTTPError as exc:
        body = exc.read().decode("utf-8", errors="ignore")
        return {
            "ok": False,
            "status_code": exc.code,
            "final_url": target,
            "headers": dict(exc.headers.items()) if exc.headers else {},
            "body": body,
            "error": f"http_{exc.code}",
        }
    except (urllib_error.URLError, TimeoutError, ValueError) as exc:
        return {
            "ok": False,
            "status_code": 0,
            "final_url": target,
            "headers": {},
            "body": "",
            "error": str(exc),
        }


def transcript_browser_profile_candidates(source_type: str) -> list[Path]:
    is_feishu_source = str(source_type or "").startswith("feishu")
    env_key = "AI_DA_GUAN_JIA_FEISHU_PROFILE_DIR" if is_feishu_source else "AI_DA_GUAN_JIA_GET_BIJI_PROFILE_DIR"
    env_path = str(os.getenv(env_key, "")).strip()
    defaults = (
        [FEISHU_READER_PROFILE_DIR, DEFAULT_CHROME_USER_DATA_DIR]
        if is_feishu_source
        else [GET_BIJI_BROWSER_PROFILE_DIR, DEFAULT_CHROME_USER_DATA_DIR]
    )
    candidates: list[Path] = []
    if env_path:
        candidates.append(Path(env_path).expanduser().resolve())
    for path in defaults:
        resolved = path.expanduser().resolve()
        if resolved.exists():
            candidates.append(resolved)
    unique: list[Path] = []
    seen: set[str] = set()
    for path in candidates:
        key = str(path)
        if key in seen:
            continue
        seen.add(key)
        unique.append(path)
    return unique


def transcript_browser_profile_needs_shadow_copy(profile_dir: Path) -> bool:
    if profile_dir == DEFAULT_CHROME_USER_DATA_DIR:
        return True
    return any((profile_dir / name).exists() for name in ["SingletonLock", "SingletonSocket", "SingletonCookie"])


def prepare_transcript_browser_launch_dir(profile_dir: Path, *, source_type: str) -> tuple[Path, Path | None]:
    if not transcript_browser_profile_needs_shadow_copy(profile_dir):
        return profile_dir, None
    cleanup_root = Path(tempfile.mkdtemp(prefix=f"adagj-{source_type}-profile-"))
    launch_dir = cleanup_root / profile_dir.name
    shutil.copytree(
        profile_dir,
        launch_dir,
        symlinks=True,
        ignore=shutil.ignore_patterns("SingletonLock", "SingletonSocket", "SingletonCookie", "RunningChromeVersion"),
    )
    return launch_dir, cleanup_root


def launch_transcript_browser_context(playwright: Any, profile_dir: Path, *, headless: bool = True) -> Any:
    kwargs: dict[str, Any] = {
        "user_data_dir": str(profile_dir),
        "headless": headless,
        "viewport": {"width": 1440, "height": 960},
    }
    chrome_binary = Path(CHROME_PATH)
    if chrome_binary.exists():
        kwargs["executable_path"] = str(chrome_binary)
    return playwright.chromium.launch_persistent_context(**kwargs)


def browser_body_text(page: Any) -> str:
    try:
        return str(page.locator("body").inner_text(timeout=10000) or "")
    except Exception:
        return ""


def wait_for_browser_entries(page: Any, href_pattern: str, *, timeout_seconds: int = 20) -> None:
    deadline = time.time() + timeout_seconds
    while time.time() < deadline:
        body_text = browser_body_text(page)
        count = int(
            page.evaluate(
                """(pattern) => Array.from(document.querySelectorAll('a[href]'))
                .filter((node) => {
                  const href = node.href || node.getAttribute('href') || '';
                  return href.includes(pattern);
                }).length""",
                href_pattern,
            )
        )
        if count > 0 or login_like_content(body_text):
            return
        page.wait_for_timeout(1500)


def browser_minutes_entries(page: Any) -> list[dict[str, Any]]:
    raw_entries = page.evaluate(
        """
        () => Array.from(document.querySelectorAll('a[href]'))
          .map((node) => {
            const href = node.href || node.getAttribute('href') || '';
            if (!href.includes('/minutes/') || href.includes('/minutes/me')) return null;
            const title =
              (node.innerText || node.textContent || node.getAttribute('title') || '').replace(/\\s+/g, ' ').trim();
            const container = node.closest('li, article, section, div') || node.parentElement || node;
            const contextText = (container?.innerText || '').replace(/\\s+/g, ' ').trim();
            return { href, title, context_text: contextText };
          })
          .filter(Boolean)
        """,
    )
    entries: list[dict[str, Any]] = []
    seen: set[str] = set()
    excluded_ids = {"me", "home", "shared", "trash", "favorites", "starred", "recent"}
    for item in raw_entries or []:
        detail_url = str(item.get("href") or "").strip()
        match = re.search(r"/minutes/([^/?#]+)", detail_url)
        item_id = match.group(1).strip() if match else ""
        if (
            not detail_url
            or detail_url in seen
            or not item_id
            or item_id in excluded_ids
            or len(item_id) < 8
        ):
            continue
        seen.add(detail_url)
        entries.append(
            {
                "detail_url": detail_url,
                "title": str(item.get("title") or "").strip(),
                "captured_at": extract_nearby_timestamp(str(item.get("context_text") or ""), str(item.get("title") or detail_url)),
            }
        )
    return entries


def browser_get_biji_entries(page: Any) -> list[dict[str, Any]]:
    raw_entries = page.evaluate(
        """
        () => Array.from(document.querySelectorAll('a[href]'))
          .map((node) => {
            const href = node.href || node.getAttribute('href') || '';
            if (!href.includes('/note/')) return null;
            const title =
              (node.innerText || node.textContent || node.getAttribute('title') || '').replace(/\\s+/g, ' ').trim();
            const container = node.closest('li, article, section, div') || node.parentElement || node;
            const contextText = (container?.innerText || '').replace(/\\s+/g, ' ').trim();
            return { href, title, context_text: contextText };
          })
          .filter(Boolean)
        """,
    )
    entries: list[dict[str, Any]] = []
    seen: set[str] = set()
    for item in raw_entries or []:
        detail_url = str(item.get("href") or "").strip()
        note_id = note_id_from_url(detail_url)
        if not note_id or note_id in seen:
            continue
        seen.add(note_id)
        entries.append(
            {
                "note_id": note_id,
                "detail_url": detail_url,
                "title": str(item.get("title") or "").strip(),
                "captured_at": extract_nearby_timestamp(str(item.get("context_text") or ""), str(item.get("title") or note_id)),
            }
        )
    return entries


def extract_get_biji_entries_from_html_blob(html_text: str, final_url: str) -> list[dict[str, Any]]:
    entries: list[dict[str, Any]] = []
    seen: set[str] = set()
    for match in re.finditer(r"(?:note_id|noteId|id)\"?\s*[:=]\s*\"?(\d{8,})\"?", str(html_text or "")):
        note_id = match.group(1)
        if note_id in seen:
            continue
        seen.add(note_id)
        snippet = str(html_text or "")[max(0, match.start() - 300): match.end() + 800]
        title_match = re.search(r"(?:title|note_title|name)\"?\s*[:=]\s*\"([^\"]{2,160})\"", snippet)
        entries.append(
            {
                "note_id": note_id,
                "detail_url": urllib_parse.urljoin(final_url, f"/note/{note_id}"),
                "title": clean_html_text(title_match.group(1)) if title_match else "",
                "captured_at": extract_nearby_timestamp(snippet, note_id),
            }
        )
    return entries


def fetch_browser_document(url: str, *, source_type: str, output_dir: Path) -> dict[str, Any]:
    artifact_dir = ensure_dir(output_dir)
    if not module_available("playwright"):
        return {
            "ok": False,
            "status_code": 0,
            "final_url": url,
            "headers": {},
            "body": "",
            "error": "playwright_not_installed",
            "diagnosis": "browser_runtime_unavailable",
        }
    try:
        from playwright.sync_api import sync_playwright
    except Exception as exc:  # pragma: no cover
        return {
            "ok": False,
            "status_code": 0,
            "final_url": url,
            "headers": {},
            "body": "",
            "error": str(exc),
            "diagnosis": "browser_runtime_unavailable",
        }

    attempts: list[dict[str, Any]] = []
    profile_candidates = transcript_browser_profile_candidates(source_type)
    if not profile_candidates:
        return {
            "ok": False,
            "status_code": 0,
            "final_url": url,
            "headers": {},
            "body": "",
            "error": "no_profile_candidates",
            "diagnosis": "browser_profile_unavailable",
        }
    for profile_dir in profile_candidates:
        screenshot_path = artifact_dir / f"{source_type}-{normalize_slug_part(profile_dir.name or 'profile')}.png"
        cleanup_root: Path | None = None
        try:
            launch_dir, cleanup_root = prepare_transcript_browser_launch_dir(profile_dir, source_type=source_type)
            with sync_playwright() as playwright:
                context = launch_transcript_browser_context(playwright, launch_dir, headless=True)
                try:
                    page = context.pages[0] if context.pages else context.new_page()
                    page.goto(url, wait_until="domcontentloaded", timeout=60000)
                    page.wait_for_timeout(2500)
                    body_text = browser_body_text(page)
                    if not body_text:
                        page.wait_for_timeout(2000)
                        body_text = browser_body_text(page)
                    html = page.content()
                    page.screenshot(path=str(screenshot_path), full_page=False)
                    diagnosis = "auth_gate" if login_like_content(" ".join([body_text, html])) else ""
                    return {
                        "ok": not diagnosis,
                        "status_code": 200 if not diagnosis else 401,
                        "final_url": page.url,
                        "headers": {},
                        "body": html,
                        "error": "",
                        "diagnosis": diagnosis,
                        "profile_dir": str(launch_dir),
                        "screenshot_path": str(screenshot_path.resolve()),
                    }
                finally:
                    context.close()
        except Exception as exc:
            attempts.append({"profile_dir": str(profile_dir), "error": str(exc)})
        finally:
            if cleanup_root is not None:
                shutil.rmtree(cleanup_root, ignore_errors=True)
    return {
        "ok": False,
        "status_code": 0,
        "final_url": url,
        "headers": {},
        "body": "",
        "error": attempts[0]["error"] if attempts else "browser_fetch_failed",
        "diagnosis": "browser_fetch_failed",
        "attempts": attempts,
    }


def list_feishu_minutes_entries_browser(minutes_url: str, output_dir: Path) -> tuple[list[dict[str, Any]], dict[str, Any]]:
    artifact_dir = ensure_dir(output_dir)
    if not module_available("playwright"):
        return [], {"status_code": 0, "error": "playwright_not_installed", "diagnosis": "browser_runtime_unavailable"}
    try:
        from playwright.sync_api import sync_playwright
    except Exception as exc:  # pragma: no cover
        return [], {"status_code": 0, "error": str(exc), "diagnosis": "browser_runtime_unavailable"}

    attempts: list[dict[str, Any]] = []
    profile_candidates = transcript_browser_profile_candidates("feishu_minutes")
    if not profile_candidates:
        return [], {"status_code": 0, "error": "no_profile_candidates", "diagnosis": "browser_profile_unavailable"}
    for profile_dir in profile_candidates:
        screenshot_path = artifact_dir / f"listing-browser-{normalize_slug_part(profile_dir.name or 'profile')}.png"
        cleanup_root: Path | None = None
        try:
            launch_dir, cleanup_root = prepare_transcript_browser_launch_dir(profile_dir, source_type="feishu_minutes")
            with sync_playwright() as playwright:
                context = launch_transcript_browser_context(playwright, launch_dir, headless=True)
                try:
                    page = context.pages[0] if context.pages else context.new_page()
                    page.goto(minutes_url, wait_until="domcontentloaded", timeout=60000)
                    wait_for_browser_entries(page, "/minutes/")
                    body_text = browser_body_text(page)
                    html = page.content()
                    entries = browser_minutes_entries(page)
                    page.screenshot(path=str(screenshot_path), full_page=False)
                    diagnosis = "auth_gate" if login_like_content(" ".join([body_text, html])) and not entries else ""
                    return entries, {
                        "status_code": 200 if entries else 401 if diagnosis else 200,
                        "final_url": page.url,
                        "error": "",
                        "diagnosis": diagnosis,
                        "count": len(entries),
                        "listing_mode": "browser_fallback",
                        "profile_dir": str(launch_dir),
                        "screenshot_path": str(screenshot_path.resolve()),
                    }
                finally:
                    context.close()
        except Exception as exc:
            attempts.append({"profile_dir": str(profile_dir), "error": str(exc)})
        finally:
            if cleanup_root is not None:
                shutil.rmtree(cleanup_root, ignore_errors=True)
    return [], {
        "status_code": 0,
        "error": attempts[0]["error"] if attempts else "browser_listing_failed",
        "diagnosis": "browser_listing_failed",
        "attempts": attempts,
    }


