def write_feishu_km_artifacts(
    run_dir: Path,
    *,
    request_payload: dict[str, Any],
    response_payload: dict[str, Any],
    record_payload: dict[str, Any],
) -> None:
    write_json(run_dir / "feishu-km-request.json", request_payload)
    write_json(run_dir / "feishu-km-response.json", response_payload)
    write_json(run_dir / "feishu-km-record.json", record_payload)


def render_feishu_km_question_markdown(request_payload: dict[str, Any]) -> str:
    question = str(request_payload.get("question") or "").strip()
    source_url = str(request_payload.get("source_url") or FEISHU_KM_DEFAULT_SOURCE_URL).strip()
    return "\n".join(
        [
            "# 飞书知识问答提问包",
            "",
            f"- `knowledge_source_type`: `{request_payload.get('knowledge_source_type', FEISHU_KM_DEFAULT_TYPE)}`",
            f"- `source`: `{request_payload.get('source', FEISHU_KM_DEFAULT_SOURCE_NAME)}`",
            f"- `access_mode`: `{request_payload.get('access_mode', 'manual_web')}`",
            f"- `asked_at`: `{request_payload.get('asked_at', '')}`",
            f"- `source_url`: `{source_url}`",
            "",
            "## 标准问法",
            "",
            question,
            "",
            "## 操作要求",
            "",
            "1. 直接在 ask.feishu 中按原文提问，不先压缩问题。",
            "2. 复制原始回答全文，不先改写、不先总结。",
            "3. 回到本地后用 `record-manual` 记录原始回答、后续追问和置信说明。",
            "",
        ]
    )


def render_feishu_km_synthesis_template(request_payload: dict[str, Any]) -> str:
    return "\n".join(
        [
            "# 飞书知识问答后处理模板",
            "",
            "## Raw Facts",
            "",
            "- 仅填写回答里直接出现的事实。",
            "",
            "## Follow-up Candidates",
            "",
            "- 这条结论的出处或证据是什么？",
            "- 哪些地方仍然不确定？",
            "- 下一轮最值得追问的问题是什么？",
            "",
            "## Planning Boundary",
            "",
            "- 只有在 `feishu-km-record.json` 已存在后，才允许进入知识库综合和行动规划。",
            "",
        ]
    )


def build_feishu_km_record(
    *,
    run_id: str,
    question: str,
    source: str,
    source_url: str,
    asked_at: str,
    raw_answer: str,
    followup_candidates: list[str],
    confidence_note: str,
    access_mode: str,
    success: bool,
    error_type: str = "",
    error_message: str = "",
) -> dict[str, Any]:
    return {
        "run_id": run_id,
        "knowledge_source_type": FEISHU_KM_DEFAULT_TYPE,
        "source": source,
        "source_url": source_url,
        "access_mode": access_mode,
        "question": question,
        "asked_at": asked_at,
        "raw_answer": raw_answer,
        "followup_candidates": followup_candidates,
        "confidence_note": confidence_note,
        "success": success,
        "error_type": error_type,
        "error_message": error_message,
        "recorded_at": iso_now(),
    }


def execute_feishu_km_prepare_manual(args: argparse.Namespace, run_dir: Path, run_id: str) -> int:
    question = str(args.question or "").strip()
    if not question:
        raise ValueError("--question cannot be empty")
    source_url = str(args.source_url or FEISHU_KM_DEFAULT_SOURCE_URL).strip() or FEISHU_KM_DEFAULT_SOURCE_URL
    asked_at = iso_now()
    request_payload = {
        "operation": "feishu_km.prepare_manual",
        "knowledge_source_type": FEISHU_KM_DEFAULT_TYPE,
        "source": FEISHU_KM_DEFAULT_SOURCE_NAME,
        "source_url": source_url,
        "access_mode": "manual_web",
        "question": question,
        "asked_at": asked_at,
    }
    response_payload = {
        "status": "awaiting_manual_answer",
        "message": "Ask the question in ask.feishu, then record the copied raw answer with feishu-km record-manual.",
    }
    record_payload = build_feishu_km_record(
        run_id=run_id,
        question=question,
        source=FEISHU_KM_DEFAULT_SOURCE_NAME,
        source_url=source_url,
        asked_at=asked_at,
        raw_answer="",
        followup_candidates=[],
        confidence_note="Pending manual answer capture.",
        access_mode="manual_web",
        success=False,
        error_type="awaiting_manual_answer",
        error_message="Manual ask packet prepared; raw answer not recorded yet.",
    )
    write_feishu_km_artifacts(
        run_dir,
        request_payload=request_payload,
        response_payload=response_payload,
        record_payload=record_payload,
    )
    (run_dir / "feishu-km-question.md").write_text(render_feishu_km_question_markdown(request_payload), encoding="utf-8")
    (run_dir / "feishu-km-synthesis-template.md").write_text(
        render_feishu_km_synthesis_template(request_payload),
        encoding="utf-8",
    )
    print(f"run_id: {run_id}")
    print(f"run_dir: {run_dir}")
    print(f"knowledge_source_type: {FEISHU_KM_DEFAULT_TYPE}")
    print("source: ask.feishu")
    print("access_mode: manual_web")
    print(f"question_file: {run_dir / 'feishu-km-question.md'}")
    print(f"request_path: {run_dir / 'feishu-km-request.json'}")
    print("next_step: copy the raw answer from ask.feishu and run feishu-km record-manual")
    return 0


def execute_feishu_km_record_manual(args: argparse.Namespace, run_dir: Path, run_id: str) -> int:
    request_path = run_dir / "feishu-km-request.json"
    request_payload = read_json(request_path) if request_path.exists() else {}
    if args.answer_file:
        raw_answer = Path(args.answer_file).expanduser().read_text(encoding="utf-8").strip()
    else:
        raw_answer = str(args.answer_text or "").strip()
    if not raw_answer:
        raise ValueError("A non-empty answer is required via --answer-text or --answer-file.")
    question = str(args.question or request_payload.get("question") or "").strip()
    if not question:
        raise ValueError("Question is missing; provide --question or prepare the manual ask first.")
    asked_at = str(request_payload.get("asked_at") or "").strip() or iso_now()
    source_url = str(request_payload.get("source_url") or args.source_url or FEISHU_KM_DEFAULT_SOURCE_URL).strip()
    followups = normalize_list(args.followup)
    response_payload = {
        "status": "recorded",
        "knowledge_source_type": FEISHU_KM_DEFAULT_TYPE,
        "source": FEISHU_KM_DEFAULT_SOURCE_NAME,
        "source_url": source_url,
        "access_mode": "manual_web",
        "question": question,
        "asked_at": asked_at,
        "answered_at": iso_now(),
        "raw_answer": raw_answer,
        "followup_candidates": followups,
        "confidence_note": str(args.confidence_note or "").strip(),
    }
    record_payload = build_feishu_km_record(
        run_id=run_id,
        question=question,
        source=FEISHU_KM_DEFAULT_SOURCE_NAME,
        source_url=source_url,
        asked_at=asked_at,
        raw_answer=raw_answer,
        followup_candidates=followups,
        confidence_note=str(args.confidence_note or "").strip(),
        access_mode="manual_web",
        success=True,
    )
    merged_request = {
        "operation": "feishu_km.prepare_manual",
        "knowledge_source_type": FEISHU_KM_DEFAULT_TYPE,
        "source": FEISHU_KM_DEFAULT_SOURCE_NAME,
        "source_url": source_url,
        "access_mode": "manual_web",
        "question": question,
        "asked_at": asked_at,
    }
    write_feishu_km_artifacts(
        run_dir,
        request_payload=merged_request,
        response_payload=response_payload,
        record_payload=record_payload,
    )
    print(f"run_id: {run_id}")
    print(f"run_dir: {run_dir}")
    print(f"knowledge_source_type: {FEISHU_KM_DEFAULT_TYPE}")
    print("source: ask.feishu")
    print("access_mode: manual_web")
    print(f"followup_count: {len(followups)}")
    print(f"record_path: {run_dir / 'feishu-km-record.json'}")
    print("verification_note: Raw question and answer are preserved for downstream synthesis.")
    return 0


def execute_feishu_km_api_readiness(args: argparse.Namespace, run_dir: Path, run_id: str) -> int:
    script_path = Path(args.script or FEISHU_KM_SCRIPT).expanduser().resolve()
    env_info = ensure_private_runtime_env(("FEISHU_APP_ID", "FEISHU_APP_SECRET"))
    payload = {
        "run_id": run_id,
        "checked_at": iso_now(),
        "knowledge_source_type": FEISHU_KM_DEFAULT_TYPE,
        "source": FEISHU_KM_DEFAULT_SOURCE_NAME,
        "script_path": str(script_path),
        "script_exists": script_path.exists(),
        "app_id_present": bool(os.getenv("FEISHU_APP_ID", "").strip()),
        "app_secret_present": bool(os.getenv("FEISHU_APP_SECRET", "").strip()),
        "credential_source": env_info["source"],
        "env_file_path": env_info["env_file_path"],
        "env_file_exists": env_info["env_file_exists"],
        "env_file_hit": env_info["env_file_hit"],
        "missing_keys": env_info["missing_keys"],
        "required_scopes": FEISHU_KM_REQUIRED_SCOPES,
        "ready_for_live_api": bool(script_path.exists() and feishu_km_credentials_present()),
        "next_commands": [
            "python3 ~/.codex/skills/feishu-km/scripts/feishu_km.py auth-check",
            "python3 ~/.codex/skills/feishu-km/scripts/feishu_km.py list-assets",
            "python3 ~/.codex/skills/feishu-km/scripts/feishu_km.py ask --message '<question>'",
        ],
    }
    write_json(run_dir / "feishu-km-api-readiness.json", payload)
    print(f"run_id: {run_id}")
    print(f"run_dir: {run_dir}")
    print(f"script_exists: {payload['script_exists']}")
    print(f"app_id_present: {payload['app_id_present']}")
    print(f"app_secret_present: {payload['app_secret_present']}")
    print(f"ready_for_live_api: {payload['ready_for_live_api']}")
    print(f"readiness_path: {run_dir / 'feishu-km-api-readiness.json'}")
    return 0 if payload["ready_for_live_api"] else 1


def command_feishu_km(args: argparse.Namespace) -> int:
    if args.feishu_km_command == "record-manual":
        run_id = str(args.run_id or "").strip()
        if not run_id:
            raise ValueError("--run-id is required for feishu-km record-manual")
        run_dir = find_run_dir(run_id)
        return execute_feishu_km_record_manual(args, run_dir, run_id)

    created_at = iso_now()
    run_id = str(args.run_id or allocate_run_id(created_at))
    run_dir = run_dir_for(run_id, created_at)
    if args.feishu_km_command == "prepare-manual":
        return execute_feishu_km_prepare_manual(args, run_dir, run_id)
    if args.feishu_km_command == "api-readiness":
        return execute_feishu_km_api_readiness(args, run_dir, run_id)
    raise ValueError(f"Unsupported feishu-km command: {args.feishu_km_command}")


def command_yuanli_pressure_test(args: argparse.Namespace) -> int:
    created_at = str(args.created_at or iso_now())
    run_id = str(args.run_id or allocate_run_id(created_at))
    run_dir = run_dir_for(run_id, created_at)
    prompt = str(
        args.prompt
        or "重跑我和用户从认识到现在的双原力压力测试与 MVP 演练，少打扰，优先复用现有语料与已知 Feishu 根源。"
    ).strip()
    if not prompt:
        raise ValueError("--prompt cannot be empty")

    yuanli_root = Path(args.yuanli_skill_root or YUANLI_JUEXING_ROOT).expanduser().resolve()
    yuanli_script = yuanli_root / "scripts" / "yuanli_juexing.py"
    if not yuanli_script.exists():
        raise ValueError(f"yuanli-juexing script not found: {yuanli_script}")
    yuanli_run_id = allocate_yuanli_run_id(yuanli_root, created_at, args.yuanli_run_id)

    thread_source_file = Path(args.thread_source_file or (yuanli_root / "artifacts" / "sources" / YUANLI_DEFAULT_THREAD_SOURCE.name)).expanduser().resolve()
    ensure_dir(thread_source_file.parent)
    thread_source_file.write_text(build_yuanli_pressure_thread_source(), encoding="utf-8")

    transcript_source_file = Path(args.transcript_source_file or (yuanli_root / "artifacts" / "sources" / YUANLI_DEFAULT_TRANSCRIPT_SOURCE.name)).expanduser().resolve()
    clarification_source_file = Path(args.clarification_source_file or (yuanli_root / "artifacts" / "sources" / YUANLI_DEFAULT_CLARIFICATION_SOURCE.name)).expanduser().resolve()
    ai_worklog_file = (
        Path(args.ai_worklog_file).expanduser().resolve()
        if args.ai_worklog_file
        else latest_ai_da_guan_jia_worklog(exclude_run_id=run_id)
    )
    feishu_root_source = Path(args.feishu_root_source_file or YUANLI_FEISHU_ROOT_SOURCE).expanduser().resolve()
    feishu_catalog_file = Path(args.feishu_catalog_file or YUANLI_FEISHU_CATALOG).expanduser().resolve()

    topic = str(args.topic or "AI大管家 + 原力觉醒 压力测试 / MVP").strip()
    note = str(
        args.note
        or "AI大管家 编排 read-first Feishu auth routing，并为 原力觉醒 建立 baseline pressure-test run。"
    ).strip()

    init_command = [
        "python3",
        str(yuanli_script),
        "init-run",
        "--topic",
        topic,
        "--note",
        note,
        "--run-id",
        yuanli_run_id,
        "--source-file",
        str(thread_source_file),
    ]
    if transcript_source_file.exists():
        init_command.extend(["--source-file", str(transcript_source_file)])
    if clarification_source_file.exists():
        init_command.extend(["--source-file", str(clarification_source_file)])
    init_result = run_command_capture(init_command, cwd=yuanli_root, timeout=60)
    if int(init_result.get("returncode", 1)) != 0:
        raise ValueError(f"Failed to initialize yuanli-juexing run: {init_result.get('stderr', '').strip()}")

    yuanli_runs_root = yuanli_root / "artifacts" / "runs"
    yuanli_run_dir = find_run_dir_under(yuanli_runs_root, yuanli_run_id)

    auth_manifest = build_yuanli_auth_manifest(
        checked_at=created_at,
        feishu_root_source=feishu_root_source,
        feishu_catalog_file=feishu_catalog_file,
        minutes_url=str(args.minutes_url or DEFAULT_FEISHU_MINUTES_URL),
    )
    write_json(yuanli_run_dir / "auth-manifest.json", auth_manifest)

    catalog_payload = read_json(feishu_catalog_file) if feishu_catalog_file.exists() else {}
    seed_map = build_yuanli_seed_map(auth_manifest, catalog_payload if isinstance(catalog_payload, dict) else {}, str(args.minutes_url or DEFAULT_FEISHU_MINUTES_URL))
    source_map = read_json(yuanli_run_dir / "source-map.json")
    source_map["seed_sources"] = seed_map
    write_json(yuanli_run_dir / "seed-source-map.json", seed_map)
    write_json(yuanli_run_dir / "source-map.json", source_map)

    evidence_ingestion = collect_yuanli_pressure_test_evidence(
        yuanli_script=yuanli_script,
        yuanli_root=yuanli_root,
        yuanli_run_dir=yuanli_run_dir,
        ai_run_dir=run_dir,
        created_at=created_at,
        catalog_payload=catalog_payload if isinstance(catalog_payload, dict) else {},
        auth_manifest=auth_manifest,
        minutes_url=str(args.minutes_url or DEFAULT_FEISHU_MINUTES_URL),
    )
    source_map = evidence_ingestion.get("source_map", source_map)
    seed_map = evidence_ingestion.get("seed_map", seed_map)

    mvp_verdict = {"status": "blocked_system", "next_seeds": []}
    if not args.skip_synthesis:
        synth_result = run_command_capture(
            ["python3", str(yuanli_script), "synthesize-dual-force", "--run-dir", str(yuanli_run_dir)],
            cwd=yuanli_root,
            timeout=60,
        )
        if int(synth_result.get("returncode", 1)) != 0:
            raise ValueError(f"Failed to synthesize yuanli-juexing run: {synth_result.get('stderr', '').strip()}")
        mirror_result = run_command_capture(
            ["python3", str(yuanli_script), "prepare-governance-mirror", "--run-dir", str(yuanli_run_dir)],
            cwd=yuanli_root,
            timeout=60,
        )
        if int(mirror_result.get("returncode", 1)) != 0:
            raise ValueError(f"Failed to prepare governance mirror: {mirror_result.get('stderr', '').strip()}")
        memory_packet = read_json(yuanli_run_dir / "memory-packet.json")
        mvp_verdict = memory_packet.get("mvp_verdict", mvp_verdict)
    closure_state = derive_pressure_test_closure_state(auth_manifest, mvp_verdict)
    current_blocker = pressure_test_current_blocker(auth_manifest, mvp_verdict)
    diagnosis_drift = pressure_test_diagnosis_drift(auth_manifest)
    exploratory_mutations = detect_pressure_test_exploratory_mutations()
    self_evaluation = build_pressure_test_self_evaluation(auth_manifest, closure_state, mvp_verdict)

    situation_map = {
        "自治判断": "高自治，除 Feishu 登录、授权、复制粘贴 App 凭证这些真实人类边界外，不打断用户。",
        "全局最优判断": "先做最小真实压力测试，不做全库漫游，不把局部材料伪装成全历史理解。",
        "能力复用判断": "复用 ai-da-guan-jia、yuanli-juexing、feishu-reader、feishu-km、feishu-bitable-bridge 这一条最小充分链路。",
        "验真判断": "必须实际生成一轮新的 dual-force run、auth-manifest、seed frontier 和 MVP verdict，不能只口头复盘。",
        "进化判断": "每轮都记录 gained、wasted、next iterate，并把后续授权与加料点显式化。",
        "当前最大失真": "把“从认识到现在”误写成基于少量样例和局部摘要的虚假全历史理解。",
    }

    payload = {
        "run_id": run_id,
        "created_at": created_at,
        "task_text": prompt,
        "selected_skills": ["yuanli-juexing", "feishu-reader", "feishu-km", "feishu-bitable-bridge"],
        "situation_map": situation_map,
        "yuanli_run_id": yuanli_run_id,
        "yuanli_run_dir": str(yuanli_run_dir),
        "auth_manifest": auth_manifest,
        "seed_map": seed_map,
        "formal_local_sources": [
            str(path)
            for path in [thread_source_file, transcript_source_file, clarification_source_file]
            if path and Path(path).exists()
        ],
        "readiness_refs": [
            str(path)
            for path in [ai_worklog_file, feishu_root_source, feishu_catalog_file]
            if path and Path(path).exists()
        ],
        "local_sources": [
            str(path)
            for path in [thread_source_file, transcript_source_file, clarification_source_file]
            if path and Path(path).exists()
        ],
        "evidence_ingestion": evidence_ingestion,
        "mvp_verdict": mvp_verdict,
        "closure_state": closure_state,
        "current_blocker": current_blocker,
        "diagnosis_drift": diagnosis_drift,
        "exploratory_mutations": exploratory_mutations,
        "self_evaluation": self_evaluation,
        "verdict": mvp_verdict.get("status", "blocked_system"),
        "skip_synthesis": bool(args.skip_synthesis),
    }
    write_json(run_dir / "route.json", payload)
    (run_dir / "situation-map.md").write_text(render_situation_map(situation_map, prompt), encoding="utf-8")
    (run_dir / "pressure-test-summary.md").write_text(render_yuanli_pressure_test_summary(payload), encoding="utf-8")
    (run_dir / "worklog.md").write_text(render_yuanli_pressure_test_worklog(payload), encoding="utf-8")
    print(f"run_id: {run_id}")
    print(f"run_dir: {run_dir}")
    print(f"yuanli_run_id: {yuanli_run_id}")
    print(f"yuanli_run_dir: {yuanli_run_dir}")
    print(f"closure_state: {payload['closure_state']}")
    print(f"verdict: {payload['verdict']}")
    return 0


def module_available(name: str) -> bool:
    try:
        import importlib.util

        return importlib.util.find_spec(name) is not None
    except Exception:
        return False


def command_status(result: dict[str, Any], *, success_codes: set[int] | None = None) -> str:
    allowed = success_codes or {0}
    if result.get("timed_out"):
        return "failed"
    return "passed" if int(result.get("returncode", 1)) in allowed else "blocked"


def path_access_snapshot(path: Path) -> dict[str, Any]:
    entry: dict[str, Any] = {
        "path": str(path),
        "exists": path.exists(),
        "readable": False,
        "sample_entries": [],
        "error": "",
    }
    if not path.exists():
        entry["error"] = "missing"
        return entry
    try:
        if path.is_dir():
            sample = sorted(item.name for item in path.iterdir())[:5]
            entry["sample_entries"] = sample
        else:
            path.read_bytes()[:0]
        entry["readable"] = True
    except Exception as exc:
        entry["error"] = str(exc)
    return entry


def collect_file_system_baseline() -> dict[str, Any]:
    targets = [
        Path.home(),
        Path.home() / "Desktop",
        Path.home() / "Documents",
        CODEX_HOME,
        SKILL_DIR,
    ]
    checks = [path_access_snapshot(path) for path in targets]
    status = "passed" if all(item["exists"] and item["readable"] for item in checks) else "failed"
    return {
        "status": status,
        "checks": checks,
    }


def collect_script_baseline(run_dir: Path) -> dict[str, Any]:
    doctor = run_command_capture(["python3", str(SCRIPT_DIR / "doctor.py")], cwd=SKILL_DIR)
    skills = discover_skills()
    inventory_payload = {
        "generated_at": iso_now(),
        "skills_root": str(SKILLS_ROOT),
        "count": len(skills),
        "skills": skills,
    }
    inventory_path = run_dir / "skills-inventory.json"
    write_json(inventory_path, inventory_payload)
    return {
        "status": command_status(doctor),
        "doctor": doctor,
        "inventory_count": len(skills),
        "inventory_path": str(inventory_path.resolve()),
    }


def collect_applescript_baseline() -> dict[str, Any]:
    ping = run_command_capture(["osascript", "-e", 'return "applecript-ok"'])
    processes = run_command_capture(
        ["osascript", "-e", 'tell application "System Events" to get name of every process'],
        timeout=30,
    )
    process_names = []
    if int(processes.get("returncode", 1)) == 0:
        process_names = [
            item.strip()
            for item in str(processes.get("stdout") or "").split(",")
            if item.strip()
        ]
    active_reuse_targets = [
        name for name in process_names if name in {"Google Chrome", "Safari", "Feishu", "WeChat", "Codex"}
    ]
    status = "passed" if command_status(ping) == "passed" and command_status(processes) == "passed" else "failed"
    return {
        "status": status,
        "ping": ping,
        "process_count": len(process_names),
        "active_reuse_targets": active_reuse_targets,
        "process_sample": process_names[:20],
    }


def collect_gui_baseline(run_dir: Path) -> dict[str, Any]:
    ui_scripting = run_command_capture(
        ["osascript", "-e", 'tell application "System Events" to tell process "Finder" to get name of every window'],
        timeout=30,
    )
    capture_path = run_dir / "desktop-smoke.png"
    screen_capture = run_command_capture(["screencapture", "-x", str(capture_path)], timeout=30)
    capture_exists = capture_path.exists()
    if int(screen_capture.get("returncode", 1)) != 0 and capture_path.exists():
        capture_path.unlink(missing_ok=True)
    statuses = {command_status(ui_scripting), "passed" if capture_exists else command_status(screen_capture)}
    if statuses == {"passed"}:
        status = "passed"
    elif "passed" in statuses:
        status = "partial"
    else:
        status = "blocked"
    return {
        "status": status,
        "ui_scripting": ui_scripting,
        "screen_capture": screen_capture,
        "screen_capture_path": str(capture_path.resolve()) if capture_exists else "",
    }


def run_browser_smoke_test(url: str, run_dir: Path) -> dict[str, Any]:
    screenshot_path = run_dir / "browser-smoke.png"
    if not module_available("playwright"):
        return {
            "status": "blocked",
            "url": url,
            "engine": "",
            "title": "",
            "headline": "",
            "screenshot_path": "",
            "login_reuse_status": "unavailable",
            "error": "python module playwright is not installed",
        }
    try:
        from playwright.sync_api import sync_playwright
    except Exception as exc:
        return {
            "status": "blocked",
            "url": url,
            "engine": "",
            "title": "",
            "headline": "",
            "screenshot_path": "",
            "login_reuse_status": "unavailable",
            "error": str(exc),
        }

    attempts = [
        ("chrome", {"channel": "chrome", "headless": True}),
        ("chromium", {"headless": True}),
    ]
    errors: list[str] = []
    try:
        with sync_playwright() as playwright:
            for engine_name, launch_kwargs in attempts:
                try:
                    browser = playwright.chromium.launch(**launch_kwargs)
                    page = browser.new_page()
                    page.goto(url, wait_until="domcontentloaded", timeout=20000)
                    title = page.title()
                    headline = ""
                    locator = page.locator("h1")
                    if locator.count():
                        headline = locator.first.inner_text(timeout=3000).strip()
                    page.screenshot(path=str(screenshot_path), full_page=True)
                    browser.close()
                    return {
                        "status": "passed",
                        "url": page.url,
                        "engine": engine_name,
                        "title": title,
                        "headline": headline,
                        "screenshot_path": str(screenshot_path.resolve()),
                        "login_reuse_status": "not_verified_existing_profile",
                        "error": "",
                    }
                except Exception as exc:
                    errors.append(f"{engine_name}: {exc}")
            return {
                "status": "blocked",
                "url": url,
                "engine": "",
                "title": "",
                "headline": "",
                "screenshot_path": "",
                "login_reuse_status": "not_verified_existing_profile",
                "error": " | ".join(errors),
            }
    except Exception as exc:
        return {
            "status": "blocked",
            "url": url,
            "engine": "",
            "title": "",
            "headline": "",
            "screenshot_path": "",
            "login_reuse_status": "not_verified_existing_profile",
            "error": str(exc),
        }


def resolve_feishu_sync_runtime(
    *,
    link_override: str | None = None,
    bridge_script_override: str | None = None,
) -> dict[str, Any]:
    env_info = ensure_private_runtime_env(PRIVATE_RUNTIME_ENV_KEYS)
    bridge_setting = str(bridge_script_override or os.getenv("AI_DA_GUAN_JIA_FEISHU_BRIDGE_SCRIPT", str(DEFAULT_BRIDGE))).strip()
    bridge_source = (
        "cli_override"
        if bridge_script_override
        else "process_env_or_private_env"
        if os.getenv("AI_DA_GUAN_JIA_FEISHU_BRIDGE_SCRIPT", "").strip()
        else "built_in_default"
    )
    bridge_path = Path(bridge_setting).expanduser().resolve()
    explicit_feishu_link = os.getenv("AI_DA_GUAN_JIA_FEISHU_LINK", "").strip()
    link = resolve_task_feishu_link(link_override)
    link_source = (
        "cli_override"
        if link_override
        else "process_env_or_private_env"
        if explicit_feishu_link
        else "built_in_default"
        if DEFAULT_FEISHU_LINK.strip()
        else "missing"
    )
    return {
        "env_info": env_info,
        "bridge_script": bridge_path,
        "bridge_exists": bridge_path.exists(),
        "bridge_source": bridge_source,
        "link": link,
        "link_source": link_source,
        "explicit_link_configured": bool(explicit_feishu_link),
        "default_link_available": bool(DEFAULT_FEISHU_LINK.strip()),
        "credential_source": env_info["source"],
        "missing_keys": env_info["missing_keys"],
    }


def collect_external_sync_readiness() -> dict[str, Any]:
    feishu_runtime = resolve_feishu_sync_runtime()
    bridge_path = feishu_runtime["bridge_script"]
    explicit_feishu_link = bool(feishu_runtime["explicit_link_configured"])
    default_feishu_link_available = bool(feishu_runtime["default_link_available"])
    feishu_credentials_ready = not any(
        key in {"FEISHU_APP_ID", "FEISHU_APP_SECRET"} for key in feishu_runtime["missing_keys"]
    )
    feishu_status = (
        "passed"
        if bridge_path.exists() and feishu_runtime["link"] and feishu_credentials_ready
        else "partial"
        if bridge_path.exists() and feishu_runtime["link"]
        else "blocked"
    )
    github_repo = resolve_github_ops_repo()
    github_backend = detect_github_backend()
    gh_path = shutil.which("gh") or ""
    github_status = "passed" if github_repo and github_backend["backend"] else "blocked"
    explicit_moltbook_url = os.getenv("AI_DA_GUAN_JIA_MOLTBOOK_URL", "").strip()
    moltbook_url = resolve_moltbook_url()
    moltbook_mode = resolve_moltbook_mode()
    moltbook_probe = scout_http_fetch(moltbook_url) if moltbook_url else {"status": "not_configured", "http_status": 0, "sample": ""}
    moltbook_status = (
        "passed"
        if explicit_moltbook_url and moltbook_mode == "manual_bridge"
        else "partial"
        if moltbook_url and moltbook_mode == "manual_bridge"
        else "blocked"
    )
    return {
        "feishu": {
            "status": feishu_status,
            "bridge_script": str(bridge_path),
            "bridge_exists": feishu_runtime["bridge_exists"],
            "bridge_source": feishu_runtime["bridge_source"],
            "link": feishu_runtime["link"],
            "link_source": feishu_runtime["link_source"],
            "credential_source": feishu_runtime["credential_source"],
            "missing_keys": feishu_runtime["missing_keys"],
            "env_file_path": feishu_runtime["env_info"]["env_file_path"],
            "env_file_exists": feishu_runtime["env_info"]["env_file_exists"],
            "env_file_hit": feishu_runtime["env_info"]["env_file_hit"],
            "credentials_ready": feishu_credentials_ready,
            "explicit_link_configured": explicit_feishu_link,
            "default_link_available": default_feishu_link_available,
        },
        "github": {
            "status": github_status,
            "gh_path": gh_path,
            "repo": github_repo,
            "backend": github_backend["backend"],
            "reason": github_backend["reason"],
            "token_present": bool(os.getenv("GITHUB_TOKEN", "").strip()),
        },
        "moltbook": {
            "status": moltbook_status,
            "url": moltbook_url,
            "mode": moltbook_mode,
            "explicit_url_configured": bool(explicit_moltbook_url),
            "default_url_available": bool(DEFAULT_MOLTBOOK_URL.strip()),
            "probe": moltbook_probe,
            "canonical_role": "non-canonical mirror",
        },
    }


def summarize_capability_baseline(payload: dict[str, Any]) -> dict[str, str]:
    browser = payload["browser"]
    gui = payload["gui"]
    external = payload["external_sync"]
    lines = [
        f"文件与脚本基线 {payload['file_system']['status']} / {payload['scripts']['status']}",
        f"AppleScript 与系统事件 {payload['applescript']['status']}",
        f"浏览器自动化 {browser['status']}，引擎 {browser['engine'] or 'none'}",
        f"GUI 桌面能力 {gui['status']}",
        f"Feishu {external['feishu']['status']}，GitHub {external['github']['status']}，Moltbook {external['moltbook']['status']} (non-canonical mirror)",
    ]
    if browser.get("login_reuse_status") and browser["login_reuse_status"] != "verified":
        lines.append("现有登录态复用未直接验真，仍需按具体业务场景补一次真实网页登录流。")
    return {
        "summary": "；".join(lines),
        "next_step": (
            "优先继续走本地文件 + 本地脚本 + 浏览器自动化；涉及登录态、发布、授权或外部写入时再补人类确认。"
        ),
    }


def capability_overall_status(payload: dict[str, Any]) -> str:
    core_statuses = [
        payload["file_system"]["status"],
        payload["scripts"]["status"],
        payload["applescript"]["status"],
        payload["browser"]["status"],
    ]
    if any(status == "failed" for status in core_statuses):
        return "failed"
    optional_statuses = [
        payload["gui"]["status"],
        payload["external_sync"]["feishu"]["status"],
        payload["external_sync"]["github"]["status"],
        payload["external_sync"]["moltbook"]["status"],
    ]
    if any(status in {"partial", "blocked", "failed"} for status in optional_statuses):
        return "partial"
    return "passed"


def render_capability_baseline_markdown(payload: dict[str, Any]) -> str:
    summary = payload["summary"]
    lines = [
        "# Capability Baseline",
        "",
        f"- Run ID: `{payload['run_id']}`",
        f"- Created At: `{payload['created_at']}`",
        f"- Overall Status: `{payload['overall_status']}`",
        "",
        "## Summary",
        "",
        f"- {summary['summary']}",
        f"- {summary['next_step']}",
        "",
        "## File System",
        "",
    ]
    for item in payload["file_system"]["checks"]:
        sample = ", ".join(item["sample_entries"]) or "none"
        lines.append(
            f"- `{item['path']}` :: exists={item['exists']} readable={item['readable']} sample={sample or 'none'}"
        )
    lines.extend(
        [
            "",
            "## Scripts",
            "",
            f"- Status: `{payload['scripts']['status']}`",
            f"- Inventory Count: `{payload['scripts']['inventory_count']}`",
            f"- Inventory Path: `{payload['scripts']['inventory_path']}`",
            f"- Doctor Return Code: `{payload['scripts']['doctor']['returncode']}`",
            "",
            "## Automation Surface",
            "",
            f"- AppleScript: `{payload['applescript']['status']}`",
            f"- Active Reuse Targets: {', '.join(payload['applescript']['active_reuse_targets']) or 'none'}",
            f"- Browser: `{payload['browser']['status']}` via `{payload['browser']['engine'] or 'none'}` on `{payload['browser']['url']}`",
            f"- Browser Title: {payload['browser']['title'] or 'none'}",
            f"- Browser Screenshot: `{payload['browser']['screenshot_path'] or 'none'}`",
            f"- Login Reuse Status: `{payload['browser']['login_reuse_status']}`",
            f"- GUI Desktop: `{payload['gui']['status']}`",
            f"- GUI Screenshot: `{payload['gui']['screen_capture_path'] or 'none'}`",
            "",
            "## External Sync",
            "",
            f"- Feishu: `{payload['external_sync']['feishu']['status']}`",
            f"- Feishu Bridge: `{payload['external_sync']['feishu']['bridge_script']}`",
            f"- Feishu Explicit Link Configured: `{payload['external_sync']['feishu']['explicit_link_configured']}`",
            f"- GitHub: `{payload['external_sync']['github']['status']}`",
            f"- GitHub Repo: `{payload['external_sync']['github']['repo'] or 'none'}`",
            f"- GitHub Backend: `{payload['external_sync']['github']['backend'] or 'none'}`",
            f"- GitHub Reason: `{payload['external_sync']['github']['reason'] or 'none'}`",
            f"- Moltbook: `{payload['external_sync']['moltbook']['status']}` (`{payload['external_sync']['moltbook']['canonical_role']}`)",
            f"- Moltbook URL: `{payload['external_sync']['moltbook']['url'] or 'none'}`",
            f"- Moltbook Mode: `{payload['external_sync']['moltbook']['mode']}`",
            f"- Moltbook Probe: `{payload['external_sync']['moltbook']['probe'].get('status', 'unknown')}` / HTTP `{payload['external_sync']['moltbook']['probe'].get('http_status', 0)}`",
            "",
        ]
    )
    return "\n".join(lines)


def command_capability_baseline(args: argparse.Namespace) -> int:
    created_at = str(args.created_at or iso_now())
    run_id = str(args.run_id or allocate_run_id(created_at))
    run_dir = run_dir_for(run_id, created_at)
    browser_url = str(args.browser_url or "https://example.com").strip()

    payload = {
        "run_id": run_id,
        "created_at": created_at,
        "default_execution_surface": [
            "local-files",
            "local-scripts",
            "browser-automation",
            "authenticated-session-reuse",
        ],
        "gui_policy": "on_demand_only_after_browser_or_script_path_fails",
        "file_system": collect_file_system_baseline(),
        "scripts": collect_script_baseline(run_dir),
        "applescript": collect_applescript_baseline(),
        "browser": run_browser_smoke_test(browser_url, run_dir) if not args.skip_browser else {
            "status": "skipped",
            "url": browser_url,
            "engine": "",
            "title": "",
            "headline": "",
            "screenshot_path": "",
            "login_reuse_status": "skipped",
            "error": "",
        },
        "gui": collect_gui_baseline(run_dir) if not args.skip_gui else {
            "status": "skipped",
            "ui_scripting": {},
            "screen_capture": {},
            "screen_capture_path": "",
        },
        "external_sync": collect_external_sync_readiness(),
    }
    payload["overall_status"] = capability_overall_status(payload)
    payload["summary"] = summarize_capability_baseline(payload)
    write_json(run_dir / "capability-baseline.json", payload)
    (run_dir / "capability-baseline.md").write_text(
        render_capability_baseline_markdown(payload),
        encoding="utf-8",
    )
    print(f"run_id: {run_id}")
    print(f"run_dir: {run_dir}")
    print(f"overall_status: {payload['overall_status']}")
    print(f"browser_status: {payload['browser']['status']}")
    print(f"gui_status: {payload['gui']['status']}")
    print(f"feishu_status: {payload['external_sync']['feishu']['status']}")
    print(f"github_status: {payload['external_sync']['github']['status']}")
    print(f"moltbook_status: {payload['external_sync']['moltbook']['status']}")
    return 0


def normalize_slug_part(value: str) -> str:
    text = re.sub(r"[^a-z0-9]+", "-", value.lower()).strip("-")
    return re.sub(r"-{2,}", "-", text) or "task"


def derive_prompt_keywords(prompt: str) -> list[str]:
    ascii_words = re.findall(r"[A-Za-z0-9][A-Za-z0-9\-_/]{1,30}", prompt.lower())
    cleaned: list[str] = []
    stopwords = {
        "please",
        "help",
        "with",
        "this",
        "that",
        "task",
        "need",
        "want",
        "make",
        "build",
        "update",
        "sync",
    }
    for word in ascii_words:
        token = word.strip("-_/")
        if len(token) < 3 or token in stopwords:
            continue
        cleaned.append(normalize_slug_part(token))
    return cleaned[:4]


def infer_github_type(prompt: str) -> str:
    text = normalize_prompt(prompt)
    mapping = [
        ("debug", ["debug", "bug", "报错", "修复", "异常", "失败", "排障", "fix ci"]),
        ("review", ["review", "审查", "审计", "盘点", "评估", "复盘"]),
        ("sync", ["sync", "同步", "镜像", "回写", "归档"]),
        ("publish", ["publish", "发布", "上线", "推送", "deploy"]),
        ("implement", ["implement", "实现", "开发", "编码", "写代码", "修"]),
        ("spec", ["spec", "设计", "方案", "规划", "架构", "需求", "plan"]),
        ("research", ["research", "调研", "研究", "benchmark", "攻略", "说明书", "官方文档"]),
        ("governance", ["governance", "治理", "规范", "命名", "分类", "管理"]),
    ]
    for label, patterns in mapping:
        if any(item in text for item in patterns):
            return label
    return "implement"


def infer_github_domain(prompt: str, selected_skills: list[str]) -> str:
    text = normalize_prompt(prompt)
    if any(item in text for item in ["github", "pull request", "pr", "issue", "repo", "仓库"]):
        return "github"
    if any(item in text for item in ["飞书", "feishu", "bitable", "wiki", "lark"]):
        return "feishu"
    if any(item in text for item in ["openai", "chatgpt", "responses api", "apps sdk", "codex"]):
        return "openai"
    if any(item in text for item in ["skill", "skills", "大管家", "router", "路由", "盘点"]) or any(
        name.startswith(("ai-", "skill-")) for name in selected_skills
    ):
        return "skill-system"
    if any(item in text for item in ["内容", "选题", "小红书", "公众号", "文章", "publish"]):
        return "content"
    if any(item in text for item in ["dataset", "数据", "csv", "excel", "spreadsheet", "分析"]):
        return "data"
    return "ops"


def infer_github_artifact(prompt: str, selected_skills: list[str]) -> str:
    text = normalize_prompt(prompt)
    if "skill" in text or any(name.startswith(("ai-", "skill-")) for name in selected_skills):
        return "skill"
    if any(item in text for item in ["workflow", "流程", "route", "router", "governance"]):
        return "workflow"
    if any(item in text for item in ["doc", "文档", "plan", "spec", "方案", "readme"]):
        return "doc"
    if any(item in text for item in ["dataset", "表", "csv", "excel", "jsonl"]):
        return "dataset"
    if any(item in text for item in ["api", "integration", "mcp", "bridge", "sync", "feishu"]):
        return "integration"
    if any(item in text for item in ["report", "summary", "brief", "review"]):
        return "report"
    return "code"


def should_skip_github_management(prompt: str, signals: dict[str, bool]) -> tuple[bool, str]:
    normalized = normalize_prompt(prompt)
    compact = normalized.replace(" ", "")
    if compact in GITHUB_SKIP_PATTERNS:
        return True, "casual_prompt"
    if len(compact) <= 4 and not any(signals.values()):
        return True, "too_short_without_verifiable_work"
    if compact in {"?", "？", "1", "yes", "no"}:
        return True, "non_actionable_prompt"
    return False, ""


def github_hash8(task_text: str) -> str:
    return hashlib.sha1(task_text.strip().encode("utf-8")).hexdigest()[:8]


def github_title_slug(prompt: str, type_name: str, domain: str) -> str:
    keywords = derive_prompt_keywords(prompt)
    if keywords:
        return normalize_slug_part("-".join(keywords[:3]))
    return normalize_slug_part(f"{type_name}-{domain}-task")


def github_display_title(prompt: str) -> str:
    return truncate_text(prompt.strip() or "未命名任务", 60)


def github_issue_title(classification: dict[str, Any], prompt: str) -> str:
    return f"[{classification['type']}/{classification['domain']}] {classification['slug']} | {github_display_title(prompt)}"


def github_labels(classification: dict[str, Any]) -> list[str]:
    return [
        f"type:{classification['type']}",
        f"domain:{classification['domain']}",
        f"state:{classification['state']}",
        f"artifact:{classification['artifact']}",
    ]


def default_github_owner() -> str:
    repo = git_origin_repo(SKILL_DIR)
    if not repo or "/" not in repo:
        return ""
    return repo.split("/", 1)[0]


def persisted_hub_repo() -> str:
    for path in [HUB_ROOT / "bootstrap-status.json", HUB_ROOT / "transport-status.json", HUB_ROOT / "source-topology.json"]:
        payload = load_optional_json(path)
        if not isinstance(payload, dict):
            continue
        candidate = str(payload.get("hub_repo") or "").strip()
        if candidate:
            return candidate
    if HUB_REPOS_ROOT.exists():
        repo_dirs = sorted(
            path
            for path in HUB_REPOS_ROOT.iterdir()
            if path.is_dir() and "__" in path.name and path.name not in {"contracts", "sources", "reports"}
        )
        if len(repo_dirs) == 1:
            return repo_dirs[0].name.replace("__", "/")
    return ""


def resolve_github_ops_repo(repo_override: str | None = None) -> str:
    value = (repo_override or os.getenv("AI_DA_GUAN_JIA_GITHUB_OPS_REPO", "")).strip()
    if value:
        return value
    persisted = persisted_hub_repo()
    if persisted:
        return persisted
    owner = default_github_owner()
    return f"{owner}/{DEFAULT_GITHUB_OPS_REPO_NAME}" if owner else ""


def resolve_dot_github_repo(repo_override: str | None = None) -> str:
    value = (repo_override or os.getenv("AI_DA_GUAN_JIA_GITHUB_DOT_GITHUB_REPO", "")).strip()
    if value:
        return value
    owner = default_github_owner()
    return f"{owner}/{DEFAULT_GITHUB_DOT_GITHUB_REPO}" if owner else ""


def resolve_github_project_owner() -> str:
    return (
        os.getenv("AI_DA_GUAN_JIA_GITHUB_PROJECT_OWNER", "").strip()
        or default_github_owner()
    )


def resolve_github_project_number() -> int:
    raw = os.getenv("AI_DA_GUAN_JIA_GITHUB_PROJECT_NUMBER", "").strip()
    if not raw:
        return 0
    try:
        return int(raw)
    except ValueError:
        return 0


def github_issue_body(
    *,
    task_key: str,
    run_id: str,
    prompt: str,
    route_payload: dict[str, Any],
    classification: dict[str, Any],
    run_dir: Path,
) -> str:
    selected = ", ".join(normalize_list(route_payload.get("selected_skills"))) or "none"
    verification_targets_text = "\n".join(f"- {item}" for item in normalize_list(route_payload.get("verification_targets")))
    return "\n".join(
        [
            f"<!-- ai-da-guan-jia-task:{task_key} -->",
            "# AI大管家 Task Mirror",
            "",
            f"- Task Key: `{task_key}`",
            f"- Run ID: `{run_id}`",
            f"- Local Run Dir: `{run_dir}`",
            f"- Type: `{classification['type']}`",
            f"- Domain: `{classification['domain']}`",
            f"- Artifact: `{classification['artifact']}`",
            f"- State: `{classification['state']}`",
            f"- Selected Skills: {selected}",
            "",
            "## Request",
            "",
            prompt.strip(),
            "",
            "## Verification Targets",
            "",
            verification_targets_text or "- Need an artifact check plus a goal check before reporting completion.",
        ]
    )


def build_github_classification(
    *,
    task_text: str,
    created_at: str,
    selected_skills: list[str],
    verification_status: str | None = None,
) -> dict[str, Any]:
    type_name = infer_github_type(task_text)
    domain = infer_github_domain(task_text, selected_skills)
    artifact = infer_github_artifact(task_text, selected_skills)
    verification_norm = (verification_status or "").strip().lower()
    state = "verified" if verification_norm in {"passed", "success", "done", "complete", "completed"} else "routed"
    slug = github_title_slug(task_text, type_name, domain)
    task_key = f"tsk-{parse_datetime(created_at).strftime('%Y%m%d')}-{type_name}-{domain}-{slug}-{github_hash8(task_text)}"
    return {
        "type": type_name,
        "domain": domain,
        "state": state,
        "artifact": artifact,
        "slug": slug,
        "task_key": task_key,
    }


def build_github_task_record(
    *,
    run_id: str,
    created_at: str,
    task_text: str,
    route_payload: dict[str, Any],
    run_dir: Path,
    verification_status: str | None = None,
    existing: dict[str, Any] | None = None,
) -> dict[str, Any]:
    existing = existing or {}
    skip, reason = should_skip_github_management(task_text, route_payload.get("signals", {}))
    selected = normalize_list(route_payload.get("selected_skills"))
    classification = build_github_classification(
        task_text=task_text,
        created_at=created_at,
        selected_skills=selected,
        verification_status=verification_status,
    )
    classification["state"] = existing.get("classification", {}).get("state") or classification["state"]
    if skip:
        classification["state"] = "blocked"
    target_repo = resolve_github_ops_repo(existing.get("github_repo"))
    project_owner = resolve_github_project_owner()
    project_number = resolve_github_project_number()
    issue_title = github_issue_title(classification, task_text)
    payload = {
        "run_id": run_id,
        "created_at": created_at,
        "task_text": task_text,
        "skip_github_management": skip,
        "skip_reason": reason,
        "classification": classification,
        "issue_title": issue_title,
        "issue_labels": github_labels(classification),
        "issue_body": github_issue_body(
            task_key=classification["task_key"],
            run_id=run_id,
            prompt=task_text,
            route_payload=route_payload,
            classification=classification,
            run_dir=run_dir,
        ),
        "github_repo": target_repo,
        "dot_github_repo": resolve_dot_github_repo(existing.get("dot_github_repo")),
        "github_project_owner": project_owner,
        "github_project_number": project_number,
        "github_project_url": existing.get("github_project_url")
        or (
            f"{DEFAULT_GITHUB_BASE_URL}/orgs/{project_owner}/projects/{project_number}"
            if project_owner and project_number
            else ""
        ),
        "issue_number": existing.get("issue_number"),
        "issue_url": existing.get("issue_url", ""),
        "issue_node_id": existing.get("issue_node_id", ""),
        "project_item_id": existing.get("project_item_id", ""),
        "closure_comment_id": existing.get("closure_comment_id", ""),
        "closure_comment_url": existing.get("closure_comment_url", ""),
        "github_sync_status": existing.get("github_sync_status", "pending_intake"),
        "github_archive_status": existing.get("github_archive_status", "not_archived"),
    }
    return payload


def render_github_sync_plan(github_task: dict[str, Any], phase: str) -> str:
    classification = github_task["classification"]
    lines = [
        "# GitHub Sync Plan",
        "",
        f"- Phase: `{phase}`",
        f"- Skip GitHub Management: `{github_task['skip_github_management']}`",
        f"- Task Key: `{classification['task_key']}`",
        f"- Repo: `{github_task['github_repo'] or 'unconfigured'}`",
        f"- Project: `{github_task['github_project_url'] or 'unconfigured'}`",
        f"- Issue Title: {github_task['issue_title']}",
        f"- Labels: {', '.join(github_task['issue_labels'])}",
        "",
        "## Classification",
        "",
        f"- Type: `{classification['type']}`",
        f"- Domain: `{classification['domain']}`",
        f"- State: `{classification['state']}`",
        f"- Artifact: `{classification['artifact']}`",
        "",
    ]
    if github_task["skip_github_management"]:
        lines.extend(
            [
                "## Result",
                "",
                f"- Skip reason: `{github_task['skip_reason']}`",
                "- No GitHub issue or project sync should be attempted for this run.",
                "",
            ]
        )
    else:
        lines.extend(
            [
                "## Execution Order",
                "",
                "1. Ensure the central ops issue exists or reuse the existing issue by task key.",
                "2. Normalize labels and issue body to the current task classification.",
                "3. If project config exists, add or update the issue in the configured Project.",
                "4. On closure, write a stable closure comment and update archive state.",
                "",
            ]
        )
    return "\n".join(lines)


def render_github_archive_markdown(
    github_task: dict[str, Any],
    evolution: dict[str, Any],
    run_dir: Path,
) -> str:
    verification = evolution["verification_result"]
    lines = [
        "# GitHub Archive",
        "",
        f"- Task Key: `{github_task['classification']['task_key']}`",
        f"- Run ID: `{evolution['run_id']}`",
        f"- Issue URL: {github_task.get('issue_url') or 'pending'}",
        f"- Project URL: {github_task.get('github_project_url') or 'pending'}",
        f"- Closure Comment URL: {github_task.get('closure_comment_url') or 'pending'}",
        f"- Archive Status: `{github_task.get('github_archive_status') or 'not_archived'}`",
        "",
        "## Verification",
        "",
        f"- Status: `{verification['status']}`",
        f"- Evidence: {' | '.join(normalize_list(verification.get('evidence'))) or 'none'}",
        f"- Open Questions: {' | '.join(normalize_list(verification.get('open_questions'))) or 'none'}",
        "",
        "## Evolution",
        "",
        f"- Effective Patterns: {' | '.join(normalize_list(evolution.get('effective_patterns'))) or 'none'}",
        f"- Wasted Patterns: {' | '.join(normalize_list(evolution.get('wasted_patterns'))) or 'none'}",
        f"- Next Iteration: {' | '.join(normalize_list(evolution.get('evolution_candidates'))) or 'none'}",
        "",
        f"- Local Run Dir: `{run_dir}`",
        "",
    ]
    return "\n".join(lines)


def project_status_name(classification_state: str) -> str:
    mapping = {
        "intake": "Inbox",
        "routed": "Inbox",
        "in_progress": "In Progress",
        "waiting_human": "Waiting",
        "blocked": "Waiting",
        "verified": "Verified",
        "archived": "Archived",
    }
    return mapping.get(classification_state, "Inbox")


def load_optional_json(path: Path) -> dict[str, Any]:
    if not path.exists():
        return {}
    payload = read_json(path)
    return payload if isinstance(payload, dict) else {}


def load_optional_json_list(path: Path) -> list[dict[str, Any]]:
    if not path.exists():
        return []
    payload = read_json(path)
    if not isinstance(payload, list):
        return []
    return [item for item in payload if isinstance(item, dict)]


def summarize_repo_automations() -> list[dict[str, Any]]:
    rows: list[dict[str, Any]] = []
    if not REPO_AUTOMATIONS_ROOT.exists():
        return rows
    for config_path in sorted(REPO_AUTOMATIONS_ROOT.glob("*.toml")):
        payload: dict[str, Any] = {}
        if tomllib is not None:
            try:
                with config_path.open("rb") as handle:
                    parsed = tomllib.load(handle)
                if isinstance(parsed, dict):
                    payload = parsed
            except Exception:
                payload = {}
        rows.append(
            {
                "id": str(payload.get("id") or config_path.stem),
                "path": str(config_path),
                "exists": True,
                "name": str(payload.get("name") or config_path.stem),
                "status": str(payload.get("status") or "UNKNOWN"),
                "rrule": str(payload.get("rrule") or ""),
                "prompt": str(payload.get("prompt") or ""),
            }
        )
    return rows


def load_frontdesk_session_rows(path: Path | None = None) -> list[dict[str, Any]]:
    payload = load_optional_json(path or FRONTDESK_SESSIONS_PATH)
    sessions = payload.get("sessions", payload) if isinstance(payload, dict) else {}
    if not isinstance(sessions, dict):
        return []
    rows: list[dict[str, Any]] = []
    for session_id, value in sessions.items():
        if not isinstance(value, dict):
            continue
        row = dict(value)
        row["session_id"] = str(row.get("session_id") or session_id).strip()
        rows.append(row)
    rows.sort(key=lambda item: str(item.get("updated_at") or ""), reverse=True)
    return rows


def iter_frontdesk_capture_rows(limit: int = 50) -> list[dict[str, Any]]:
    rows: list[dict[str, Any]] = []
    if not RUNS_ROOT.exists():
        return rows
    run_dirs = sorted(
        [path for path in RUNS_ROOT.glob("*/*") if path.is_dir()],
        key=lambda item: str(item),
        reverse=True,
    )
    for run_dir in run_dirs:
        route_payload = load_optional_json(run_dir / "route.json")
        if not route_payload.get("note_capture"):
            continue
        capture_dir = run_dir / "frontdesk-captures"
        if not capture_dir.exists():
            continue
        for capture_path in sorted(capture_dir.glob("*.json"), reverse=True):
            capture = load_optional_json(capture_path)
            if not capture:
                continue
            rows.append(
                {
                    "capture_id": str(capture.get("capture_id") or capture_path.stem),
                    "run_id": str(capture.get("run_id") or route_payload.get("run_id") or run_dir.name),
                    "parent_run_id": str(capture.get("parent_run_id") or ""),
                    "session_id": str(capture.get("session_id") or ""),
                    "content": str(capture.get("content") or route_payload.get("task_text") or ""),
                    "created_at": str(capture.get("created_at") or route_payload.get("created_at") or ""),
                    "sync_status": str(capture.get("sync_status") or "canonical_local_only"),
                    "artifact_path": str(capture_path),
                    "source_run_dir": str(run_dir),
                }
            )
            if len(rows) >= limit:
                return rows
    return rows


def heartbeat_task_lane(task: dict[str, Any]) -> str:
    status = str(task.get("status") or "").strip()
    human_boundary_state = str(task.get("human_boundary_state") or "").strip()
    if status == "blocked_system":
        return "blocked_system"
    if status in {"blocked", "failed_partial"}:
        return "blocked"
    if status == "blocked_needs_user" or human_boundary_state in {"needs_input", "needs_approval", "waiting_human", "required", "pending", "granted"}:
        return "waiting_human"
    if status in {"active", "planned", "in_progress", "ready", "ready_for_close"}:
        return "active"
    return "other"


def parse_clock_minutes(text: str) -> int:
    value = str(text or "").strip()
    if not value:
        raise ValueError("clock value is empty")
    parts = value.split(":", 1)
    hour = int(parts[0])
    minute = int(parts[1]) if len(parts) == 2 else 0
    if hour == 24 and minute == 0:
        return 24 * 60
    if hour < 0 or hour > 23 or minute < 0 or minute > 59:
        raise ValueError(f"invalid clock value: {text}")
    return hour * 60 + minute


def parse_hour_windows(spec: str) -> list[tuple[int, int]]:
    windows: list[tuple[int, int]] = []
    for chunk in [item.strip() for item in str(spec or "").split(",") if item.strip()]:
        if "-" not in chunk:
            start = parse_clock_minutes(chunk if ":" in chunk else f"{chunk}:00")
            end = min(start + 60, 24 * 60)
            windows.append((start, end))
            continue
        start_text, end_text = [part.strip() for part in chunk.split("-", 1)]
        start = parse_clock_minutes(start_text if ":" in start_text else f"{start_text}:00")
        end = parse_clock_minutes(end_text if ":" in end_text else f"{end_text}:00")
        windows.append((start, end))
    return windows


def time_in_windows(moment: datetime, spec: str) -> bool:
    windows = parse_hour_windows(spec)
    if not windows:
        return False
    now_minutes = moment.hour * 60 + moment.minute
    for start, end in windows:
        if start == end:
            return True
        if end > start and start <= now_minutes < end:
            return True
        if end < start and (now_minutes >= start or now_minutes < end):
            return True
    return False


def heartbeat_project_fingerprint(row: dict[str, Any]) -> str:
    return stable_hash(
        str(row.get("project_id") or ""),
        str(row.get("kind") or ""),
        str(row.get("status") or ""),
        str(row.get("lane") or ""),
        str(row.get("next_action") or ""),
        str(row.get("updated_at") or ""),
        str(row.get("requested_frontdesk_state") or ""),
        str(row.get("human_boundary_state") or ""),
    )


def build_project_heartbeat_registry(
    *,
    created_at: str,
    project_id_filter: str = "",
    frontstage_cap: int = PROJECT_HEARTBEAT_FRONTSTAGE_CAP,
) -> dict[str, Any]:
    tasks = load_canonical_entity_rows("tasks.json")
    threads = {
        str(item.get("thread_id") or item.get("id") or "").strip(): item
        for item in load_canonical_entity_rows("threads.json")
    }
    relations = load_optional_json_list(PROJECT_ROOT / "canonical" / "relations" / "relations.json")
    frontstage_rows = [
        row
        for row in load_optional_json_list(strategy_canonical_thread_registry_path())
        if str(row.get("disposition") or "").strip() == "frontstage_now"
    ][: max(frontstage_cap, 1)]
    active_threads = [
        row
        for row in load_optional_json_list(STRATEGY_CURRENT_ROOT / "active-threads.json")
        if str(row.get("status") or "").strip() != "archived"
    ]
    sessions = load_frontdesk_session_rows()
    captures = iter_frontdesk_capture_rows(limit=40)
    session_by_run_id: dict[str, list[dict[str, Any]]] = defaultdict(list)
    session_by_thread_id: dict[str, list[dict[str, Any]]] = defaultdict(list)
    session_by_task_id: dict[str, list[dict[str, Any]]] = defaultdict(list)
    for session in sessions:
        run_id = str(session.get("active_run_id") or session.get("run_id") or "").strip()
        thread_id = str(session.get("active_thread_id") or "").strip()
        if run_id:
            session_by_run_id[run_id].append(session)
        if thread_id:
            session_by_thread_id[thread_id].append(session)
        for task_id in normalize_list(session.get("active_task_ids")):
            session_by_task_id[task_id].append(session)

    frontstage_keywords: set[str] = set()
    for row in frontstage_rows:
        frontstage_keywords.add(str(row.get("canonical_thread") or "").strip())
        for alias in normalize_list(row.get("window_aliases")):
            frontstage_keywords.add(alias)

    projects: list[dict[str, Any]] = []
    used_thread_ids: set[str] = set()
    active_task_rows: list[dict[str, Any]] = []
    for task in tasks:
        status = str(task.get("status") or "").strip()
        if status in {"completed", "verified", "merged", "deferred", "archived", "handoff_only_closed"}:
            continue
        task_id = str(task.get("task_id") or task.get("id") or "").strip()
        thread_id = str(task.get("thread_id") or "").strip()
        thread = threads.get(thread_id, {})
        run_id = str(task.get("intake_run_id") or thread.get("source_run_id") or "").strip()
        title = str(task.get("title") or thread.get("title") or task_id).strip()
        lane = heartbeat_task_lane(task)
        related_sessions = session_by_task_id.get(task_id, []) + session_by_run_id.get(run_id, []) + session_by_thread_id.get(thread_id, [])
        related_sessions = [item for index, item in enumerate(related_sessions) if item and item not in related_sessions[:index]]
        requested_state = next(
            (str(item.get("requested_frontdesk_state") or "").strip() for item in related_sessions if str(item.get("requested_frontdesk_state") or "").strip()),
            "",
        )
        waiting_boundary = next(
            (
                str(item.get("pending_human_boundary") or item.get("human_boundary") or "").strip()
                for item in related_sessions
                if str(item.get("pending_human_boundary") or item.get("human_boundary") or "").strip()
            ),
            "",
        )
        verification_state = str(task.get("verification_state") or "").strip() or "unknown"
        thread_open_questions = normalize_list(thread.get("open_questions"))
        next_action = str(task.get("next_action") or task.get("required_human_input") or (thread_open_questions[0] if thread_open_questions else "")).strip()
        active_task_rows.append(
            {
                "project_id": task_id or f"thread::{thread_id}" or stable_hash(title),
                "kind": "canonical_task",
                "task_id": task_id,
                "thread_id": thread_id,
                "run_id": run_id,
                "title": title,
                "status": status or "unknown",
                "lane": lane,
                "priority": str(task.get("priority") or "P9"),
                "goal_id": str(task.get("goal_id") or thread.get("goal_id") or ""),
                "theme_id": str(thread.get("theme_id") or ""),
                "canonical_thread": str(thread.get("title") or ""),
                "disposition": "frontstage_now"
                if any(keyword and keyword in title for keyword in frontstage_keywords) or any(keyword and keyword in str(thread.get("title") or "") for keyword in frontstage_keywords)
                else "",
                "next_action": next_action,
                "requested_frontdesk_state": requested_state,
                "human_boundary_state": str(task.get("human_boundary_state") or ""),
                "pending_human_boundary": waiting_boundary,
                "verification_state": verification_state,
                "updated_at": str(task.get("updated_at") or task.get("last_updated_at") or thread.get("updated_at") or ""),
                "frontdesk_session_ids": [str(item.get("session_id") or "") for item in related_sessions if str(item.get("session_id") or "")],
                "blocker_reason": str(task.get("blocker_reason") or task.get("required_human_input") or ""),
                "relation_count": len([row for row in relations if task_id and task_id in normalize_list([row.get("from_id"), row.get("to_id")])]),
            }
        )
        if thread_id:
            used_thread_ids.add(thread_id)

    projects.extend(active_task_rows)

    for thread in active_threads:
        thread_id = str(thread.get("thread_id") or "").strip()
        if thread_id and thread_id in used_thread_ids:
            continue
        title = str(thread.get("task_text") or thread.get("canonical_thread") or thread_id).strip()
        run_id = str(thread.get("run_id") or "").strip()
        thread_open_questions = normalize_list(thread.get("open_questions"))
        related_sessions = session_by_run_id.get(run_id, []) + session_by_thread_id.get(thread_id, [])
        requested_state = next(
            (str(item.get("requested_frontdesk_state") or "").strip() for item in related_sessions if str(item.get("requested_frontdesk_state") or "").strip()),
            "",
        )
        lane = "waiting_human" if requested_state == "waiting_for_user" else ("blocked" if str(thread.get("next_blocker") or "").strip() else "active")
        projects.append(
            {
                "project_id": thread_id or stable_hash(title),
                "kind": "frontstage_thread",
                "task_id": "",
                "thread_id": thread_id,
                "run_id": run_id,
                "title": title,
                "status": str(thread.get("status") or "active"),
                "lane": lane,
                "priority": "P2",
                "goal_id": str(thread.get("goal_id") or ""),
                "theme_id": str(thread.get("theme") or ""),
                "canonical_thread": str(thread.get("canonical_thread") or ""),
                "disposition": str(thread.get("disposition") or ""),
                "next_action": str(thread.get("next_blocker") or (thread_open_questions[0] if thread_open_questions else "")).strip(),
                "requested_frontdesk_state": requested_state,
                "human_boundary_state": "not_needed",
                "pending_human_boundary": next(
                    (
                        str(item.get("pending_human_boundary") or item.get("human_boundary") or "").strip()
                        for item in related_sessions
                        if str(item.get("pending_human_boundary") or item.get("human_boundary") or "").strip()
                    ),
                    "",
                ),
                "verification_state": "unknown",
                "updated_at": "",
                "frontdesk_session_ids": [str(item.get("session_id") or "") for item in related_sessions if str(item.get("session_id") or "")],
                "blocker_reason": str(thread.get("next_blocker") or ""),
                "relation_count": 0,
            }
        )

    if not active_task_rows:
        for capture in captures:
            title = truncate_text(str(capture.get("content") or "轻记录").strip() or "轻记录", 80)
            projects.append(
                {
                    "project_id": str(capture.get("capture_id") or ""),
                    "kind": "capture_proposal",
                    "task_id": "",
                    "thread_id": "",
                    "run_id": str(capture.get("run_id") or ""),
                    "title": title,
                    "status": "proposal_only",
                    "lane": "proposal",
                    "priority": "P3",
                    "goal_id": "",
                    "theme_id": "",
                    "canonical_thread": "",
                    "disposition": "",
                    "next_action": "把这条轻记录评估成 intake proposal，而不是直接升级成正式任务。",
                    "requested_frontdesk_state": "follow_up_requested",
                    "human_boundary_state": "not_needed",
                    "pending_human_boundary": "",
                    "verification_state": "captured_canonical",
                    "updated_at": str(capture.get("created_at") or ""),
                    "frontdesk_session_ids": [str(capture.get("session_id") or "")] if str(capture.get("session_id") or "") else [],
                    "blocker_reason": "当前只有轻记录，没有对应 canonical 活跃任务。",
                    "relation_count": 0,
                    "capture_id": str(capture.get("capture_id") or ""),
                    "artifact_path": str(capture.get("artifact_path") or ""),
                }
            )

    if project_id_filter:
        projects = [
            row
            for row in projects
            if project_id_filter in str(row.get("project_id") or "") or project_id_filter in str(row.get("title") or "")
        ]

    projects.sort(
        key=lambda item: (
            0 if str(item.get("kind") or "") == "capture_proposal" else 1,
            0 if str(item.get("lane") or "") in {"blocked_system", "waiting_human"} else 1,
            str(item.get("priority") or "P9"),
            str(item.get("updated_at") or ""),
        )
    )
    return {
        "generated_at": created_at,
        "project_id_filter": project_id_filter,
        "projects": projects,
        "counts": {
            "projects": len(projects),
            "frontstage_threads": len(frontstage_rows),
            "active_threads": len(active_threads),
            "sessions": len(sessions),
            "captures": len(captures),
            "relations": len(relations),
        },
        "automations": {
            "repo": summarize_repo_automations(),
            "local": summarize_local_automations(),
        },
    }


def build_project_heartbeat_scorecard(
    registry: dict[str, Any],
    *,
    created_at: str,
    stall_rounds_threshold: int,
) -> dict[str, Any]:
    previous = load_optional_json(PROJECT_HEARTBEAT_CURRENT_ROOT / "scorecard.json")
    previous_rows = previous.get("rows", previous) if isinstance(previous, dict) else []
    previous_map = {
        str(item.get("project_id") or "").strip(): item
        for item in previous_rows
        if isinstance(item, dict) and str(item.get("project_id") or "").strip()
    }
    moment = parse_datetime(created_at)
    rows: list[dict[str, Any]] = []
    for project in registry.get("projects", []):
        project_id = str(project.get("project_id") or "").strip()
        fingerprint = heartbeat_project_fingerprint(project)
        previous_row = previous_map.get(project_id, {})
        previous_fingerprint = str(previous_row.get("fingerprint") or "")
        unchanged_rounds = int(previous_row.get("unchanged_rounds") or 0) + 1 if previous_fingerprint == fingerprint else 1
        updated_at = str(project.get("updated_at") or "").strip()
        age_hours = 999.0
        if updated_at:
            try:
                age_hours = max(0.0, (moment - parse_datetime(updated_at)).total_seconds() / 3600)
            except Exception:
                age_hours = 999.0
        momentum_score = 92.0 if age_hours <= 6 else 76.0 if age_hours <= 24 else 54.0 if age_hours <= 72 else 28.0
        if str(project.get("kind") or "") == "capture_proposal":
            momentum_score = 36.0
        if str(project.get("requested_frontdesk_state") or "") in {"resume_requested", "follow_up_requested"}:
            momentum_score = min(100.0, momentum_score + 8.0)
        stall_risk_score = min(95.0, 15.0 + max(0, unchanged_rounds - 1) * 35.0)
        if str(project.get("kind") or "") == "capture_proposal":
            stall_risk_score = 24.0
        human_waiting_score = 12.0
        if str(project.get("lane") or "") == "waiting_human":
            human_waiting_score = 86.0
        elif str(project.get("lane") or "") == "blocked_system":
            human_waiting_score = 72.0
        elif str(project.get("requested_frontdesk_state") or "") in {"waiting_for_user", "close_check_requested"}:
            human_waiting_score = 78.0
        verification_state = str(project.get("verification_state") or "").strip()
        closure_readiness_score = 14.0
        if verification_state in {"verified", "ready_for_close", "completed"}:
            closure_readiness_score = 86.0
        elif verification_state in {"captured_canonical", "captured", "unknown"}:
            closure_readiness_score = 22.0
        elif str(project.get("requested_frontdesk_state") or "") == "close_check_requested":
            closure_readiness_score = 36.0
        project_push_score = round(
            momentum_score * 0.20
            + stall_risk_score * 0.35
            + human_waiting_score * 0.25
            + closure_readiness_score * 0.20,
            2,
        )
        row = dict(project)
        row.update(
            {
                "fingerprint": fingerprint,
                "unchanged_rounds": unchanged_rounds,
                "momentum_score": round(momentum_score, 2),
                "stall_risk_score": round(stall_risk_score, 2),
                "human_waiting_score": round(human_waiting_score, 2),
                "closure_readiness_score": round(closure_readiness_score, 2),
                "project_push_score": project_push_score,
                "stall_risk": unchanged_rounds >= stall_rounds_threshold,
            }
        )
        rows.append(row)
    rows.sort(
        key=lambda item: (
            0 if str(item.get("lane") or "") == "blocked_system" else 1,
            -float(item.get("project_push_score") or 0.0),
            str(item.get("priority") or "P9"),
        )
    )
    return {
        "generated_at": created_at,
        "stall_rounds_threshold": stall_rounds_threshold,
        "rows": rows,
    }


def build_project_heartbeat_action_queue(scorecard: dict[str, Any]) -> dict[str, Any]:
    actions: list[dict[str, Any]] = []
    for row in scorecard.get("rows", []):
        kind = "monitor"
        summary = f"继续静默盯住《{row['title']}》的推进节奏。"
        reason = "当前仍有推进信号，不需要升级边界。"
        if str(row.get("kind") or "") == "capture_proposal":
            kind = "intake_proposal"
            summary = f"把轻记录《{row['title']}》转成 intake proposal，不直接升格为正式任务。"
            reason = "当前只有 capture，没有 canonical 活跃任务。"
        elif str(row.get("lane") or "") == "blocked_system":
            kind = "system_escalation"
            summary = f"升级系统阻塞《{row['title']}》，避免伪推进。"
            reason = str(row.get("blocker_reason") or "系统依赖阻塞，需要共同治理者看见。")
        elif str(row.get("lane") or "") == "waiting_human":
            kind = "human_boundary"
            summary = f"把《{row['title']}》推回共同治理者拍板。"
            reason = str(row.get("pending_human_boundary") or "已经卡在人类边界，不该继续沉默等待。")
        elif bool(row.get("stall_risk")):
            kind = "stall_nudge"
            summary = f"催办连续停滞的《{row['title']}》。"
            reason = f"连续 {row.get('unchanged_rounds')} 轮没有真实变化。"
        elif str(row.get("requested_frontdesk_state") or "") in {"resume_requested", "close_check_requested"}:
            kind = "frontdesk_follow_up"
            summary = f"优先响应前台请求《{row['title']}》。"
            reason = f"前台请求状态为 {row.get('requested_frontdesk_state')}。"
        actions.append(
            {
                "action_id": f"pha-{len(actions) + 1:02d}",
                "project_id": str(row.get("project_id") or ""),
                "title": str(row.get("title") or ""),
                "kind": kind,
                "status": str(row.get("status") or ""),
                "project_push_score": float(row.get("project_push_score") or 0.0),
                "summary": summary,
                "reason": reason,
                "next_step": str(row.get("next_action") or "") or summary,
                "human_boundary": str(row.get("pending_human_boundary") or ""),
                "source_ref": str(row.get("artifact_path") or row.get("run_id") or row.get("thread_id") or row.get("task_id") or ""),
            }
        )
        if len(actions) >= 3:
            break
    return {"generated_at": scorecard.get("generated_at", ""), "actions": actions}


def build_project_heartbeat_human_boundary_queue(scorecard: dict[str, Any]) -> dict[str, Any]:
    items: list[dict[str, Any]] = []
    for row in scorecard.get("rows", []):
        lane = str(row.get("lane") or "")
        requested_state = str(row.get("requested_frontdesk_state") or "")
        if lane not in {"blocked_system", "waiting_human"} and requested_state != "close_check_requested":
            continue
        items.append(
            {
                "project_id": str(row.get("project_id") or ""),
                "title": str(row.get("title") or ""),
                "status": "blocked_system" if lane == "blocked_system" else "blocked_needs_user",
                "reason": str(row.get("blocker_reason") or row.get("pending_human_boundary") or row.get("next_action") or ""),
                "requested_frontdesk_state": requested_state,
                "human_boundary": str(row.get("pending_human_boundary") or ""),
                "project_push_score": float(row.get("project_push_score") or 0.0),
            }
        )
    items.sort(key=lambda item: (0 if item["status"] == "blocked_system" else 1, -item["project_push_score"]))
    return {"generated_at": scorecard.get("generated_at", ""), "items": items}


def project_heartbeat_total_judgment(
    registry: dict[str, Any],
    actions: dict[str, Any],
    boundary_queue: dict[str, Any],
) -> str:
    projects = registry.get("projects", [])
    if not projects:
        return "当前没有可纳管的活跃项目，本轮保持静默，不制造假推进。"
    if boundary_queue.get("items"):
        top = boundary_queue["items"][0]
        if top.get("status") == "blocked_system":
            return "本轮优先显性化系统阻塞，避免把 runtime 问题伪装成继续推进。"
        return "本轮优先把待你拍板的事项推到前台，而不是继续让它们沉默堆积。"
    top_action = (actions.get("actions") or [{}])[0]
    if top_action.get("kind") == "stall_nudge":
        return "本轮重点处理连续停滞的 frontstage 任务，先恢复节奏，再谈扩展动作。"
    if top_action.get("kind") == "intake_proposal":
        return "本轮重点是把轻记录整理成 intake proposal，不直接把 capture 冒充成正式任务。"
    return "本轮继续静默盯住最需要推进的一条主线，只在值得打扰时打扰。"


def project_heartbeat_max_distortion(
    scorecard: dict[str, Any],
    actions: dict[str, Any],
) -> str:
    rows = scorecard.get("rows", [])
    if not rows:
        return "把定时醒来误判成必须每小时打扰共同治理者。"
    if any(str(row.get("lane") or "") == "blocked_system" for row in rows):
        return "把系统级阻塞继续包装成还在推进。"
    if any(str(row.get("kind") or "") == "capture_proposal" for row in rows):
        return "把轻记录 capture 误判成正式任务。"
    if any(bool(row.get("stall_risk")) for row in rows):
        return "任务已经停滞，但表面上看起来还在流动。"
    top_action = (actions.get("actions") or [{}])[0]
    if top_action.get("kind") == "human_boundary":
        return "已经到人类边界了，却还在系统里空转。"
    return "没有真实变化时，也为了存在感去发小时提醒。"


def build_project_heartbeat_round(
    *,
    created_at: str,
    source: str,
    registry: dict[str, Any],
    scorecard: dict[str, Any],
    actions: dict[str, Any],
    boundary_queue: dict[str, Any],
    active_hours: str,
    quiet_hours: str,
) -> dict[str, Any]:
    top_action = (actions.get("actions") or [{}])[0]
    top_boundary = (boundary_queue.get("items") or [{}])[0]
    round_key = parse_datetime(created_at).strftime("%Y-%m-%dT%H")
    return {
        "created_at": created_at,
        "round_key": round_key,
        "source": source,
        "status": "silent" if not registry.get("projects") else "ok",
        "project_count": int(registry.get("counts", {}).get("projects", 0)),
        "total_judgment": project_heartbeat_total_judgment(registry, actions, boundary_queue),
        "top_action": top_action,
        "top_actions": actions.get("actions", []),
        "top_human_boundary": top_boundary,
        "counts": {
            **dict(registry.get("counts", {})),
            "action_queue": len(actions.get("actions", [])),
            "human_boundary_queue": len(boundary_queue.get("items", [])),
        },
        "active_hours": active_hours,
        "quiet_hours": quiet_hours,
        "current_max_distortion": project_heartbeat_max_distortion(scorecard, actions),
    }


def should_notify_project_heartbeat(
    round_payload: dict[str, Any],
    *,
    active_hours: str,
    quiet_hours: str,
) -> tuple[bool, str]:
    moment = parse_datetime(str(round_payload.get("created_at") or iso_now()))
    top_action = round_payload.get("top_action") if isinstance(round_payload.get("top_action"), dict) else {}
    top_boundary = round_payload.get("top_human_boundary") if isinstance(round_payload.get("top_human_boundary"), dict) else {}
    in_active_hours = True if not active_hours else time_in_windows(moment, active_hours)
    in_quiet_hours = False if not quiet_hours else time_in_windows(moment, quiet_hours)
    reason = ""
    forced = False
    if str(top_boundary.get("status") or "") == "blocked_system":
        reason = "new_blocked_system"
        forced = True
    elif str(top_action.get("kind") or "") == "human_boundary":
        reason = "human_boundary_waiting"
    elif str(top_action.get("kind") or "") == "stall_nudge":
        reason = "stall_risk"
    elif str(top_action.get("kind") or "") == "frontdesk_follow_up":
        reason = "frontdesk_follow_up"
    if not reason:
        return False, "no_significant_change"
    if in_quiet_hours and not forced:
        return False, "quiet_hours"
    if not in_active_hours and not forced:
        return False, "outside_active_hours"
    return True, reason


def render_project_heartbeat_brief(round_payload: dict[str, Any]) -> str:
    top_action = round_payload.get("top_action") if isinstance(round_payload.get("top_action"), dict) else {}
    top_boundary = round_payload.get("top_human_boundary") if isinstance(round_payload.get("top_human_boundary"), dict) else {}
    actions = round_payload.get("top_actions") if isinstance(round_payload.get("top_actions"), list) else []
    lines = [
        "# 原力OS · 小猫小时推进简报",
        "",
        f"- 生成时间: `{round_payload.get('created_at', '')}`",
        f"- 来源: `{round_payload.get('source', '')}`",
        f"- 本小时总判断: {round_payload.get('total_judgment', '当前无摘要。')}",
        "",
        "## 最该推进的 1 件事",
        "",
        f"- {top_action.get('summary') or '当前没有需要主动推进的动作。'}",
        "",
        "## 最该你拍板的 1 件事",
        "",
        f"- {top_boundary.get('title') or '当前没有需要你立刻拍板的事项。'}"
        + (f"｜{top_boundary.get('reason')}" if top_boundary.get("reason") else ""),
        "",
        "## 本小时已自动催办 / 已记录的动作",
        "",
    ]
    if actions:
        for item in actions[:3]:
            lines.append(f"- [{item.get('kind')}] {item.get('summary')}")
    else:
        lines.append("- 本小时保持静默记录，没有新增催办。")
    lines.extend(
        [
            "",
            "## 当前最大失真",
            "",
            f"- {round_payload.get('current_max_distortion', '暂无')}",
            "",
        ]
    )
    return "\n".join(lines)


def send_project_heartbeat_to_feishu_chat(*, chat_id: str, round_payload: dict[str, Any]) -> dict[str, Any]:
    if not chat_id:
        return {"status": "skipped_missing_chat_id", "message_id": "", "error": ""}
    try:
        module = load_feishu_claw_bridge_module()
        config = module.BridgeConfig.from_env()
        auth_client = module.FeishuAuthClient(config)
        messenger = module.FeishuMessenger(auth_client)
        text_result = messenger.send_text_to_chat(chat_id, render_project_heartbeat_brief(round_payload))
        return {
            "status": "sent_text",
            "message_id": str((text_result.get("data") or {}).get("message_id") or ""),
            "error": "",
            "text_result": text_result,
        }
    except Exception as exc:
        return {"status": "send_failed", "message_id": "", "error": str(exc)}


def window_heartbeat_storage_key(window_id: str) -> str:
    slug = normalize_slug_part(window_id)[:48]
    return f"{slug}-{stable_hash(window_id)}"


def window_heartbeat_current_path(window_id: str) -> Path:
    return WINDOW_HEARTBEAT_CURRENT_ROOT / f"{window_heartbeat_storage_key(window_id)}.json"


def window_heartbeat_round_dir(window_id: str) -> Path:
    return ensure_dir(WINDOW_HEARTBEAT_ROUNDS_ROOT / window_heartbeat_storage_key(window_id))


def canonicalize_local_path(raw_path: str) -> str:
    text = raw_path.strip()
    if not text:
        return ""
    candidate = Path(text).expanduser()
    if not candidate.is_absolute():
        candidate = (Path.cwd() / candidate).resolve()
    else:
        candidate = candidate.resolve()
    try:
        return str(candidate.relative_to(PROJECT_ROOT))
    except ValueError:
        return str(candidate)


def resolve_heartbeat_path(path_text: str) -> Path:
    candidate = Path(path_text).expanduser()
    if candidate.is_absolute():
        return candidate
    return (PROJECT_ROOT / candidate).resolve()


def normalize_sole_blocker_text(value: str) -> str:
    text = value.strip()
    if text.lower() in {"", "none", "null", "n/a", "na", "no_blocker"}:
        return ""
    return text


def build_window_heartbeat_payload(
    *,
    window_id: str,
    role: str,
    current_phase: str,
    last_action: str,
    current_status: str,
    latest_evidence_paths: list[str],
    sole_blocker: str,
    updated_at: str,
) -> dict[str, Any]:
    evidence_paths = [path for path in (canonicalize_local_path(item) for item in latest_evidence_paths) if path]
    return {
        "schema_version": "window-heartbeat-v1",
        "window_id": window_id.strip(),
        "role": role.strip(),
        "current_phase": current_phase.strip(),
        "last_action": last_action.strip(),
        "current_status": current_status.strip(),
        "latest_evidence_paths": evidence_paths,
        "sole_blocker": normalize_sole_blocker_text(sole_blocker),
        "updated_at": updated_at,
    }


def validate_window_heartbeat_payload(payload: dict[str, Any]) -> None:
    required_fields = [
        "window_id",
        "role",
        "current_phase",
        "last_action",
        "current_status",
        "latest_evidence_paths",
        "sole_blocker",
        "updated_at",
    ]
    missing = [field for field in required_fields if field not in payload]
    if missing:
        raise ValueError(f"missing required fields: {', '.join(missing)}")
    for field in ["window_id", "role", "current_phase", "last_action", "current_status", "updated_at"]:
        if not isinstance(payload.get(field), str) or not str(payload.get(field)).strip():
            raise ValueError(f"field must be a non-empty string: {field}")
    if not isinstance(payload.get("sole_blocker"), str):
        raise ValueError("field must be a string: sole_blocker")
    if not isinstance(payload.get("latest_evidence_paths"), list):
        raise ValueError("field must be a list: latest_evidence_paths")
    parse_datetime(str(payload.get("updated_at") or ""))


def write_window_heartbeat(payload: dict[str, Any]) -> dict[str, str]:
    validate_window_heartbeat_payload(payload)
    created_at = str(payload.get("updated_at") or iso_now())
    current_root = ensure_dir(WINDOW_HEARTBEAT_CURRENT_ROOT)
    current_path = current_root / window_heartbeat_current_path(str(payload.get("window_id") or "")).name
    round_dir = window_heartbeat_round_dir(str(payload.get("window_id") or ""))
    round_filename = parse_datetime(created_at).strftime("%Y-%m-%dT%H-%M-%S%z") + ".json"
    round_path = round_dir / round_filename
    write_json(current_path, payload)
    write_json(round_path, payload)
    return {
        "current_path": str(current_path.resolve()),
        "round_path": str(round_path.resolve()),
    }


def load_window_heartbeat_current_records() -> list[dict[str, Any]]:
    current_root = ensure_dir(WINDOW_HEARTBEAT_CURRENT_ROOT)
    rows: list[dict[str, Any]] = []
    for path in sorted(current_root.glob("*.json")):
        if path.name in {
            WINDOW_HEARTBEAT_SUMMARY_FILENAME,
            WINDOW_HEARTBEAT_GOVERNANCE_FILENAME,
        }:
            continue
        try:
            payload = read_json(path)
        except Exception:
            continue
        if isinstance(payload, dict):
            rows.append(payload)
    rows.sort(key=lambda item: str(item.get("window_id") or ""))
    return rows


def load_previous_window_heartbeat(window_id: str, updated_at: str) -> dict[str, Any] | None:
    round_dir = window_heartbeat_round_dir(window_id)
    current_stamp = parse_datetime(updated_at)
    candidates: list[tuple[datetime, dict[str, Any]]] = []
    for path in sorted(round_dir.glob("*.json")):
        try:
            payload = read_json(path)
        except Exception:
            continue
        if not isinstance(payload, dict):
            continue
        candidate_updated_at = str(payload.get("updated_at") or "")
        if not candidate_updated_at:
            continue
        candidate_stamp = parse_datetime(candidate_updated_at)
        if candidate_stamp < current_stamp:
            candidates.append((candidate_stamp, payload))
    if not candidates:
        return None
    candidates.sort(key=lambda item: item[0])
    return candidates[-1][1]


def latest_window_governance_cleanup_manifest_path() -> Path | None:
    candidates = sorted(RUNS_ROOT.glob("*/adagj-black-satellite-governance-cleanup-*/run-manifest.json"))
    if not candidates:
        return None
    return max(candidates, key=lambda path: (path.parent.as_posix(), path.stat().st_mtime))


def load_window_cleanup_annotations() -> dict[str, dict[str, Any]]:
    manifest_path = latest_window_governance_cleanup_manifest_path()
    if not manifest_path or not manifest_path.exists():
        return {}
    try:
        manifest = read_json(manifest_path)
    except Exception:
        return {}
    if not isinstance(manifest, dict):
        return {}

    annotations: dict[str, dict[str, Any]] = {}
    for package_key, label_key in (("package_a", "recommended_label"), ("package_b", "recommended_action")):
        package_meta = manifest.get(package_key)
        if not isinstance(package_meta, dict):
            continue
        for path_text in normalize_list(package_meta.get("evidence_paths")):
            if not str(path_text).strip().endswith(".json"):
                continue
            candidate = resolve_heartbeat_path(path_text)
            if not candidate.exists():
                continue
            try:
                payload = read_json(candidate)
            except Exception:
                continue
            if not isinstance(payload, dict):
                continue
            window_id = ""
            if isinstance(payload.get("legacy_window"), dict):
                window_id = str(payload["legacy_window"].get("window_id") or "")
            elif isinstance(payload.get("window"), dict):
                window_id = str(payload["window"].get("window_id") or "")
            if not window_id:
                continue
            action_meta = payload.get("recommended_control_tower_action")
            action_meta = action_meta if isinstance(action_meta, dict) else {}
            annotations[window_id] = {
                "accepted_cleanup_label": str(payload.get(label_key) or ""),
                "accepted_cleanup_reason": str(action_meta.get("why") or ""),
                "accepted_cleanup_source_path": str(candidate.resolve()),
                "accepted_cleanup_manifest_path": str(manifest_path.resolve()),
            }
            break
    return annotations


def annotate_window_expression(payload: dict[str, Any]) -> dict[str, Any]:
    annotation = load_window_cleanup_annotations().get(str(payload.get("window_id") or ""), {})
    if annotation:
        payload["display_state"] = str(annotation.get("accepted_cleanup_label") or payload.get("observed_state") or "")
        payload["accepted_cleanup_label"] = str(annotation.get("accepted_cleanup_label") or "")
        payload["accepted_cleanup_reason"] = str(annotation.get("accepted_cleanup_reason") or "")
        payload["accepted_cleanup_source_path"] = str(annotation.get("accepted_cleanup_source_path") or "")
        payload["accepted_cleanup_manifest_path"] = str(annotation.get("accepted_cleanup_manifest_path") or "")
    else:
        payload["display_state"] = str(payload.get("observed_state") or "")
        payload["accepted_cleanup_label"] = ""
        payload["accepted_cleanup_reason"] = ""
        payload["accepted_cleanup_source_path"] = ""
        payload["accepted_cleanup_manifest_path"] = ""
    return payload


def collect_window_evidence_state(evidence_paths: list[str]) -> list[dict[str, Any]]:
    rows: list[dict[str, Any]] = []
    for item in evidence_paths:
        path = resolve_heartbeat_path(item)
        exists = path.exists()
        trusted = exists
        try:
            path.relative_to(PROJECT_ROOT)
        except ValueError:
            trusted = False
        modified_at = ""
        if exists:
            modified_at = datetime.fromtimestamp(path.stat().st_mtime, tz=now_local().tzinfo).isoformat(timespec="seconds")
        rows.append(
            {
                "path": item,
                "resolved_path": str(path),
                "exists": exists,
                "trusted": trusted,
                "modified_at": modified_at,
            }
        )
    return rows


def window_heartbeat_signature(payload: dict[str, Any]) -> str:
    evidence = payload.get("latest_evidence_paths") if isinstance(payload.get("latest_evidence_paths"), list) else []
    signature_payload = {
        "current_phase": str(payload.get("current_phase") or ""),
        "last_action": str(payload.get("last_action") or ""),
        "current_status": str(payload.get("current_status") or ""),
        "latest_evidence_paths": evidence,
        "sole_blocker": str(payload.get("sole_blocker") or ""),
    }
    return stable_hash(json.dumps(signature_payload, ensure_ascii=False, sort_keys=True))


def classify_window_heartbeat(
    payload: dict[str, Any],
    *,
    generated_at: str,
    stall_minutes: int,
    silent_lost_minutes: int,
) -> dict[str, Any]:
    updated_at = str(payload.get("updated_at") or "")
    updated_dt = parse_datetime(updated_at)
    generated_dt = parse_datetime(generated_at)
    age_minutes = max(0.0, (generated_dt - updated_dt).total_seconds() / 60.0)
    previous = load_previous_window_heartbeat(str(payload.get("window_id") or ""), updated_at)
    previous_signature = window_heartbeat_signature(previous) if previous else ""
    current_signature = window_heartbeat_signature(payload)
    signature_changed = current_signature != previous_signature
    evidence_state = collect_window_evidence_state(normalize_list(payload.get("latest_evidence_paths")))
    trusted_evidence = [item for item in evidence_state if item.get("trusted")]
    status = str(payload.get("current_status") or "").strip().lower()
    sole_blocker = str(payload.get("sole_blocker") or "").strip()

    observed_state = "stuck"
    reason = "没有足够信号证明窗口仍在推进。"
    if age_minutes >= float(silent_lost_minutes):
        observed_state = "suspected_silent_lost"
        reason = f"heartbeat 已超过 {silent_lost_minutes} 分钟未更新。"
    elif status in WINDOW_HEARTBEAT_WAITING_STATUSES or (sole_blocker and status not in WINDOW_HEARTBEAT_BLOCKED_STATUSES):
        observed_state = "waiting_external"
        reason = "窗口明确声明正在等待外部条件或唯一 blocker。"
    elif status in WINDOW_HEARTBEAT_BLOCKED_STATUSES:
        observed_state = "stuck"
        reason = "窗口已自报 blocked/error/failed。"
    elif age_minutes > float(stall_minutes):
        observed_state = "stuck"
        reason = f"heartbeat 已超过 {stall_minutes} 分钟未更新。"
    elif status in WINDOW_HEARTBEAT_ACTIVE_STATUSES and (signature_changed or trusted_evidence):
        observed_state = "progressing"
        reason = "heartbeat 新鲜，且字段或本地证据存在推进信号。"
    elif status in WINDOW_HEARTBEAT_ACTIVE_STATUSES:
        observed_state = "progressing"
        reason = "heartbeat 新鲜，窗口仍声明处于推进态。"

    return annotate_window_expression(
        {
        "window_id": str(payload.get("window_id") or ""),
        "role": str(payload.get("role") or ""),
        "current_phase": str(payload.get("current_phase") or ""),
        "last_action": str(payload.get("last_action") or ""),
        "current_status": str(payload.get("current_status") or ""),
        "sole_blocker": sole_blocker,
        "updated_at": updated_at,
        "age_minutes": round(age_minutes, 1),
        "observed_state": observed_state,
        "reason": reason,
        "signature_changed": signature_changed,
        "trusted_evidence_count": len(trusted_evidence),
        "trusted_evidence": trusted_evidence,
        "evidence_state": evidence_state,
        "current_heartbeat_path": str(window_heartbeat_current_path(str(payload.get("window_id") or "")).resolve()),
        }
    )


def render_window_heartbeat_summary(summary: dict[str, Any]) -> str:
    lines = [
        "# Window Heartbeat Summary",
        "",
        f"- generated_at: `{summary.get('generated_at', '')}`",
        f"- stall_minutes: `{summary.get('stall_minutes', '')}`",
        f"- silent_lost_minutes: `{summary.get('silent_lost_minutes', '')}`",
        "",
        "## Windows",
        "",
    ]
    windows = summary.get("windows") if isinstance(summary.get("windows"), list) else []
    if not windows:
        lines.append("- no_window_heartbeats")
        return "\n".join(lines) + "\n"
    for item in windows:
        lines.append(
            f"- `{item.get('window_id', '')}` | role=`{item.get('role', '')}` | observed_state=`{item.get('observed_state', '')}` | "
            f"current_status=`{item.get('current_status', '')}` | updated_at=`{item.get('updated_at', '')}` | "
            f"trusted_evidence_count=`{item.get('trusted_evidence_count', 0)}` | reason={item.get('reason', '')}"
        )
    return "\n".join(lines) + "\n"


def window_heartbeat_has_human_boundary(item: dict[str, Any]) -> bool:
    blocker = str(item.get("sole_blocker") or "").strip()
    status = str(item.get("current_status") or "").strip().lower()
    observed_state = str(item.get("observed_state") or "").strip().lower()
    if status == "waiting_user":
        return True
    if not blocker:
        return False
    is_current_wait = status in WINDOW_HEARTBEAT_WAITING_STATUSES or observed_state == "waiting_external"
    is_current_blocked = status in WINDOW_HEARTBEAT_BLOCKED_STATUSES or observed_state == "stuck"
    if not (is_current_wait or is_current_blocked):
        return False
    blocker_text = blocker.lower()
    return any(keyword.lower() in blocker_text for keyword in WINDOW_HEARTBEAT_HUMAN_BOUNDARY_KEYWORDS)


def build_window_heartbeat_governance_decision(item: dict[str, Any]) -> dict[str, Any]:
    observed_state = str(item.get("observed_state") or "")
    role = str(item.get("role") or "")
    phase = str(item.get("current_phase") or "")
    last_action = str(item.get("last_action") or "")
    blocker = str(item.get("sole_blocker") or "")
    trusted_evidence_count = int(item.get("trusted_evidence_count") or 0)
    human_boundary = window_heartbeat_has_human_boundary(item)

    decision = "等待"
    auto_dispatch_allowed = False
    next_action = "保持观察。"
    suggested_prompt = ""
    reason = str(item.get("reason") or "")

    if observed_state == "progressing":
        decision = "继续"
        auto_dispatch_allowed = trusted_evidence_count > 0
        next_action = "继续当前子目标，并在下一轮真实推进或状态变化后刷新 heartbeat。"
        suggested_prompt = (
            "总控自动指令：\n\n"
            "继续当前子目标，不扩 scope。\n"
            f"- 当前阶段：`{phase}`\n"
            f"- 最近动作：`{last_action}`\n"
            "- 要求：下一轮只回真实已成立结果、仍待外部条件、唯一 blocker。"
        )
    elif observed_state == "waiting_external":
        if not human_boundary and not blocker:
            decision = "继续"
            auto_dispatch_allowed = True
            next_action = "外部等待信号已不明显，可恢复执行并刷新 heartbeat。"
            suggested_prompt = (
                "总控自动指令：\n\n"
                "你当前可恢复执行。\n"
                f"- 当前阶段：`{phase}`\n"
                f"- 最近动作：`{last_action}`\n"
                "- 只恢复当前子目标，不扩 scope；恢复后立即写新的 heartbeat。"
            )
        else:
            decision = "等待"
            auto_dispatch_allowed = False
            next_action = "继续等待外部条件；总控暂不自动越过当前边界。"
    elif observed_state == "stuck":
        if human_boundary:
            decision = "等待"
            auto_dispatch_allowed = False
            next_action = "当前 blocker 涉及人类边界；等待总控转交人类执行面。"
        else:
            decision = "裁决"
            auto_dispatch_allowed = True
            next_action = "总控可直接下发新的最小裁决 prompt。"
            suggested_prompt = (
                "总控裁决如下：\n\n"
                "1. 当前窗口记为 `stuck`\n"
                f"2. 当前阶段：`{phase}`\n"
                f"3. 最近动作：`{last_action}`\n"
                f"4. 唯一 blocker：`{blocker or '未明示，请围绕当前证据重新压缩成一个最小 blocker'}`\n"
                "5. 下一步只允许围绕这个最小 blocker 收口，不扩 scope。\n"
                "6. 输出继续只用：\n"
                "   1. 本轮做了什么\n"
                "   2. 哪些结果已真实成立\n"
                "   3. 哪些对象仍等待外部条件\n"
                "   4. 需要总控裁决的唯一问题"
            )
    elif observed_state == "suspected_silent_lost":
        decision = "收口"
        auto_dispatch_allowed = True
        next_action = "总控应先要求窗口回报当前状态或正式收口。"
        suggested_prompt = (
            "总控收口指令：\n\n"
            "你的 heartbeat 已疑似静默失联。\n"
            f"- 当前阶段：`{phase}`\n"
            f"- 最近动作：`{last_action}`\n"
            "请只回：\n"
            "1. 当前是否仍在推进\n"
            "2. 最近真实结果\n"
            "3. 唯一 blocker\n"
            "4. 若已完成或失效，请直接收口"
        )

    return {
        "window_id": str(item.get("window_id") or ""),
        "role": role,
        "observed_state": observed_state,
        "display_state": str(item.get("display_state") or observed_state),
        "decision": decision,
        "recommended_action": decision,
        "auto_dispatch_allowed": auto_dispatch_allowed,
        "human_boundary": human_boundary,
        "reason": reason,
        "next_action": next_action,
        "suggested_prompt": suggested_prompt,
        "trusted_evidence_count": trusted_evidence_count,
        "sole_blocker": blocker,
        "accepted_cleanup_label": str(item.get("accepted_cleanup_label") or ""),
        "accepted_cleanup_reason": str(item.get("accepted_cleanup_reason") or ""),
        "accepted_cleanup_source_path": str(item.get("accepted_cleanup_source_path") or ""),
        "accepted_cleanup_manifest_path": str(item.get("accepted_cleanup_manifest_path") or ""),
    }


def render_window_heartbeat_governance_summary(summary: dict[str, Any]) -> str:
    lines = [
        "# Window Heartbeat Governance Summary",
        "",
        f"- generated_at: `{summary.get('generated_at', '')}`",
        f"- window_count: `{summary.get('window_count', 0)}`",
        "",
        "## Decisions",
        "",
    ]
    decisions = summary.get("decisions") if isinstance(summary.get("decisions"), list) else []
    if not decisions:
        lines.append("- no_window_heartbeats")
        return "\n".join(lines) + "\n"
    for item in decisions:
        lines.append(
            f"- `{item.get('window_id', '')}` | role=`{item.get('role', '')}` | "
            f"observed_state=`{item.get('observed_state', '')}` | decision=`{item.get('decision', '')}` | "
            f"auto_dispatch_allowed=`{item.get('auto_dispatch_allowed', False)}` | "
            f"human_boundary=`{item.get('human_boundary', False)}` | reason={item.get('reason', '')}"
        )
    lines.extend(["", "## Auto-Dispatch Prompts", ""])
    prompts = [item for item in decisions if item.get("suggested_prompt")]
    if not prompts:
        lines.append("- no_auto_dispatch_prompts")
    else:
        for item in prompts:
            lines.append(f"### {item.get('window_id', '')}")
            lines.append("")
            lines.append(item.get("suggested_prompt", ""))
            lines.append("")
    return "\n".join(lines) + "\n"


def build_window_heartbeat_summary(
    *,
    generated_at: str,
    stall_minutes: int,
    silent_lost_minutes: int,
    window_id_filter: str = "",
) -> dict[str, Any]:
    rows = load_window_heartbeat_current_records()
    inspections: list[dict[str, Any]] = []
    for payload in rows:
        if window_id_filter and window_id_filter not in str(payload.get("window_id") or ""):
            continue
        inspections.append(
            classify_window_heartbeat(
                payload,
                generated_at=generated_at,
                stall_minutes=stall_minutes,
                silent_lost_minutes=silent_lost_minutes,
            )
        )
    counts = Counter(item.get("observed_state") for item in inspections)
    return {
        "generated_at": generated_at,
        "schema_version": "window-heartbeat-summary-v1",
        "stall_minutes": stall_minutes,
        "silent_lost_minutes": silent_lost_minutes,
        "window_count": len(inspections),
        "counts": dict(counts),
        "windows": inspections,
        "artifact_paths": {
            "summary_json": str((WINDOW_HEARTBEAT_CURRENT_ROOT / WINDOW_HEARTBEAT_SUMMARY_FILENAME).resolve()),
            "summary_markdown": str((WINDOW_HEARTBEAT_CURRENT_ROOT / WINDOW_HEARTBEAT_SUMMARY_MARKDOWN_FILENAME).resolve()),
        },
    }


def build_window_heartbeat_governance_summary(
    *,
    generated_at: str,
    stall_minutes: int,
    silent_lost_minutes: int,
    window_id_filter: str = "",
) -> dict[str, Any]:
    summary = build_window_heartbeat_summary(
        generated_at=generated_at,
        stall_minutes=stall_minutes,
        silent_lost_minutes=silent_lost_minutes,
        window_id_filter=window_id_filter,
    )
    decisions = [build_window_heartbeat_governance_decision(item) for item in summary.get("windows", [])]
    decision_counts = Counter(item.get("decision") for item in decisions)
    auto_dispatch_count = sum(1 for item in decisions if item.get("auto_dispatch_allowed"))
    decision_map = {
        str(item.get("window_id") or ""): item
        for item in decisions
        if isinstance(item, dict) and str(item.get("window_id") or "").strip()
    }
    windows_with_actions: list[dict[str, Any]] = []
    for item in summary.get("windows", []):
        if not isinstance(item, dict):
            continue
        row = dict(item)
        decision = decision_map.get(str(item.get("window_id") or ""), {})
        row["recommended_action"] = str(decision.get("recommended_action") or decision.get("decision") or "")
        row["governance_reason"] = str(decision.get("reason") or "")
        row["governance_next_action"] = str(decision.get("next_action") or "")
        windows_with_actions.append(row)
    return {
        **summary,
        "windows": windows_with_actions,
        "schema_version": "window-heartbeat-governance-v1",
        "decision_counts": dict(decision_counts),
        "auto_dispatch_count": auto_dispatch_count,
        "decisions": decisions,
        "artifact_paths": {
            **summary.get("artifact_paths", {}),
            "governance_json": str((WINDOW_HEARTBEAT_CURRENT_ROOT / WINDOW_HEARTBEAT_GOVERNANCE_FILENAME).resolve()),
            "governance_markdown": str((WINDOW_HEARTBEAT_CURRENT_ROOT / WINDOW_HEARTBEAT_GOVERNANCE_MARKDOWN_FILENAME).resolve()),
        },
    }


def command_window_heartbeat_write(args: argparse.Namespace) -> int:
    updated_at = iso_now()
    payload = build_window_heartbeat_payload(
        window_id=str(args.window_id or ""),
        role=str(args.role or ""),
        current_phase=str(args.current_phase or ""),
        last_action=str(args.last_action or ""),
        current_status=str(args.current_status or ""),
        latest_evidence_paths=normalize_list(args.evidence),
        sole_blocker=str(args.sole_blocker or ""),
        updated_at=updated_at,
    )
    paths = write_window_heartbeat(payload)
    print(f"window_id: {payload['window_id']}")
    print(f"role: {payload['role']}")
    print(f"current_status: {payload['current_status']}")
    print(f"updated_at: {payload['updated_at']}")
    print(f"current_path: {paths['current_path']}")
    print(f"round_path: {paths['round_path']}")
    return 0


def command_window_heartbeat_inspect(args: argparse.Namespace) -> int:
    generated_at = iso_now()
    stall_minutes = int(args.stall_minutes or WINDOW_HEARTBEAT_STALL_MINUTES)
    silent_lost_minutes = int(args.silent_lost_minutes or WINDOW_HEARTBEAT_SILENT_LOST_MINUTES)
    summary = build_window_heartbeat_summary(
        generated_at=generated_at,
        stall_minutes=stall_minutes,
        silent_lost_minutes=silent_lost_minutes,
        window_id_filter=str(args.window_id or "").strip(),
    )
    current_root = ensure_dir(WINDOW_HEARTBEAT_CURRENT_ROOT)
    write_json(current_root / WINDOW_HEARTBEAT_SUMMARY_FILENAME, summary)
    (current_root / WINDOW_HEARTBEAT_SUMMARY_MARKDOWN_FILENAME).write_text(
        render_window_heartbeat_summary(summary),
        encoding="utf-8",
    )
    print(f"window_count: {summary['window_count']}")
    print(f"progressing: {summary['counts'].get('progressing', 0)}")
    print(f"waiting_external: {summary['counts'].get('waiting_external', 0)}")
    print(f"stuck: {summary['counts'].get('stuck', 0)}")
    print(f"suspected_silent_lost: {summary['counts'].get('suspected_silent_lost', 0)}")
    for item in summary.get("windows", []):
        print(
            f"{item.get('window_id', '')}\t{item.get('observed_state', '')}\t{item.get('current_status', '')}\t"
            f"{item.get('age_minutes', 0)}m\t{item.get('trusted_evidence_count', 0)} evidence"
        )
    return 0


def command_window_heartbeat_govern(args: argparse.Namespace) -> int:
    generated_at = iso_now()
    stall_minutes = int(args.stall_minutes or WINDOW_HEARTBEAT_STALL_MINUTES)
    silent_lost_minutes = int(args.silent_lost_minutes or WINDOW_HEARTBEAT_SILENT_LOST_MINUTES)
    summary = build_window_heartbeat_governance_summary(
        generated_at=generated_at,
        stall_minutes=stall_minutes,
        silent_lost_minutes=silent_lost_minutes,
        window_id_filter=str(args.window_id or "").strip(),
    )
    current_root = ensure_dir(WINDOW_HEARTBEAT_CURRENT_ROOT)
    write_json(current_root / WINDOW_HEARTBEAT_GOVERNANCE_FILENAME, summary)
    (current_root / WINDOW_HEARTBEAT_GOVERNANCE_MARKDOWN_FILENAME).write_text(
        render_window_heartbeat_governance_summary(summary),
        encoding="utf-8",
    )
    print(f"window_count: {summary['window_count']}")
    print(f"continue: {summary['decision_counts'].get('继续', 0)}")
    print(f"wait: {summary['decision_counts'].get('等待', 0)}")
    print(f"rule: {summary['decision_counts'].get('裁决', 0)}")
    print(f"close: {summary['decision_counts'].get('收口', 0)}")
    print(f"auto_dispatch_count: {summary['auto_dispatch_count']}")
    for item in summary.get("decisions", []):
        print(
            f"{item.get('window_id', '')}\t{item.get('decision', '')}\t{item.get('observed_state', '')}\t"
            f"auto={item.get('auto_dispatch_allowed', False)}\thuman_boundary={item.get('human_boundary', False)}"
        )
    return 0


