def default_role_template_rows() -> list[dict[str, Any]]:
    return [dict(row) for row in DEFAULT_ROLE_TEMPLATE_ROWS]


def normalized_clone_portfolio(value: Any, *, missing_default: str = "client") -> str:
    text = str(value or "").strip().lower()
    if text in CLONE_PORTFOLIO_CHOICES:
        return text
    return missing_default if missing_default in CLONE_PORTFOLIO_CHOICES else "client"


def normalized_clone_mode(value: Any, *, missing_default: str = "client") -> str:
    text = str(value or "").strip().lower()
    if text in CLONE_MODE_CHOICES:
        return text
    return missing_default if missing_default in CLONE_MODE_CHOICES else "client"


def normalized_clone_actor_type(
    value: Any,
    *,
    clone_mode: str = "client",
    customer_id: str = "",
    org_id: str = "",
) -> str:
    text = str(value or "").strip().lower()
    if text in CLONE_ACTOR_TYPE_CHOICES:
        return text
    normalized_customer = normalize_slug_part(customer_id)
    normalized_org = normalize_slug_part(org_id)
    if clone_mode == "lab":
        return "satellite"
    if normalized_customer in {"self-fleet", DEFAULT_INTERNAL_ORG_ID} or normalized_org == DEFAULT_INTERNAL_ORG_ID:
        return "employee"
    return "client_operator"


def clone_portfolio_for_actor(
    actor_type: str,
    *,
    org_id: str = "",
    customer_id: str = "",
    clone_mode: str = "client",
) -> str:
    normalized_actor = normalized_clone_actor_type(
        actor_type,
        clone_mode=clone_mode,
        customer_id=customer_id,
        org_id=org_id,
    )
    if normalized_actor == "client_operator":
        return "client"
    if normalized_actor in {"founder", "employee", "satellite", "internal-operator"}:
        return "internal"
    if normalize_slug_part(org_id) == DEFAULT_INTERNAL_ORG_ID or normalize_slug_part(customer_id) == "self-fleet":
        return "internal"
    return "client"


def default_org_id_for_clone(
    *,
    clone_id: str,
    customer_id: str,
    clone_mode: str,
    actor_type: str,
) -> str:
    if clone_portfolio_for_actor(actor_type, customer_id=customer_id, clone_mode=clone_mode) == "internal":
        return DEFAULT_INTERNAL_ORG_ID
    return normalize_slug_part(customer_id) or normalize_slug_part(clone_id) or "org"


def default_tenant_id_for_clone(
    *,
    customer_id: str,
    clone_mode: str,
    actor_type: str,
) -> str:
    if clone_portfolio_for_actor(actor_type, customer_id=customer_id, clone_mode=clone_mode) == "internal":
        return "self-fleet-lab" if clone_mode == "lab" else DEFAULT_INTERNAL_TENANT_ID
    return normalize_slug_part(customer_id) or "tenant"


def normalized_clone_visibility_policy(
    value: Any,
    *,
    actor_type: str,
) -> str:
    text = str(value or "").strip().lower()
    if text in CLONE_VISIBILITY_POLICY_CHOICES:
        return text
    if actor_type == "client_operator":
        return "tenant_operated_summary"
    if actor_type == "founder":
        return "hq_cross_org_summary"
    return "hq_internal_full"


def normalized_clone_service_tier(
    value: Any,
    *,
    actor_type: str,
) -> str:
    text = str(value or "").strip().lower()
    if text in CLONE_SERVICE_TIER_CHOICES:
        return text
    if actor_type == "client_operator":
        return "operated_v1"
    if actor_type == "satellite":
        return "internal_support"
    if actor_type == "internal-operator":
        return "tier-1-internal"
    return "internal_core"


def effective_clone_portfolio(portfolio: str | None = None, *, include_lab: bool = False) -> str:
    normalized = normalized_clone_portfolio(portfolio, missing_default="client")
    if include_lab and normalized == "client":
        return "all"
    return normalized


def clone_portfolio_should_persist_locally(portfolio: str | None = None, *, include_lab: bool = False) -> bool:
    effective_portfolio = effective_clone_portfolio(portfolio, include_lab=include_lab)
    return effective_portfolio in {"client", "internal"} and not include_lab


def role_template_registry_rows() -> list[dict[str, Any]]:
    ensure_clone_factory_current_files()
    rows = load_optional_json_list(ROLE_TEMPLATE_REGISTRY_PATH)
    normalized: list[dict[str, Any]] = []
    if not rows:
        rows = default_role_template_rows()
    for row in rows:
        normalized.append(
            {
                "role_template_id": str(row.get("role_template_id") or "").strip(),
                "display_name": str(row.get("display_name") or "").strip(),
                "goal_model": str(row.get("goal_model") or "").strip(),
                "recommended_skill_chain": normalize_list(row.get("recommended_skill_chain")),
                "prohibited_boundaries": normalize_list(row.get("prohibited_boundaries")),
                "scorecard_metrics": normalize_list(row.get("scorecard_metrics")),
                "default_actor_type": normalized_clone_actor_type(row.get("default_actor_type"), clone_mode="client", customer_id="self-fleet", org_id=DEFAULT_INTERNAL_ORG_ID),
                "default_visibility_policy": normalized_clone_visibility_policy(
                    row.get("default_visibility_policy"),
                    actor_type=normalized_clone_actor_type(row.get("default_actor_type"), clone_mode="client", customer_id="self-fleet", org_id=DEFAULT_INTERNAL_ORG_ID),
                ),
                "default_service_tier": normalized_clone_service_tier(
                    row.get("default_service_tier"),
                    actor_type=normalized_clone_actor_type(row.get("default_actor_type"), clone_mode="client", customer_id="self-fleet", org_id=DEFAULT_INTERNAL_ORG_ID),
                ),
            }
        )
    normalized = [row for row in normalized if row["role_template_id"]]
    normalized.sort(key=lambda item: item["role_template_id"])
    if normalized != rows:
        write_json(ROLE_TEMPLATE_REGISTRY_PATH, normalized)
    return normalized


def role_template_by_id(role_template_id: str, rows: list[dict[str, Any]]) -> dict[str, Any]:
    normalized_id = str(role_template_id or "").strip()
    if not normalized_id:
        return {}
    for row in rows:
        if str(row.get("role_template_id") or "").strip() == normalized_id:
            return row
    raise ValueError(f"unknown role_template_id: {normalized_id}")


def normalize_clone_registry_rows(rows: list[dict[str, Any]]) -> tuple[list[dict[str, Any]], bool]:
    role_templates = {row["role_template_id"]: row for row in role_template_registry_rows()}
    normalized_rows: list[dict[str, Any]] = []
    changed = False
    for row in rows:
        normalized = dict(row)
        clone_mode = normalized_clone_mode(normalized.get("clone_mode"), missing_default="lab")
        template = role_templates.get(str(normalized.get("role_template_id") or "").strip(), {})
        actor_type = normalized_clone_actor_type(
            normalized.get("actor_type") or template.get("default_actor_type"),
            clone_mode=clone_mode,
            customer_id=str(normalized.get("customer_id") or ""),
            org_id=str(normalized.get("org_id") or ""),
        )
        org_id = str(normalized.get("org_id") or "").strip() or default_org_id_for_clone(
            clone_id=str(normalized.get("clone_id") or ""),
            customer_id=str(normalized.get("customer_id") or ""),
            clone_mode=clone_mode,
            actor_type=actor_type,
        )
        tenant_id = str(normalized.get("tenant_id") or "").strip() or default_tenant_id_for_clone(
            customer_id=str(normalized.get("customer_id") or ""),
            clone_mode=clone_mode,
            actor_type=actor_type,
        )
        visibility_policy = normalized_clone_visibility_policy(
            normalized.get("visibility_policy") or template.get("default_visibility_policy"),
            actor_type=actor_type,
        )
        service_tier = normalized_clone_service_tier(
            normalized.get("service_tier") or template.get("default_service_tier"),
            actor_type=actor_type,
        )
        portfolio = clone_portfolio_for_actor(
            actor_type,
            org_id=org_id,
            customer_id=str(normalized.get("customer_id") or ""),
            clone_mode=clone_mode,
        )
        merged = {
            **normalized,
            "clone_mode": clone_mode,
            "org_id": org_id,
            "tenant_id": tenant_id,
            "actor_type": actor_type,
            "role_template_id": str(normalized.get("role_template_id") or "").strip(),
            "visibility_policy": visibility_policy,
            "service_tier": service_tier,
            "manager_clone_id": str(normalized.get("manager_clone_id") or "").strip(),
            "portfolio_scope": portfolio,
        }
        if merged != row:
            changed = True
        normalized_rows.append(merged)
    normalized_rows.sort(key=lambda item: str(item.get("clone_id") or ""))
    return normalized_rows, changed


def clone_registry_scope(
    registry_rows: list[dict[str, Any]],
    *,
    include_lab: bool,
    portfolio: str = "client",
) -> list[dict[str, Any]]:
    effective_portfolio = effective_clone_portfolio(portfolio, include_lab=include_lab)
    if effective_portfolio == "all":
        return list(registry_rows)
    return [
        row
        for row in registry_rows
        if str(row.get("portfolio_scope") or clone_portfolio_for_actor(
            str(row.get("actor_type") or ""),
            org_id=str(row.get("org_id") or ""),
            customer_id=str(row.get("customer_id") or ""),
            clone_mode=normalized_clone_mode(row.get("clone_mode"), missing_default="lab"),
        ))
        == effective_portfolio
    ]


def satellite_registry_row(satellite_id: str, rows: list[dict[str, Any]]) -> dict[str, Any]:
    normalized_id = normalize_slug_part(satellite_id)
    for row in rows:
        if str(row.get("satellite_id") or "").strip() == normalized_id:
            return row
    raise ValueError(f"unknown satellite_id: {satellite_id}")


