def build_default_satellite_clone_row(spec: dict[str, Any], *, created_at: str) -> dict[str, Any]:
    clone_id = str(spec.get("clone_id") or "")
    return {
        "clone_id": clone_id,
        "customer_id": "self-fleet",
        "org_id": DEFAULT_INTERNAL_ORG_ID,
        "tenant_id": "self-fleet-lab",
        "display_name": str(spec.get("display_name") or clone_id),
        "status": "active",
        "clone_mode": "lab",
        "actor_type": "satellite",
        "role_template_id": "",
        "visibility_policy": "hq_internal_full",
        "service_tier": "internal_support",
        "manager_clone_id": "",
        "goal_model": str(spec.get("goal_model") or ""),
        "shared_core_version": current_shared_core_version(),
        "memory_namespace": f"clone/self-fleet/{clone_id}",
        "report_owner": "liming",
        "created_at": created_at,
        "updated_at": created_at,
    }


def register_default_satellite_fleet(*, selected_ids: list[str] | None = None, created_at: str | None = None) -> dict[str, Any]:
    ensure_clone_factory_current_files()
    ensure_satellite_registry_current_files()
    selected = {normalize_slug_part(item) for item in (selected_ids or []) if str(item).strip()}
    specs = [
        spec
        for spec in default_satellite_fleet_specs()
        if not selected or normalize_slug_part(str(spec.get("satellite_id") or "")) in selected
    ]
    if not specs:
        raise ValueError("no satellite matched the requested ids")
    timestamp = str(created_at or iso_now())
    clone_state = load_clone_factory_state()
    clone_rows = list(clone_state["registry"])
    satellite_rows = load_satellite_registry(persist=False)
    registered_satellite_ids: list[str] = []
    registered_clone_ids: list[str] = []
    for spec in specs:
        clone_row = build_default_satellite_clone_row(spec, created_at=timestamp)
        existing_clone = next((row for row in clone_rows if str(row.get("clone_id") or "") == clone_row["clone_id"]), {})
        if existing_clone:
            clone_row["created_at"] = str(existing_clone.get("created_at") or timestamp)
        clone_rows = upsert_rows_by_key(clone_rows, "clone_id", clone_row)
        satellite_rows = upsert_satellite_registry_row(satellite_rows, build_default_satellite_row(spec))
        registered_satellite_ids.append(str(spec.get("satellite_id") or ""))
        registered_clone_ids.append(str(spec.get("clone_id") or ""))
    write_json(CLONE_REGISTRY_PATH, clone_rows)
    write_json(SATELLITE_REGISTRY_PATH, normalize_satellite_registry_rows(satellite_rows)[0])
    refreshed_satellites = load_satellite_registry()
    refreshed_clones = refresh_clone_factory_state(report_date=parse_datetime(timestamp).strftime("%Y-%m-%d"))
    repo = resolve_github_ops_repo()
    bootstrap = bootstrap_hub_repo(repo)
    return {
        "registered_satellite_ids": registered_satellite_ids,
        "registered_clone_ids": registered_clone_ids,
        "satellite_registry_path": str(SATELLITE_REGISTRY_PATH.resolve()),
        "clone_registry_path": str(CLONE_REGISTRY_PATH.resolve()),
        "satellite_rows": refreshed_satellites,
        "clone_rows": refreshed_clones["registry"],
        "expected_sources": bootstrap.get("expected_sources", []),
        "hub_repo": repo,
    }


def resolve_satellite_assignment(requested_alias: str | None = None) -> dict[str, Any]:
    requested = str(requested_alias or "").strip()
    rows = load_satellite_registry()
    normalized_requested = normalize_satellite_alias(requested)
    default_row = next((row for row in rows if bool(row.get("default_when_unspecified"))), {})
    if not rows:
        return {
            "requested_alias": requested,
            "resolved_satellite_id": "",
            "resolved_clone_id": "",
            "resolved_source_id": "",
            "dispatch_mode": "",
            "is_default_fallback": False,
            "status": "registry_empty",
        }
    if not normalized_requested:
        target = default_row or {}
        return {
            "requested_alias": requested,
            "resolved_satellite_id": str(target.get("satellite_id") or ""),
            "resolved_clone_id": str(target.get("clone_id") or ""),
            "resolved_source_id": str(target.get("source_id") or ""),
            "dispatch_mode": str(target.get("dispatch_mode") or ""),
            "is_default_fallback": True,
            "status": str(target.get("status") or "registry_empty"),
        }
    for row in rows:
        alias_tokens = {
            normalize_satellite_alias(item)
            for item in normalize_list(row.get("aliases")) + [
                row.get("display_name", ""),
                row.get("satellite_id", ""),
                row.get("source_id", ""),
            ]
        }
        alias_tokens.discard("")
        if normalized_requested in alias_tokens:
            return {
                "requested_alias": requested,
                "resolved_satellite_id": str(row.get("satellite_id") or ""),
                "resolved_clone_id": str(row.get("clone_id") or ""),
                "resolved_source_id": str(row.get("source_id") or ""),
                "dispatch_mode": str(row.get("dispatch_mode") or ""),
                "is_default_fallback": False,
                "status": str(row.get("status") or ""),
            }
    return {
        "requested_alias": requested,
        "resolved_satellite_id": "",
        "resolved_clone_id": "",
        "resolved_source_id": "",
        "dispatch_mode": "",
        "is_default_fallback": False,
        "status": "unregistered_alias",
    }


def clone_review_sync_context() -> dict[str, str]:
    sync_result = load_optional_json(CLONE_SYNC_RESULT_PATH)
    return {
        "feishu_mirror_state": normalized_feishu_mirror_state(sync_result.get("status") or "local_only", details=sync_result),
        "github_mirror_state": "local_only",
        "feishu_sync_bundle_path": str(CLONE_FEISHU_SYNC_BUNDLE_PATH.resolve()) if CLONE_FEISHU_SYNC_BUNDLE_PATH.exists() else "",
        "sync_result_path": str(CLONE_SYNC_RESULT_PATH.resolve()) if CLONE_SYNC_RESULT_PATH.exists() else "",
    }


def enrich_clone_portfolio_report(report: dict[str, Any]) -> dict[str, Any]:
    enriched = dict(report)
    enriched.update(clone_review_sync_context())
    return enriched


def render_clone_portfolio_markdown(report: dict[str, Any]) -> str:
    report = enrich_clone_portfolio_report(report)
    lines = [
        "# Clone Portfolio Daily Report",
        "",
        f"- Generated At: {report.get('generated_at') or 'unknown'}",
        f"- Report Date: {report.get('report_date') or 'unknown'}",
        f"- Portfolio: {report.get('portfolio') or 'client'}",
        f"- Clone Count: {int(report.get('clone_count') or 0)}",
        f"- Total Registered Clones: {int(report.get('total_registered_clones') or 0)}",
        f"- Internal Clones: {int(report.get('internal_clone_count') or 0)}",
        f"- Client Clones: {int(report.get('client_clone_count') or 0)}",
        f"- Lab Clones Excluded: {int(report.get('lab_clone_count') or 0)}",
        f"- Include Lab: {bool(report.get('include_lab', False))}",
        f"- Feishu Mirror State: {report.get('feishu_mirror_state') or 'local_only'}",
        f"- GitHub Mirror State: {report.get('github_mirror_state') or 'local_only'}",
        "",
    ]
    sections = report.get("sections") if isinstance(report.get("sections"), dict) else {}
    for section in CLONE_PORTFOLIO_SECTIONS:
        lines.extend([f"## {section}", ""])
        items = sections.get(section) if isinstance(sections, dict) else []
        if isinstance(items, list) and items:
            for item in items:
                if isinstance(item, dict):
                    summary = str(item.get("summary") or json.dumps(item, ensure_ascii=False))
                else:
                    summary = str(item)
                lines.append(f"- {summary}")
        else:
            lines.append("- none")
        lines.append("")
    return "\n".join(lines)


def ensure_clone_factory_current_files() -> None:
    ensure_dir(CLONES_CURRENT_ROOT)
    defaults: list[tuple[Path, Any]] = [
        (CLONE_REGISTRY_PATH, []),
        (ROLE_TEMPLATE_REGISTRY_PATH, default_role_template_rows()),
        (CLONE_ORG_REGISTRY_PATH, []),
        (CLONE_TRAINING_STATE_PATH, []),
        (CLONE_SCORECARD_PATH, []),
        (CLONE_SCORECARD_AGGREGATE_PATH, []),
        (CLONE_AUTONOMY_TIER_PATH, []),
        (CLONE_PROMOTION_QUEUE_PATH, []),
        (CLONE_BUDGET_ALLOCATION_PATH, []),
        (CLONE_TASK_RUNS_PATH, []),
        (CLONE_TRAINING_CYCLES_PATH, []),
        (CLONE_CAPABILITY_PROPOSALS_PATH, []),
        (CLONE_ALERTS_DECISIONS_PATH, []),
        (CLONE_PORTFOLIO_REPORT_PATH, empty_clone_portfolio_report()),
    ]
    for path, payload in defaults:
        if not path.exists():
            write_json(path, payload)
    if not CLONE_PORTFOLIO_REPORT_MD_PATH.exists():
        CLONE_PORTFOLIO_REPORT_MD_PATH.write_text(
            render_clone_portfolio_markdown(empty_clone_portfolio_report()),
            encoding="utf-8",
        )


def load_clone_factory_state() -> dict[str, Any]:
    ensure_clone_factory_current_files()
    registry_rows, registry_changed = normalize_clone_registry_rows(load_optional_json_list(CLONE_REGISTRY_PATH))
    if registry_changed:
        write_json(CLONE_REGISTRY_PATH, registry_rows)
    portfolio = enrich_clone_portfolio_report(load_optional_json(CLONE_PORTFOLIO_REPORT_PATH))
    if not portfolio:
        portfolio = empty_clone_portfolio_report()
    return {
        "registry": registry_rows,
        "role_templates": role_template_registry_rows(),
        "org_registry": load_optional_json_list(CLONE_ORG_REGISTRY_PATH),
        "training_state": load_optional_json_list(CLONE_TRAINING_STATE_PATH),
        "scorecard": load_optional_json_list(CLONE_SCORECARD_PATH),
        "autonomy_tier": load_optional_json_list(CLONE_AUTONOMY_TIER_PATH),
        "promotion_queue": load_optional_json_list(CLONE_PROMOTION_QUEUE_PATH),
        "budget_allocation": load_optional_json_list(CLONE_BUDGET_ALLOCATION_PATH),
        "task_runs": load_optional_json_list(CLONE_TASK_RUNS_PATH),
        "training_cycles": load_optional_json_list(CLONE_TRAINING_CYCLES_PATH),
        "capability_proposals": load_optional_json_list(CLONE_CAPABILITY_PROPOSALS_PATH),
        "alerts_decisions": load_optional_json_list(CLONE_ALERTS_DECISIONS_PATH),
        "portfolio_report": portfolio,
    }


def current_shared_core_version() -> str:
    completed = subprocess.run(
        ["git", "-C", str(SKILL_DIR), "rev-parse", "--short", "HEAD"],
        capture_output=True,
        text=True,
        check=False,
    )
    if completed.returncode == 0 and completed.stdout.strip():
        return completed.stdout.strip()
    return "local-unversioned"


def next_clone_cycle_label(reference: str | None = None) -> str:
    dt = parse_datetime(reference or iso_now())
    next_dt = (dt + timedelta(days=1)).replace(hour=9, minute=0, second=0, microsecond=0)
    return next_dt.isoformat(timespec="seconds")


def upsert_rows_by_key(rows: list[dict[str, Any]], key_field: str, new_row: dict[str, Any]) -> list[dict[str, Any]]:
    key = str(new_row.get(key_field) or "").strip()
    merged: list[dict[str, Any]] = []
    found = False
    for row in rows:
        if str(row.get(key_field) or "").strip() == key:
            merged.append(new_row)
            found = True
        else:
            merged.append(row)
    if not found:
        merged.append(new_row)
    return sorted(
        merged,
        key=lambda item: (
            str(item.get(key_field) or ""),
            str(item.get("updated_at") or item.get("created_at") or ""),
        ),
    )


def is_clone_training_record(record: dict[str, Any]) -> bool:
    run_kind = str(record.get("run_kind") or "").strip()
    clone_id = str(record.get("clone_id") or "").strip()
    return run_kind == "clone_training" or bool(clone_id)


def iter_clone_training_records(limit: int = 5000, clone_id: str | None = None) -> list[dict[str, Any]]:
    rows: list[dict[str, Any]] = []
    for record in iter_evolution_records(limit=limit):
        if not is_clone_training_record(record):
            continue
        current_clone_id = str(record.get("clone_id") or "").strip()
        if clone_id and current_clone_id != clone_id:
            continue
        rows.append(record)
    return rows


def clone_grouped_records(records: list[dict[str, Any]]) -> dict[str, list[dict[str, Any]]]:
    grouped: dict[str, list[dict[str, Any]]] = {}
    for record in records:
        clone_id = str(record.get("clone_id") or "").strip()
        if not clone_id:
            continue
        grouped.setdefault(clone_id, []).append(record)
    for clone_id, items in grouped.items():
        items.sort(key=lambda item: str(item.get("created_at") or ""), reverse=True)
        grouped[clone_id] = items
    return grouped


def clone_human_interruption_cost(human_boundary: str) -> float:
    text = normalize_prompt(human_boundary)
    if not text or "default to high autonomy" in text:
        return 0.15
    if any(keyword in text for keyword in ["login", "登录", "授权", "payment", "支付", "审批", "approval", "发布", "删除"]):
        return 0.9
    return 0.35


def clone_run_metrics(record: dict[str, Any]) -> dict[str, float]:
    verification = normalize_verification_result(record.get("verification_result"))
    status = normalized_verification_status(str(verification.get("status") or ""))
    evidence = normalize_list(verification.get("evidence"))
    open_questions = normalize_list(verification.get("open_questions"))
    selected_skills = normalize_list(record.get("skills_selected"))
    max_distortion = normalize_prompt(str(record.get("max_distortion") or ""))
    score_before = safe_float(record.get("score_before"), 0.0)
    score_after = safe_float(record.get("score_after"), score_before)
    task_success_rate = 1.0 if status == "completed" else 0.0
    status_strength = {"completed": 1.0, "partial": 0.6, "failed": 0.0, "unverified": 0.25}.get(status, 0.25)
    closure_quality = max(0.0, status_strength - min(0.6, len(open_questions) * 0.15))
    verification_strength = min(1.0, len(evidence) / 3.0)
    reuse_contribution = min(1.0, len(selected_skills) / 3.0)
    distortion_rate = min(1.0, len(open_questions) * 0.3 + (0.2 if max_distortion and max_distortion not in {"none", "无", "n/a"} else 0.0))
    goal_alignment = 1.0 if str(record.get("target_capability") or "").strip() and str(record.get("goal_model") or "").strip() else 0.7
    human_cost = clone_human_interruption_cost(str(record.get("human_boundary") or ""))
    budget_efficiency = min(1.0, max(0.0, (score_after - score_before + 25.0) / 50.0))
    return {
        "task_success_rate": round(task_success_rate, 4),
        "closure_quality": round(closure_quality, 4),
        "verification_strength": round(verification_strength, 4),
        "reuse_contribution": round(reuse_contribution, 4),
        "distortion_rate": round(distortion_rate, 4),
        "human_interruption_cost": round(human_cost, 4),
        "goal_alignment": round(goal_alignment, 4),
        "budget_efficiency": round(budget_efficiency, 4),
    }


def clone_round_score_from_metrics(metrics: dict[str, float]) -> float:
    return round(
        metrics["task_success_rate"] * 22
        + metrics["closure_quality"] * 18
        + metrics["verification_strength"] * 16
        + metrics["reuse_contribution"] * 10
        + metrics["goal_alignment"] * 12
        + metrics["budget_efficiency"] * 10
        + (1.0 - metrics["distortion_rate"]) * 8
        + (1.0 - metrics["human_interruption_cost"]) * 4,
        2,
    )


def clone_routing_priority(scorecard: dict[str, Any]) -> float:
    return round(
        safe_float(scorecard.get("task_success_rate")) * 22
        + safe_float(scorecard.get("closure_quality")) * 18
        + safe_float(scorecard.get("verification_strength")) * 16
        + safe_float(scorecard.get("reuse_contribution")) * 10
        + safe_float(scorecard.get("goal_alignment")) * 12
        + safe_float(scorecard.get("budget_efficiency")) * 10
        + (1.0 - safe_float(scorecard.get("distortion_rate"))) * 8
        + (1.0 - safe_float(scorecard.get("human_interruption_cost"))) * 4,
        2,
    )


def clone_autonomy_cap(routing_priority: float, distortion_rate: float) -> str:
    if distortion_rate >= 0.55:
        return "suggest" if routing_priority >= 35 else "observe"
    if routing_priority >= 75 and distortion_rate <= 0.25:
        return "guarded-autonomy"
    if routing_priority >= 55 and distortion_rate <= 0.4:
        return "trusted-suggest"
    if routing_priority >= 35:
        return "suggest"
    return "observe"


def clone_has_hard_boundary_open_questions(record: dict[str, Any]) -> bool:
    verification = normalize_verification_result(record.get("verification_result"))
    for item in normalize_list(verification.get("open_questions")):
        text = normalize_prompt(item)
        if any(
            keyword in text
            for keyword in [
                "approval",
                "approve",
                "审批",
                "authorize",
                "authorization",
                "授权",
                "login",
                "登录",
                "permission",
                "权限",
                "auth",
                "token",
                "payment",
                "支付",
                "publish",
                "发布",
                "delete",
                "删除",
                "human boundary",
                "人类边界",
                "客户确认",
            ]
        ):
            return True
    return False


def clone_promotion_recommendation(scorecard: dict[str, Any], *, latest_record: dict[str, Any] | None = None) -> str:
    routing_priority = safe_float(scorecard.get("routing_priority"))
    distortion_rate = safe_float(scorecard.get("distortion_rate"))
    success_rate = safe_float(scorecard.get("task_success_rate"))
    verification_strength = safe_float(scorecard.get("verification_strength"))
    training_runs = int(safe_float(scorecard.get("training_runs"), 0.0))
    clone_mode = normalized_clone_mode(scorecard.get("clone_mode"), missing_default="client")
    latest_record = latest_record or {}
    latest_status = normalized_verification_status(
        str(normalize_verification_result(latest_record.get("verification_result")).get("status") or "")
    )
    hard_boundary_open_questions = clone_has_hard_boundary_open_questions(latest_record)
    if distortion_rate >= 0.65 or (latest_status == "failed" and training_runs >= 2):
        return "hibernate"
    if distortion_rate >= 0.55:
        return "watch" if routing_priority >= 35 else "hibernate"
    if clone_mode != "client":
        return "watch" if training_runs else "hold"
    if (
        training_runs >= 3
        and success_rate >= 0.8
        and verification_strength >= 0.6
        and distortion_rate <= 0.25
        and not hard_boundary_open_questions
        and latest_status == "completed"
    ):
        return "promote"
    if routing_priority >= 55:
        return "hold"
    if routing_priority >= 30 or hard_boundary_open_questions or latest_status in {"partial", "unverified"}:
        return "watch"
    return "hibernate"


def clone_budget_allocations(scorecards: list[dict[str, Any]]) -> list[dict[str, Any]]:
    active_rows = [row for row in scorecards if str(row.get("promotion_recommendation") or "") != "hibernate"]
    active_scores = [max(0.0, safe_float(row.get("routing_priority"))) for row in active_rows]
    total = sum(active_scores)
    fallback_weight = round(1.0 / max(1, len(active_rows)), 4) if active_rows else 0.0
    rows: list[dict[str, Any]] = []
    for row in scorecards:
        routing_priority = max(0.0, safe_float(row.get("routing_priority")))
        if str(row.get("promotion_recommendation") or "") == "hibernate":
            budget_weight = 0.0
            rationale = "High distortion or low routing priority; keep budget at observation level."
        elif total > 0:
            budget_weight = round(routing_priority / total, 4)
            rationale = "Budget share follows clone routing priority and verification quality."
        else:
            budget_weight = fallback_weight
            rationale = "No proven priority gap yet; keep equal-weight provisional allocation."
        rows.append(
            {
                "clone_id": row["clone_id"],
                "display_name": row["display_name"],
                "customer_id": row["customer_id"],
                "org_id": str(row.get("org_id") or ""),
                "tenant_id": str(row.get("tenant_id") or ""),
                "portfolio_scope": str(row.get("portfolio_scope") or ""),
                "clone_mode": row.get("clone_mode", "client"),
                "budget_weight": budget_weight,
                "routing_priority": routing_priority,
                "promotion_recommendation": row["promotion_recommendation"],
                "autonomy_cap": row["autonomy_cap"],
                "rationale": rationale,
                "updated_at": iso_now(),
            }
        )
    rows.sort(key=lambda item: (safe_float(item.get("budget_weight")), safe_float(item.get("routing_priority"))), reverse=True)
    return rows


def clone_open_question_summary(record: dict[str, Any]) -> str:
    questions = normalize_list(normalize_verification_result(record.get("verification_result")).get("open_questions"))
    return " | ".join(questions[:2])


def clone_task_run_evidence_path(record: dict[str, Any]) -> str:
    run_id = str(record.get("run_id") or "")
    created_at = str(record.get("created_at") or iso_now())
    if not run_id:
        return ""
    return str((run_dir_for(run_id, created_at) / "evolution.json").resolve())


def build_clone_org_rows(registry_rows: list[dict[str, Any]]) -> list[dict[str, Any]]:
    grouped: dict[str, dict[str, Any]] = {}
    for row in registry_rows:
        org_id = str(row.get("org_id") or "").strip()
        tenant_id = str(row.get("tenant_id") or "").strip()
        if not org_id or not tenant_id:
            continue
        key = f"{org_id}::{tenant_id}"
        entry = grouped.setdefault(
            key,
            {
                "org_key": key,
                "org_id": org_id,
                "tenant_id": tenant_id,
                "portfolio_scope": str(row.get("portfolio_scope") or "client"),
                "clone_ids": [],
                "clone_count": 0,
                "active_clone_count": 0,
                "actor_types": set(),
                "service_tiers": set(),
                "visibility_policies": set(),
                "report_owners": set(),
                "updated_at": str(row.get("updated_at") or row.get("created_at") or iso_now()),
            },
        )
        clone_id = str(row.get("clone_id") or "")
        if clone_id:
            entry["clone_ids"].append(clone_id)
        entry["clone_count"] += 1
        if str(row.get("status") or "active") == "active":
            entry["active_clone_count"] += 1
        entry["actor_types"].add(str(row.get("actor_type") or ""))
        entry["service_tiers"].add(str(row.get("service_tier") or ""))
        entry["visibility_policies"].add(str(row.get("visibility_policy") or ""))
        if str(row.get("report_owner") or "").strip():
            entry["report_owners"].add(str(row.get("report_owner") or "").strip())
        entry["updated_at"] = max(entry["updated_at"], str(row.get("updated_at") or row.get("created_at") or iso_now()))
    rows: list[dict[str, Any]] = []
    for entry in grouped.values():
        rows.append(
            {
                "org_key": entry["org_key"],
                "org_id": entry["org_id"],
                "tenant_id": entry["tenant_id"],
                "portfolio_scope": entry["portfolio_scope"],
                "clone_count": entry["clone_count"],
                "active_clone_count": entry["active_clone_count"],
                "actor_types": sorted(item for item in entry["actor_types"] if item),
                "service_tiers": sorted(item for item in entry["service_tiers"] if item),
                "visibility_policies": sorted(item for item in entry["visibility_policies"] if item),
                "report_owners": sorted(item for item in entry["report_owners"] if item),
                "clone_ids": sorted(item for item in entry["clone_ids"] if item),
                "updated_at": entry["updated_at"],
            }
        )
    rows.sort(key=lambda item: item["org_key"])
    return rows


def build_clone_task_run_rows(
    records: list[dict[str, Any]],
    registry_rows: list[dict[str, Any]],
) -> list[dict[str, Any]]:
    registry_map = {str(row.get("clone_id") or ""): row for row in registry_rows}
    rows: list[dict[str, Any]] = []
    for record in records:
        clone_id = str(record.get("clone_id") or "").strip()
        if not clone_id:
            continue
        registry = registry_map.get(clone_id, {})
        if not registry:
            continue
        verification = normalize_verification_result(record.get("verification_result"))
        rows.append(
            {
                "task_run_key": str(record.get("run_id") or ""),
                "run_id": str(record.get("run_id") or ""),
                "clone_id": clone_id,
                "display_name": str(registry.get("display_name") or clone_id),
                "org_id": str(registry.get("org_id") or ""),
                "tenant_id": str(registry.get("tenant_id") or ""),
                "actor_type": str(registry.get("actor_type") or ""),
                "role_template_id": str(registry.get("role_template_id") or ""),
                "portfolio_scope": str(registry.get("portfolio_scope") or ""),
                "customer_id": str(registry.get("customer_id") or ""),
                "training_cycle_id": str(record.get("training_cycle_id") or ""),
                "target_capability": str(record.get("target_capability") or ""),
                "verification_status": normalized_verification_status(str(verification.get("status") or "")),
                "promotion_recommendation": normalized_promotion_recommendation(record.get("promotion_recommendation")),
                "budget_weight": round(safe_float(record.get("budget_weight"), 0.0), 4),
                "max_distortion": str(record.get("max_distortion") or ""),
                "open_questions": clone_open_question_summary(record),
                "evidence_ref": clone_task_run_evidence_path(record),
                "updated_at": str(record.get("created_at") or iso_now()),
            }
        )
    rows.sort(key=lambda item: (item["updated_at"], item["task_run_key"]), reverse=True)
    return rows


def build_clone_training_cycle_rows(
    records: list[dict[str, Any]],
    registry_rows: list[dict[str, Any]],
) -> list[dict[str, Any]]:
    registry_map = {str(row.get("clone_id") or ""): row for row in registry_rows}
    grouped: dict[str, list[dict[str, Any]]] = {}
    for record in records:
        clone_id = str(record.get("clone_id") or "").strip()
        cycle_id = str(record.get("training_cycle_id") or "").strip()
        if not clone_id or not cycle_id:
            continue
        if clone_id not in registry_map:
            continue
        grouped.setdefault(f"{clone_id}::{cycle_id}", []).append(record)
    rows: list[dict[str, Any]] = []
    for key, items in grouped.items():
        items.sort(key=lambda item: str(item.get("created_at") or ""), reverse=True)
        latest = items[0]
        oldest = items[-1]
        clone_id = str(latest.get("clone_id") or "")
        registry = registry_map.get(clone_id, {})
        rows.append(
            {
                "training_cycle_key": key,
                "training_cycle_id": str(latest.get("training_cycle_id") or ""),
                "clone_id": clone_id,
                "display_name": str(registry.get("display_name") or clone_id),
                "org_id": str(registry.get("org_id") or ""),
                "tenant_id": str(registry.get("tenant_id") or ""),
                "role_template_id": str(registry.get("role_template_id") or ""),
                "portfolio_scope": str(registry.get("portfolio_scope") or ""),
                "target_capability": str(latest.get("target_capability") or ""),
                "run_count": len(items),
                "score_before": round(safe_float(oldest.get("score_before"), 0.0), 2),
                "score_after": round(safe_float(latest.get("score_after"), 0.0), 2),
                "score_delta": round(safe_float(latest.get("score_after"), 0.0) - safe_float(oldest.get("score_before"), 0.0), 2),
                "verification_status": normalized_verification_status(
                    str(normalize_verification_result(latest.get("verification_result")).get("status") or "")
                ),
                "promotion_recommendation": normalized_promotion_recommendation(latest.get("promotion_recommendation")),
                "last_run_id": str(latest.get("run_id") or ""),
                "open_risks": clone_open_question_summary(latest),
                "updated_at": str(latest.get("created_at") or iso_now()),
            }
        )
    rows.sort(key=lambda item: (item["updated_at"], item["training_cycle_key"]), reverse=True)
    return rows


def capability_proposal_recommendation(record: dict[str, Any], support_count: int) -> str:
    verification = normalized_verification_status(str(normalize_verification_result(record.get("verification_result")).get("status") or ""))
    score_after = safe_float(record.get("score_after"), 0.0)
    if support_count >= 2 and verification == "completed" and score_after >= 55:
        return "promote_shared_core"
    if verification in {"partial", "unverified"}:
        return "keep_tenant_local"
    return "pending_hq_review"


def build_clone_capability_proposals(
    records: list[dict[str, Any]],
    registry_rows: list[dict[str, Any]],
) -> list[dict[str, Any]]:
    registry_map = {str(row.get("clone_id") or ""): row for row in registry_rows}
    grouped: dict[str, dict[str, Any]] = {}
    for record in records:
        clone_id = str(record.get("clone_id") or "").strip()
        if not clone_id:
            continue
        if clone_id not in registry_map:
            continue
        candidates = normalize_list(record.get("evolution_candidates"))
        for candidate in candidates:
            slug = normalize_slug_part(candidate)[:80] or "candidate"
            key = f"{clone_id}::{slug}"
            bucket = grouped.setdefault(
                key,
                {
                    "clone_id": clone_id,
                    "proposal_title": candidate,
                    "records": [],
                },
            )
            bucket["records"].append(record)
    rows: list[dict[str, Any]] = []
    for key, bucket in grouped.items():
        items = sorted(bucket["records"], key=lambda item: str(item.get("created_at") or ""), reverse=True)
        latest = items[0]
        clone_id = bucket["clone_id"]
        registry = registry_map.get(clone_id, {})
        support_count = len(items)
        suggested_decision = capability_proposal_recommendation(latest, support_count)
        proposal_title = str(bucket["proposal_title"] or "")
        rows.append(
            {
                "proposal_id": f"capability::{key}",
                "clone_id": clone_id,
                "display_name": str(registry.get("display_name") or clone_id),
                "org_id": str(registry.get("org_id") or ""),
                "tenant_id": str(registry.get("tenant_id") or ""),
                "role_template_id": str(registry.get("role_template_id") or ""),
                "portfolio_scope": str(registry.get("portfolio_scope") or ""),
                "proposal_title": proposal_title,
                "proposal_scope": "shared_core_candidate" if suggested_decision == "promote_shared_core" else "tenant_local_candidate",
                "suggested_decision": suggested_decision,
                "hq_review_status": "pending_hq_review",
                "support_count": support_count,
                "source_run_id": str(latest.get("run_id") or ""),
                "evidence_ref": clone_task_run_evidence_path(latest),
                "updated_at": str(latest.get("created_at") or iso_now()),
            }
        )
    rows.sort(key=lambda item: (item["updated_at"], item["proposal_id"]), reverse=True)
    return rows


def build_clone_alerts_decisions(
    scorecards: list[dict[str, Any]],
    state_rows: list[dict[str, Any]],
    promotion_queue: list[dict[str, Any]],
) -> list[dict[str, Any]]:
    state_map = {str(row.get("clone_id") or ""): row for row in state_rows}
    rows: list[dict[str, Any]] = []
    for row in promotion_queue:
        clone_id = str(row.get("clone_id") or "")
        rows.append(
            {
                "alert_key": f"promotion::{clone_id}",
                "clone_id": clone_id,
                "display_name": str(row.get("display_name") or clone_id),
                "org_id": str(row.get("org_id") or ""),
                "tenant_id": str(row.get("tenant_id") or ""),
                "portfolio_scope": str(row.get("portfolio_scope") or ""),
                "alert_type": "promotion_queue",
                "severity": "high" if str(row.get("promotion_recommendation") or "") in {"promote", "hibernate"} else "medium",
                "title": str(row.get("reason") or ""),
                "recommended_action": str(row.get("recommended_action") or row.get("promotion_recommendation") or ""),
                "approval_required": bool(row.get("approval_required", True)),
                "status": str(row.get("status") or "pending_approval"),
                "evidence_ref": str(row.get("source_path") or ""),
                "updated_at": str(row.get("updated_at") or iso_now()),
            }
        )
    for row in scorecards:
        risks = normalize_list(state_map.get(str(row.get("clone_id") or ""), {}).get("open_risks"))
        if not risks:
            continue
        rows.append(
            {
                "alert_key": f"risk::{row['clone_id']}",
                "clone_id": row["clone_id"],
                "display_name": row["display_name"],
                "org_id": str(row.get("org_id") or ""),
                "tenant_id": str(row.get("tenant_id") or ""),
                "portfolio_scope": str(row.get("portfolio_scope") or ""),
                "alert_type": "risk_open_question",
                "severity": "high" if safe_float(row.get("distortion_rate"), 0.0) >= 0.55 else "medium",
                "title": " | ".join(risks[:2]),
                "recommended_action": (
                    "需要总部复核并先清风险"
                    if safe_float(row.get("distortion_rate"), 0.0) >= 0.55
                    else "继续一轮受控训练并跟踪边界问题"
                ),
                "approval_required": bool(row.get("hard_boundary_open_questions")),
                "status": "open",
                "evidence_ref": str(row.get("last_run_id") or ""),
                "updated_at": str(row.get("updated_at") or iso_now()),
            }
        )
    rows.sort(key=lambda item: (item["updated_at"], item["alert_key"]), reverse=True)
    return rows


def build_clone_scorecards(
    registry_rows: list[dict[str, Any]],
    state_rows: list[dict[str, Any]],
    records: list[dict[str, Any]],
    *,
    include_lab: bool = False,
    portfolio: str = "client",
) -> list[dict[str, Any]]:
    grouped = clone_grouped_records(records)
    state_map = {str(row.get("clone_id") or "").strip(): row for row in state_rows}
    rows: list[dict[str, Any]] = []
    effective_portfolio = effective_clone_portfolio(portfolio, include_lab=include_lab)
    for registry in registry_rows:
        clone_id = str(registry.get("clone_id") or "").strip()
        if not clone_id:
            continue
        clone_mode = normalized_clone_mode(registry.get("clone_mode"), missing_default="lab")
        portfolio_scope = str(registry.get("portfolio_scope") or clone_portfolio_for_actor(
            str(registry.get("actor_type") or ""),
            org_id=str(registry.get("org_id") or ""),
            customer_id=str(registry.get("customer_id") or ""),
            clone_mode=clone_mode,
        ))
        if effective_portfolio != "all" and portfolio_scope != effective_portfolio:
            continue
        clone_records = grouped.get(clone_id, [])
        metrics = [clone_run_metrics(record) for record in clone_records]
        latest = clone_records[0] if clone_records else {}
        row = {
            "clone_id": clone_id,
            "customer_id": str(registry.get("customer_id") or ""),
            "org_id": str(registry.get("org_id") or ""),
            "tenant_id": str(registry.get("tenant_id") or ""),
            "display_name": str(registry.get("display_name") or clone_id),
            "status": str(registry.get("status") or "active"),
            "clone_mode": clone_mode,
            "actor_type": str(registry.get("actor_type") or ""),
            "role_template_id": str(registry.get("role_template_id") or ""),
            "visibility_policy": str(registry.get("visibility_policy") or ""),
            "service_tier": str(registry.get("service_tier") or ""),
            "manager_clone_id": str(registry.get("manager_clone_id") or ""),
            "portfolio_scope": portfolio_scope,
            "goal_model": str(registry.get("goal_model") or ""),
            "task_success_rate": round(average([item["task_success_rate"] for item in metrics]), 4),
            "closure_quality": round(average([item["closure_quality"] for item in metrics]), 4),
            "verification_strength": round(average([item["verification_strength"] for item in metrics]), 4),
            "reuse_contribution": round(average([item["reuse_contribution"] for item in metrics]), 4),
            "distortion_rate": round(average([item["distortion_rate"] for item in metrics]), 4),
            "human_interruption_cost": round(average([item["human_interruption_cost"] for item in metrics]), 4),
            "goal_alignment": round(average([item["goal_alignment"] for item in metrics]) or (1.0 if registry.get("goal_model") else 0.0), 4),
            "budget_efficiency": round(average([item["budget_efficiency"] for item in metrics]), 4),
            "training_runs": len(clone_records),
            "last_run_id": str(latest.get("run_id") or state_map.get(clone_id, {}).get("last_run_id") or ""),
            "last_created_at": str(latest.get("created_at") or registry.get("created_at") or ""),
            "routing_priority": 0.0,
            "autonomy_cap": "observe",
            "budget_weight": 0.0,
            "hard_boundary_open_questions": clone_has_hard_boundary_open_questions(latest),
            "latest_verification_status": normalized_verification_status(
                str(normalize_verification_result(latest.get("verification_result")).get("status") or "")
            )
            if latest
            else "unverified",
            "promotion_recommendation": "watch" if clone_records else "hold",
            "updated_at": iso_now(),
        }
        row["routing_priority"] = clone_routing_priority(row)
        row["autonomy_cap"] = clone_autonomy_cap(row["routing_priority"], row["distortion_rate"])
        row["promotion_recommendation"] = clone_promotion_recommendation(row, latest_record=latest)
        rows.append(row)
    budget_rows = clone_budget_allocations(rows)
    budget_map = {str(item.get("clone_id") or ""): safe_float(item.get("budget_weight")) for item in budget_rows}
    for row in rows:
        row["budget_weight"] = budget_map.get(row["clone_id"], 0.0)
    rows.sort(key=lambda item: (safe_float(item.get("routing_priority")), safe_float(item.get("task_success_rate"))), reverse=True)
    return rows


def build_clone_training_states(
    registry_rows: list[dict[str, Any]],
    existing_rows: list[dict[str, Any]],
    records: list[dict[str, Any]],
    scorecards: list[dict[str, Any]],
) -> list[dict[str, Any]]:
    grouped = clone_grouped_records(records)
    existing_map = {str(row.get("clone_id") or "").strip(): row for row in existing_rows}
    scorecard_map = {str(row.get("clone_id") or "").strip(): row for row in scorecards}
    rows: list[dict[str, Any]] = []
    for registry in registry_rows:
        clone_id = str(registry.get("clone_id") or "").strip()
        if not clone_id:
            continue
        existing = existing_map.get(clone_id, {})
        latest = grouped.get(clone_id, [{}])[0] if grouped.get(clone_id) else {}
        scorecard = scorecard_map.get(clone_id, {})
        open_risks = normalize_list(existing.get("open_risks")) if not latest else []
        latest_open = normalize_list(normalize_verification_result(latest.get("verification_result")).get("open_questions"))
        if latest_open:
            open_risks = latest_open
        max_distortion = str(latest.get("max_distortion") or "").strip()
        if max_distortion and (latest_open or str(scorecard.get("promotion_recommendation") or "") in {"watch", "hibernate"}):
            open_risks = normalize_list(open_risks + [max_distortion])
        if not open_risks and not latest:
            open_risks = ["No training cycle completed yet."]
        current_stage = "registered"
        if latest:
            current_stage = "training"
        if str(scorecard.get("promotion_recommendation") or "") in {"watch", "hibernate"}:
            current_stage = "review_pending"
        rows.append(
            {
                "clone_id": clone_id,
                "clone_mode": normalized_clone_mode(registry.get("clone_mode"), missing_default="lab"),
                "current_stage": current_stage,
                "assigned_skill_chain": normalize_list(latest.get("skills_selected") or existing.get("assigned_skill_chain")),
                "last_run_id": str(latest.get("run_id") or existing.get("last_run_id") or ""),
                "target_capability": str(latest.get("target_capability") or existing.get("target_capability") or ""),
                "open_risks": open_risks,
                "next_cycle": next_clone_cycle_label(str(latest.get("created_at") or registry.get("created_at") or iso_now())),
                "updated_at": iso_now(),
            }
        )
    rows.sort(key=lambda item: str(item.get("clone_id") or ""))
    return rows


def build_clone_autonomy_rows(scorecards: list[dict[str, Any]]) -> list[dict[str, Any]]:
    rows = [
        {
            "clone_id": row["clone_id"],
            "display_name": row["display_name"],
            "customer_id": row["customer_id"],
            "org_id": str(row.get("org_id") or ""),
            "tenant_id": str(row.get("tenant_id") or ""),
            "portfolio_scope": str(row.get("portfolio_scope") or ""),
            "clone_mode": row.get("clone_mode", "client"),
            "autonomy_cap": row["autonomy_cap"],
            "routing_priority": row["routing_priority"],
            "budget_weight": row["budget_weight"],
            "promotion_recommendation": row["promotion_recommendation"],
            "updated_at": row["updated_at"],
        }
        for row in scorecards
    ]
    rows.sort(key=lambda item: (AUTONOMY_TIERS.index(str(item["autonomy_cap"])), -safe_float(item["routing_priority"])))
    return rows


def promotion_reason(row: dict[str, Any]) -> str:
    recommendation = str(row.get("promotion_recommendation") or "")
    if normalized_clone_mode(row.get("clone_mode"), missing_default="client") != "client":
        return "Lab clone stays proposal-only and is excluded from formal client promotion by default."
    if recommendation == "promote":
        return "Client clone passed the multi-run promotion gate with strong verification and low distortion."
    if recommendation == "watch":
        if bool(row.get("hard_boundary_open_questions")):
            return "Boundary-sensitive open questions remain; keep the clone in controlled observation."
        return "Evidence exists, but distortion or closure quality still needs another controlled cycle."
    if recommendation == "hibernate":
        return "Current distortion outweighs verified gains; freeze budget expansion until risks clear."
    return "Stay at the current tier while accumulating more evidence."


def build_clone_promotion_queue(scorecards: list[dict[str, Any]]) -> list[dict[str, Any]]:
    rows: list[dict[str, Any]] = []
    for row in scorecards:
        recommendation = str(row.get("promotion_recommendation") or "hold")
        if recommendation == "hold":
            continue
        rows.append(
            {
                "clone_id": row["clone_id"],
                "display_name": row["display_name"],
                "customer_id": row["customer_id"],
                "org_id": str(row.get("org_id") or ""),
                "tenant_id": str(row.get("tenant_id") or ""),
                "portfolio_scope": str(row.get("portfolio_scope") or ""),
                "clone_mode": row.get("clone_mode", "client"),
                "proposal_id": f"clone-promotion::{row['clone_id']}",
                "proposal_type": "clone_promotion",
                "target_id": row["clone_id"],
                "recommended_action": recommendation,
                "promotion_recommendation": recommendation,
                "autonomy_cap": row["autonomy_cap"],
                "routing_priority": row["routing_priority"],
                "budget_weight": row["budget_weight"],
                "reason": promotion_reason(row),
                "approval_required": True,
                "status": "pending_approval",
                "source_path": str(CLONE_PROMOTION_QUEUE_PATH.resolve()),
                "updated_at": row["updated_at"],
                "created_at": row["updated_at"],
            }
        )
    rows.sort(key=lambda item: (CLONE_PROMOTION_CHOICES.index(item["promotion_recommendation"]), -safe_float(item["routing_priority"])))
    return rows


def build_clone_portfolio_report(
    registry_rows: list[dict[str, Any]],
    state_rows: list[dict[str, Any]],
    scorecards: list[dict[str, Any]],
    promotion_queue: list[dict[str, Any]],
    records: list[dict[str, Any]],
    *,
    report_date: str | None = None,
    include_lab: bool = False,
    portfolio: str = "client",
    all_registry_rows: list[dict[str, Any]] | None = None,
) -> dict[str, Any]:
    target_date = report_date or now_local().strftime("%Y-%m-%d")
    grouped = clone_grouped_records(records)
    state_map = {str(row.get("clone_id") or "").strip(): row for row in state_rows}
    sections: dict[str, list[dict[str, Any]]] = {section: [] for section in CLONE_PORTFOLIO_SECTIONS}
    all_registry_rows = all_registry_rows or registry_rows
    effective_portfolio = effective_clone_portfolio(portfolio, include_lab=include_lab)

    for registry in registry_rows:
        clone_id = str(registry.get("clone_id") or "").strip()
        if not clone_id:
            continue
        latest = grouped.get(clone_id, [{}])[0] if grouped.get(clone_id) else {}
        state = state_map.get(clone_id, {})
        created_on_date = str(registry.get("created_at") or "").startswith(target_date)
        latest_on_date = str(latest.get("created_at") or "").startswith(target_date)
        if created_on_date or latest_on_date:
            summary_parts = [str(registry.get("display_name") or clone_id)]
            if created_on_date:
                summary_parts.append("new clone registered")
            if latest_on_date:
                summary_parts.append(f"latest capability: {str(latest.get('target_capability') or 'n/a')}")
                summary_parts.append(f"last run: {str(latest.get('run_id') or 'n/a')}")
            sections["今日新增与状态变化"].append(
                {
                    "clone_id": clone_id,
                    "summary": " | ".join(summary_parts),
                }
            )
        if state:
            risk_items = normalize_list(state.get("open_risks"))
            if risk_items:
                sections["当前最大失真与主要风险"].append(
                    {
                        "clone_id": clone_id,
                        "summary": f"{str(registry.get('display_name') or clone_id)} :: {' | '.join(risk_items[:2])}",
                    }
                )

    for index, row in enumerate(scorecards, start=1):
        sections["克隆体排名与分层"].append(
            {
                "clone_id": row["clone_id"],
                "summary": (
                    f"#{index} {row['display_name']} :: priority={row['routing_priority']} :: "
                    f"mode={row.get('clone_mode', 'client')} :: autonomy={row['autonomy_cap']} :: "
                    f"promotion={row['promotion_recommendation']} :: "
                    f"budget={row['budget_weight']}"
                ),
            }
        )
        state = state_map.get(row["clone_id"], {})
        target_capability = str(state.get("target_capability") or row.get("goal_model") or "").strip()
        if not target_capability:
            target_capability = "建立下一轮验证能力"
        if str(row.get("promotion_recommendation") or "") == "promote":
            suggestion = f"{row['display_name']} :: prepare guarded-autonomy review for {target_capability}"
        elif str(row.get("promotion_recommendation") or "") == "hibernate":
            suggestion = f"{row['display_name']} :: pause expansion and clear distortion before more budget"
        else:
            suggestion = f"{row['display_name']} :: continue one focused training cycle on {target_capability}"
        sections["明日训练建议"].append({"clone_id": row["clone_id"], "summary": suggestion})

    for row in promotion_queue:
        sections["候选晋升 / 降权 / 休眠"].append(
            {
                "clone_id": row["clone_id"],
                "summary": (
                    f"{row['display_name']} :: {row['promotion_recommendation']} :: "
                    f"priority={row['routing_priority']} :: status={row.get('status') or 'pending_approval'} :: reason={row['reason']}"
                ),
            }
        )

    for section in CLONE_PORTFOLIO_SECTIONS:
        sections[section] = sections[section][:12]

    if not scorecards and any(
        normalized_clone_mode(row.get("clone_mode"), missing_default="lab") == "lab" for row in all_registry_rows
    ) and effective_portfolio == "client":
        sections["今日新增与状态变化"].insert(
            0,
            {
                "clone_id": "scope-note",
                "summary": "All currently registered clones are tagged as lab and are excluded from the default client portfolio.",
            },
        )

    report = {
        "generated_at": iso_now(),
        "report_date": target_date,
        "portfolio": effective_portfolio,
        "clone_count": len(registry_rows),
        "total_registered_clones": len(all_registry_rows),
        "internal_clone_count": len(
            [row for row in all_registry_rows if str(row.get("portfolio_scope") or "client") == "internal"]
        ),
        "client_clone_count": len(
            [row for row in all_registry_rows if str(row.get("portfolio_scope") or "client") == "client"]
        ),
        "lab_clone_count": len(
            [row for row in all_registry_rows if normalized_clone_mode(row.get("clone_mode"), missing_default="lab") == "lab"]
        ),
        "include_lab": include_lab,
        "sections": sections,
    }
    return enrich_clone_portfolio_report(report)


def refresh_clone_factory_state(
    report_date: str | None = None,
    *,
    include_lab: bool = False,
    portfolio: str = "client",
    persist: bool = True,
) -> dict[str, Any]:
    state = load_clone_factory_state()
    registry_rows = state["registry"]
    role_templates = state["role_templates"]
    effective_portfolio = effective_clone_portfolio(portfolio, include_lab=include_lab)
    scoped_registry_rows = clone_registry_scope(registry_rows, include_lab=include_lab, portfolio=effective_portfolio)
    records = iter_clone_training_records(limit=5000)
    scorecards = build_clone_scorecards(
        registry_rows,
        state["training_state"],
        records,
        include_lab=include_lab,
        portfolio=effective_portfolio,
    )
    training_state = build_clone_training_states(registry_rows, state["training_state"], records, scorecards)
    autonomy_rows = build_clone_autonomy_rows(scorecards)
    promotion_queue = build_clone_promotion_queue(scorecards)
    budget_rows = clone_budget_allocations(scorecards)
    budget_map = {str(item.get("clone_id") or ""): safe_float(item.get("budget_weight")) for item in budget_rows}
    promotion_map = {str(item.get("clone_id") or ""): str(item.get("promotion_recommendation") or "hold") for item in promotion_queue}
    autonomy_map = {str(item.get("clone_id") or ""): str(item.get("autonomy_cap") or "observe") for item in autonomy_rows}
    for row in scorecards:
        row["budget_weight"] = budget_map.get(row["clone_id"], row["budget_weight"])
        row["promotion_recommendation"] = promotion_map.get(row["clone_id"], row["promotion_recommendation"])
        row["autonomy_cap"] = autonomy_map.get(row["clone_id"], row["autonomy_cap"])
    autonomy_rows = build_clone_autonomy_rows(scorecards)
    promotion_queue = build_clone_promotion_queue(scorecards)
    budget_rows = clone_budget_allocations(scorecards)
    portfolio = build_clone_portfolio_report(
        scoped_registry_rows,
        training_state,
        scorecards,
        promotion_queue,
        records,
        report_date=report_date,
        include_lab=include_lab,
        portfolio=effective_portfolio,
        all_registry_rows=registry_rows,
    )
    org_rows = build_clone_org_rows(scoped_registry_rows)
    task_run_rows = build_clone_task_run_rows(records, scoped_registry_rows)
    training_cycle_rows = build_clone_training_cycle_rows(records, scoped_registry_rows)
    capability_proposals = build_clone_capability_proposals(records, scoped_registry_rows)
    alerts_decisions = build_clone_alerts_decisions(scorecards, training_state, promotion_queue)
    if persist:
        write_json(ROLE_TEMPLATE_REGISTRY_PATH, role_templates)
        write_json(CLONE_ORG_REGISTRY_PATH, org_rows)
        write_json(CLONE_SCORECARD_PATH, scorecards)
        write_json(CLONE_TRAINING_STATE_PATH, training_state)
        write_json(CLONE_AUTONOMY_TIER_PATH, autonomy_rows)
        write_json(CLONE_PROMOTION_QUEUE_PATH, promotion_queue)
        write_json(CLONE_BUDGET_ALLOCATION_PATH, budget_rows)
        write_json(CLONE_TASK_RUNS_PATH, task_run_rows)
        write_json(CLONE_TRAINING_CYCLES_PATH, training_cycle_rows)
        write_json(CLONE_CAPABILITY_PROPOSALS_PATH, capability_proposals)
        write_json(CLONE_ALERTS_DECISIONS_PATH, alerts_decisions)
        write_json(CLONE_PORTFOLIO_REPORT_PATH, portfolio)
        CLONE_PORTFOLIO_REPORT_MD_PATH.write_text(render_clone_portfolio_markdown(portfolio), encoding="utf-8")
    return {
        "registry": registry_rows,
        "role_templates": role_templates,
        "org_registry": org_rows,
        "visible_registry": scoped_registry_rows,
        "lab_registry_count": len(
            [row for row in registry_rows if normalized_clone_mode(row.get("clone_mode"), missing_default="lab") == "lab"]
        ),
        "include_lab": include_lab,
        "portfolio": effective_portfolio,
        "training_state": training_state,
        "scorecard": scorecards,
        "autonomy_tier": autonomy_rows,
        "promotion_queue": promotion_queue,
        "budget_allocation": budget_rows,
        "task_runs": task_run_rows,
        "training_cycles": training_cycle_rows,
        "capability_proposals": capability_proposals,
        "alerts_decisions": alerts_decisions,
        "portfolio_report": portfolio,
        "records": records,
    }


def clone_seed_slug_title(value: str) -> str:
    parts = [part for part in re.split(r"[-_\s]+", str(value or "").strip()) if part]
    if not parts:
        return "Clone"
    return " ".join(part[:1].upper() + part[1:] for part in parts)


def current_claude_init_version() -> str:
    claude_init_path = PROJECT_ROOT / "yuanli-os-claude" / "CLAUDE-INIT.md"
    if not claude_init_path.exists():
        return "unknown"
    text = claude_init_path.read_text(encoding="utf-8")
    match = re.search(r"V\d+(?:\.\d+)?", text)
    return match.group(0) if match else "unknown"


