def list_run_artifacts(run_dir: Path) -> list[str]:
    artifacts: list[str] = []
    for path in sorted(run_dir.iterdir()) if run_dir.exists() else []:
        if path.is_file():
            artifacts.append(str(path.resolve()))
    return artifacts


def recommend_next_action_from_evolution(evolution: dict[str, Any]) -> str:
    open_questions = summarize_open_questions(evolution.get("verification_result") or {})
    candidates = [
        first_non_empty_line("\n".join(normalize_list(evolution.get("evolution_candidates")))),
        first_non_empty_line(open_questions),
    ]
    for candidate in candidates:
        if candidate:
            return candidate
    verification_status = str((evolution.get("verification_result") or {}).get("status") or "").strip().lower()
    if verification_status in {"passed", "success", "done", "complete", "completed"}:
        return "Promote the strongest verified pattern into the next iteration."
    return "Close the remaining open question before promoting this run."


def build_claude_handoff(evolution: dict[str, Any], worklog: dict[str, Any], run_dir: Path) -> dict[str, Any]:
    verification = evolution.get("verification_result") if isinstance(evolution.get("verification_result"), dict) else {}
    return {
        "run_id": str(evolution.get("run_id") or ""),
        "task_text": str(evolution.get("task_text") or ""),
        "selected_skills": normalize_list(evolution.get("skills_selected")),
        "verification_status": str(verification.get("status") or ""),
        "verification_evidence": normalize_list(verification.get("evidence")),
        "feishu_sync_status": str(evolution.get("feishu_sync_status") or ""),
        "github_sync_status": str(evolution.get("github_sync_status") or ""),
        "github_issue_url": str(evolution.get("github_issue_url") or ""),
        "worklog_path": str((run_dir / "worklog.md").resolve()),
        "new_artifacts": list_run_artifacts(run_dir),
        "gained": normalize_list(evolution.get("effective_patterns")),
        "wasted": normalize_list(evolution.get("wasted_patterns")),
        "next_iterate": normalize_list(evolution.get("evolution_candidates")),
        "open_questions": normalize_list(verification.get("open_questions")),
        "recommended_next_action": recommend_next_action_from_evolution(evolution),
    }


