def refresh_run_documents(
    run_dir: Path,
    evolution: dict[str, Any],
    *,
    append_daily_log: bool = False,
) -> tuple[dict[str, Any], dict[str, Any], dict[str, Any]]:
    evolution = ensure_evolution_mirror_states(dict(evolution), run_dir)
    claude_context = evolution.get("claude_context") if isinstance(evolution.get("claude_context"), dict) else {}
    evolution["claude_context"] = {
        **claude_context,
        "handoff_json_path": str((run_dir / "claude_handoff.json").resolve()),
        "handoff_md_path": str((run_dir / "claude_handoff.md").resolve()),
    }
    worklog = build_worklog(evolution, run_dir)
    handoff = build_claude_handoff(evolution, worklog, run_dir)
    evolution["claude_context"] = {
        **evolution["claude_context"],
        "recommended_next_action": handoff["recommended_next_action"],
        "updated_at": iso_now(),
    }
    worklog = build_worklog(evolution, run_dir)
    handoff = build_claude_handoff(evolution, worklog, run_dir)
    write_json(run_dir / "evolution.json", evolution)
    (run_dir / "evolution.md").write_text(render_evolution_markdown(evolution), encoding="utf-8")
    write_json(run_dir / "worklog.json", worklog)
    (run_dir / "worklog.md").write_text(render_worklog_markdown(worklog), encoding="utf-8")
    (run_dir / "soul.md").write_text(render_soul_markdown(evolution, run_dir), encoding="utf-8")
    write_json(run_dir / "claude_handoff.json", handoff)
    (run_dir / "claude_handoff.md").write_text(render_claude_handoff_markdown(handoff), encoding="utf-8")
    write_json(run_dir / "feishu-payload.json", make_feishu_payload(worklog))
    if append_daily_log:
        append_daily_soul_log(evolution)
    return evolution, worklog, handoff


