def normalize_autoclaw_family_key(value: str) -> str:
    slug = value.strip().lower().replace("_", "-")
    slug = re.sub(r"-(?:v?\d+(?:\.\d+){0,4})$", "", slug)
    return slug


def iter_nested_objects(payload: Any) -> Any:
    if isinstance(payload, dict):
        yield payload
        for value in payload.values():
            yield from iter_nested_objects(value)
    elif isinstance(payload, list):
        for item in payload:
            yield from iter_nested_objects(item)


def normalize_string_list(value: Any) -> list[str]:
    if isinstance(value, str):
        text = value.strip()
        return [text] if text else []
    if isinstance(value, list):
        result: list[str] = []
        for item in value:
            if isinstance(item, str) and item.strip():
                result.append(item.strip())
        return result
    return []


def extract_requirement_info(metadata: dict[str, Any], text: str) -> dict[str, Any]:
    bins_required: list[str] = []
    env_required: list[str] = []
    os_required: list[str] = []
    install_labels: list[str] = []
    for node in iter_nested_objects(metadata):
        if not isinstance(node, dict):
            continue
        requires = node.get("requires")
        if isinstance(requires, dict):
            bins_required.extend(normalize_string_list(requires.get("bins")))
            env_required.extend(normalize_string_list(requires.get("env")))
            env_required.extend(normalize_string_list(requires.get("envs")))
            env_required.extend(normalize_string_list(requires.get("secrets")))
            env_required.extend(normalize_string_list(requires.get("tokens")))
            env_required.extend(normalize_string_list(requires.get("auth")))
        os_required.extend(normalize_string_list(node.get("os")))
        install_value = node.get("install")
        if isinstance(install_value, list):
            for item in install_value:
                if isinstance(item, dict):
                    label = str(item.get("label") or item.get("formula") or item.get("id") or "").strip()
                    if label:
                        install_labels.append(label)
    bins_required = sorted(set(bins_required))
    env_required = sorted(set(env_required))
    os_required = sorted(set(os_required))
    install_labels = sorted(set(install_labels))
    bins_missing = sorted(bin_name for bin_name in bins_required if shutil.which(bin_name) is None)
    current_os = "darwin" if sys.platform == "darwin" else ("linux" if sys.platform.startswith("linux") else sys.platform)
    platform_limited = bool(os_required)
    platform_match = not platform_limited or current_os in os_required
    auth_hint = bool(env_required)
    if not auth_hint:
        auth_patterns = [
            r"\bapi[_ -]?key\b",
            r"\bapp[_ -]?id\b",
            r"\bapp[_ -]?secret\b",
            r"\btoken\b",
            r"\bpermissions?\b",
            r"\bsign[- ]?in\b",
            r"\bauth\b",
        ]
        auth_hint = any(re.search(pattern, text, re.IGNORECASE) for pattern in auth_patterns)
    dependency_bucket = "无依赖可直接用"
    if bins_missing:
        dependency_bucket = "缺 bin"
    elif auth_hint:
        dependency_bucket = "缺 auth"
    elif platform_limited:
        dependency_bucket = "平台限定"
    return {
        "bins_required": bins_required,
        "bins_missing": bins_missing,
        "env_required": env_required,
        "os_required": os_required,
        "platform_match": platform_match,
        "install_labels": install_labels,
        "auth_hint": auth_hint,
        "dependency_bucket": dependency_bucket,
    }


def classify_capability_cluster(family_key: str, name: str, description: str) -> str:
    slug = " ".join([family_key, name.lower()])
    if family_key in AUTOGLM_CORE_FAMILIES or any(token in slug for token in ["browser-agent", "deepresearch", "open-link", "search-image", "generate-image", "websearch"]):
        return "AutoGLM 基础能力"
    if family_key.startswith("feishu") or "feishu" in slug or "lark" in slug or "wiki" in slug:
        return "Feishu 协作"
    if any(token in slug for token in ["blog", "seo", "copywriting", "social", "content", "writer", "marketing"]):
        return "内容营销"
    if any(token in slug for token in ["stock", "market", "aminer", "research", "paper", "backtest", "finance"]):
        return "研究金融"
    if any(token in slug for token in ["code", "debug", "frontend", "architecture", "security", "test", "github", "gh-", "supabase", "tmux", "1password", "video"]):
        return "开发构建"
    if family_key in WORKFLOW_META_PRIORITY_FAMILIES or any(
        token in slug
        for token in [
            "find-skills",
            "skill-creator",
            "skill-vetter",
            "reflection",
            "memory",
            "session-logs",
            "brainstorming",
            "executing-plans",
            "writing-plans",
            "opencode-controller",
            "automation-workflows",
        ]
    ):
        return "workflow/meta"
    return "其他"


def load_autoclaw_source_specs(config_path: Path, app_resources_root: Path) -> list[dict[str, str]]:
    specs: list[dict[str, str]] = []
    if app_resources_root.exists():
        packaged_root = app_resources_root / "skills"
        gateway_root = app_resources_root / "gateway" / "openclaw" / "skills"
        feishu_root = app_resources_root / "gateway" / "openclaw" / "extensions" / "feishu" / "skills"
        if packaged_root.exists():
            specs.append(
                {
                    "source_id": "packaged_custom",
                    "source_layer": "packaged custom",
                    "path": str(packaged_root),
                    "label": "AutoClaw.app packaged custom",
                }
            )
        if gateway_root.exists():
            specs.append(
                {
                    "source_id": "gateway_builtin",
                    "source_layer": "gateway builtin",
                    "path": str(gateway_root),
                    "label": "AutoClaw gateway builtins",
                }
            )
        if feishu_root.exists():
            specs.append(
                {
                    "source_id": "feishu_extension",
                    "source_layer": "feishu extension",
                    "path": str(feishu_root),
                    "label": "AutoClaw gateway feishu extension",
                }
            )
    config = load_optional_json(config_path)
    extra_dirs = config.get("skills", {}).get("load", {}).get("extraDirs", []) if isinstance(config.get("skills"), dict) else []
    for index, raw_path in enumerate(extra_dirs, start=1):
        path = Path(str(raw_path)).expanduser()
        specs.append(
            {
                "source_id": f"extra_mirror_{index}",
                "source_layer": "extraDirs mirror",
                "path": str(path),
                "label": f"extraDirs[{index}]",
            }
        )
    return specs


def scan_autoclaw_skill_source(source_spec: dict[str, str]) -> list[dict[str, Any]]:
    root = Path(source_spec["path"]).expanduser()
    if not root.exists():
        return []
    entries: list[dict[str, Any]] = []
    for skill_md in sorted(root.glob("*/SKILL.md")):
        try:
            text = load_text(skill_md)
        except Exception:
            continue
        payload = parse_frontmatter(text)
        metadata = payload.get("metadata") if isinstance(payload.get("metadata"), dict) else {}
        exact_name = skill_md.parent.name
        skill_name = str(payload.get("name") or exact_name).strip() or exact_name
        description = str(payload.get("description") or "").strip()
        family_key = normalize_autoclaw_family_key(exact_name)
        requirement_info = extract_requirement_info(metadata, text)
        entries.append(
            {
                "name": skill_name,
                "exact_name": exact_name,
                "family_key": family_key,
                "description": description,
                "path": str(skill_md),
                "base_dir": str(skill_md.parent),
                "source_id": source_spec["source_id"],
                "source_layer": source_spec["source_layer"],
                "source_label": source_spec["label"],
                "sha256": hashlib.sha256(text.encode("utf-8")).hexdigest(),
                "dependency": requirement_info,
                "capability_cluster": classify_capability_cluster(family_key, skill_name, description),
            }
        )
    return entries


def load_autoclaw_runtime_snapshot(session_index_path: Path) -> dict[str, Any]:
    payload = load_optional_json(session_index_path)
    latest_key = ""
    latest_entry: dict[str, Any] = {}
    latest_updated_at = -1
    for key, value in payload.items():
        if not isinstance(value, dict):
            continue
        updated_at = int(value.get("updatedAt") or -1)
        if "skillsSnapshot" not in value or updated_at < latest_updated_at:
            continue
        latest_key = str(key)
        latest_entry = value
        latest_updated_at = updated_at
    snapshot = latest_entry.get("skillsSnapshot") if isinstance(latest_entry.get("skillsSnapshot"), dict) else {}
    skills = snapshot.get("skills") if isinstance(snapshot.get("skills"), list) else []
    resolved = snapshot.get("resolvedSkills") if isinstance(snapshot.get("resolvedSkills"), list) else []
    resolved_entries: list[dict[str, Any]] = []
    for item in resolved:
        if not isinstance(item, dict):
            continue
        file_path = str(item.get("filePath") or "").strip()
        exact_name = Path(file_path).parent.name if file_path else str(item.get("name") or "").strip().lower().replace(" ", "-")
        family_key = normalize_autoclaw_family_key(exact_name or str(item.get("name") or ""))
        resolved_entries.append(
            {
                "name": str(item.get("name") or "").strip(),
                "file_path": file_path,
                "base_dir": str(item.get("baseDir") or "").strip(),
                "source": str(item.get("source") or "").strip(),
                "exact_name": exact_name,
                "family_key": family_key,
            }
        )
    return {
        "session_key": latest_key,
        "updated_at": latest_updated_at,
        "skills_count": len(skills),
        "resolved_count": len(resolved_entries),
        "resolved_entries": resolved_entries,
        "resolved_sources": dict(Counter(item["source"] for item in resolved_entries if item["source"])),
        "resolved_exact_names": sorted({item["exact_name"] for item in resolved_entries if item["exact_name"]}),
        "resolved_family_keys": sorted({item["family_key"] for item in resolved_entries if item["family_key"]}),
        "resolved_paths": sorted({item["file_path"] for item in resolved_entries if item["file_path"]}),
    }


def summarize_autoclaw_sources(entries: list[dict[str, Any]], source_specs: list[dict[str, str]]) -> list[dict[str, Any]]:
    summary: list[dict[str, Any]] = []
    by_source: dict[str, list[dict[str, Any]]] = defaultdict(list)
    for entry in entries:
        by_source[entry["source_id"]].append(entry)
    for spec in source_specs:
        rows = by_source.get(spec["source_id"], [])
        summary.append(
            {
                "source_id": spec["source_id"],
                "source_layer": spec["source_layer"],
                "label": spec["label"],
                "path": spec["path"],
                "exists": Path(spec["path"]).exists(),
                "skill_count": len(rows),
                "family_count": len({row["family_key"] for row in rows}),
            }
        )
    return summary


def build_exact_duplicate_view(entries: list[dict[str, Any]]) -> list[dict[str, Any]]:
    grouped: dict[str, list[dict[str, Any]]] = defaultdict(list)
    for entry in entries:
        grouped[entry["exact_name"]].append(entry)
    rows: list[dict[str, Any]] = []
    for exact_name, members in sorted(grouped.items()):
        if len(members) <= 1:
            continue
        rows.append(
            {
                "exact_name": exact_name,
                "source_layers": sorted({member["source_layer"] for member in members}),
                "source_ids": [member["source_id"] for member in members],
                "hash_count": len({member["sha256"] for member in members}),
                "hashes_identical": len({member["sha256"] for member in members}) == 1,
                "paths": [member["path"] for member in members],
            }
        )
    return rows


def compute_autoclaw_overlap_note(family_key: str, cluster: str) -> str:
    if family_key in AUTOGLM_CORE_FAMILIES:
        return "AutoGLM 核心能力本体"
    if any(token in family_key for token in ["browser", "websearch", "deepresearch", "open-link", "search-image", "generate-image"]):
        return "会抢 AutoGLM 基础能力"
    if cluster == "研究金融" and any(token in family_key for token in ["research", "market", "aminer"]):
        return "容易与 deepresearch / websearch 抢研究入口"
    return "无直接重叠"


def compute_gateway_fit(source_layers: set[str], dependency_bucket: str, runtime_available: bool) -> str:
    if runtime_available or "gateway builtin" in source_layers or "feishu extension" in source_layers:
        return "高"
    if dependency_bucket in {"缺 bin", "缺 auth"}:
        return "低"
    return "中"


def compute_retention_value(cluster: str, runtime_available: bool, family_key: str) -> str:
    if family_key in AUTOGLM_CORE_FAMILIES:
        return "高"
    if runtime_available and cluster in {"Feishu 协作", "开发构建"}:
        return "中"
    if cluster in {"workflow/meta", "内容营销"}:
        return "低"
    return "中" if runtime_available else "低"


def recommend_autoclaw_action(profile: dict[str, Any]) -> tuple[str, str, str]:
    family_key = profile["family_key"]
    cluster = profile["capability_cluster"]
    dependency_bucket = profile["dependency_bucket"]
    runtime_available = profile["runtime_available"]
    if family_key in AUTOGLM_CORE_FAMILIES:
        return ("保留启用", "基础底座", "AutoGLM 核心执行层，应作为默认保留集。")
    if family_key in {"github", "gh-issues", "weather", "healthcheck"}:
        return ("保留启用", "高频执行层", "当前 gateway 原生能力，和主模型/网关适配度高。")
    if family_key in {"1password", "tmux", "video-frames", "feishu-doc", "feishu-drive", "feishu-perm", "feishu-wiki"}:
        return ("条件启用", "中频专项层", "专项价值明确，但依赖 bin、鉴权或边界敏感，不适合全时开启。")
    if family_key in WORKFLOW_META_PRIORITY_FAMILIES or cluster == "workflow/meta":
        return ("默认禁用", "高冲突或低收益层", "容易与总控、记忆、自反思链路叠加，优先收缩。")
    if cluster == "内容营销":
        return ("默认禁用", "高冲突或低收益层", "对当前 AutoClaw 总控工作流不是底座能力，默认关闭更稳。")
    if dependency_bucket in {"缺 bin", "缺 auth"}:
        return ("条件启用", "中频专项层", "功能可用，但当前机器还缺依赖或凭证。")
    if cluster in {"Feishu 协作", "开发构建", "研究金融"}:
        return ("观察", "中频专项层", "保留候选位，等 7 天自用数据再决定是否常驻。")
    if runtime_available:
        return ("观察", "中频专项层", "当前可用但非底座，先观察真实唤起频率。")
    return ("默认禁用", "高冲突或低收益层", "当前既非底座也非高频，不建议默认开启。")


def build_autoclaw_family_profiles(entries: list[dict[str, Any]], runtime_snapshot: dict[str, Any]) -> list[dict[str, Any]]:
    runtime_paths = set(runtime_snapshot.get("resolved_paths", []))
    runtime_families = set(runtime_snapshot.get("resolved_family_keys", []))
    grouped: dict[str, list[dict[str, Any]]] = defaultdict(list)
    for entry in entries:
        grouped[entry["family_key"]].append(entry)
    profiles: list[dict[str, Any]] = []
    for family_key, members in sorted(grouped.items()):
        source_layers = {member["source_layer"] for member in members}
        capability_cluster = Counter(member["capability_cluster"] for member in members).most_common(1)[0][0]
        dependency_bucket = Counter(member["dependency"]["dependency_bucket"] for member in members).most_common(1)[0][0]
        runtime_available = family_key in runtime_families or any(member["path"] in runtime_paths for member in members)
        duplicate_source_layers = len(source_layers)
        family_overlap_note = compute_autoclaw_overlap_note(family_key, capability_cluster)
        workflow_conflict = "高" if capability_cluster == "workflow/meta" or family_key in WORKFLOW_META_PRIORITY_FAMILIES else ("中" if duplicate_source_layers > 1 else "低")
        action, recommendation_tier, recommendation_reason = recommend_autoclaw_action(
            {
                "family_key": family_key,
                "capability_cluster": capability_cluster,
                "dependency_bucket": dependency_bucket,
                "runtime_available": runtime_available,
            }
        )
        conflict_score = 0
        if capability_cluster == "workflow/meta":
            conflict_score += 60
        if family_key in SPECIAL_AUDIT_FAMILIES:
            conflict_score += 25
        if duplicate_source_layers > 1:
            conflict_score += 20
        if dependency_bucket in {"缺 bin", "缺 auth"}:
            conflict_score += 15
        if family_overlap_note != "无直接重叠":
            conflict_score += 15
        if runtime_available:
            conflict_score += 5
        profile = {
            "family_key": family_key,
            "display_name": members[0]["name"],
            "config_skill_keys": sorted({str(member["name"]).strip() for member in members if str(member["name"]).strip()}),
            "exact_members": sorted({member["exact_name"] for member in members}),
            "source_layers": sorted(source_layers),
            "source_ids": sorted({member["source_id"] for member in members}),
            "paths": [member["path"] for member in members],
            "capability_cluster": capability_cluster,
            "dependency_bucket": dependency_bucket,
            "bins_required": sorted({bin_name for member in members for bin_name in member["dependency"]["bins_required"]}),
            "bins_missing": sorted({bin_name for member in members for bin_name in member["dependency"]["bins_missing"]}),
            "os_required": sorted({os_name for member in members for os_name in member["dependency"]["os_required"]}),
            "runtime_available": runtime_available,
            "gateway_fit": compute_gateway_fit(source_layers, dependency_bucket, runtime_available),
            "autoglm_overlap": family_overlap_note,
            "workflow_conflict": workflow_conflict,
            "retention_value": compute_retention_value(capability_cluster, runtime_available, family_key),
            "recommendation": action,
            "recommendation_tier": recommendation_tier,
            "recommendation_reason": recommendation_reason,
            "conflict_score": conflict_score,
        }
        profiles.append(profile)
    profiles.sort(key=lambda item: (-item["conflict_score"], item["family_key"]))
    return profiles


def build_autoclaw_special_family_notes(family_profiles: list[dict[str, Any]]) -> list[dict[str, Any]]:
    profile_map = {item["family_key"]: item for item in family_profiles}
    notes: list[dict[str, Any]] = []
    note_text = {
        "1password": "与 gateway 内置版同族，且当前机器缺 `op`。建议只保留一个 family，并在确实要走 secrets/tmux 鉴权链时再启用。",
        "tmux": "与 gateway 内置版同族，且当前机器缺 `tmux`。它是交互式 CLI 的专项工具，不适合作为默认常驻技能。",
        "session-logs": "与 gateway 内置版同族，又属于 workflow/meta。默认开启会放大重复日志与重复自我总结。",
        "skill-creator": "与 gateway 内置版同族，又会和 find-skills / self-improving 抢治理入口。应保留一条显式调用路径，而不是常驻。",
        "video-frames": "与 gateway 内置版同族，且当前机器缺 `ffmpeg`。明确是专项多媒体工具，应走条件启用。",
        "feishu-doc": "packaged custom 与 Feishu extension 同族重叠。优先保留更贴近 gateway 的扩展面，避免双套文档读写语义并存。",
        "feishu-drive": "当前 runtime 里已有 gateway extension 版本。建议把文件云盘能力统一到 extension 面，别再叠一套 custom 版。",
        "feishu-perm": "权限类 skill 天然敏感，且和 packaged custom 重叠。即便保留，也只适合作为条件启用，不适合默认放开。",
    }
    for family_key in SPECIAL_AUDIT_FAMILIES:
        profile = profile_map.get(family_key)
        if not profile:
            continue
        notes.append(
            {
                "family_key": family_key,
                "recommendation": profile["recommendation"],
                "tier": profile["recommendation_tier"],
                "note": note_text[family_key],
                "source_layers": profile["source_layers"],
                "dependency_bucket": profile["dependency_bucket"],
            }
        )
    return notes


def render_markdown_table(headers: list[str], rows: list[list[str]]) -> str:
    if not rows:
        return "_无数据_"
    lines = [
        "| " + " | ".join(headers) + " |",
        "| " + " | ".join(["---"] * len(headers)) + " |",
    ]
    for row in rows:
        lines.append("| " + " | ".join(row) + " |")
    return "\n".join(lines)


def render_autoclaw_skill_audit_report(audit: dict[str, Any]) -> str:
    source_rows = [
        [
            row["source_layer"],
            row["source_id"],
            str(row["skill_count"]),
            str(row["family_count"]),
            row["path"],
        ]
        for row in audit["source_view"]
    ]
    dependency_counter = Counter(item["dependency_bucket"] for item in audit["family_profiles"])
    cluster_counter = Counter(item["capability_cluster"] for item in audit["family_profiles"])
    top_conflicts = audit["top_conflict_families"][:20]
    conflict_rows = [
        [
            item["family_key"],
            item["capability_cluster"],
            item["recommendation"],
            str(item["conflict_score"]),
            item["autoglm_overlap"],
        ]
        for item in top_conflicts
    ]
    retain_rows = [[item["family_key"], item["recommendation_tier"], item["recommendation_reason"]] for item in audit["default_keep_set"]]
    special_rows = [
        [
            item["family_key"],
            item["recommendation"],
            item["tier"],
            item["dependency_bucket"],
            item["note"],
        ]
        for item in audit["special_family_notes"]
    ]
    lines = [
        "# AutoClaw Skill 治理审计报告",
        "",
        f"- generated_at: `{audit['generated_at']}`",
        f"- config: `{audit['config_path']}`",
        f"- sessions: `{audit['session_index_path']}`",
        "",
        "## 结论摘要",
        "",
        f"- 原始来源条目总数: `{audit['summary']['source_entries_total']}`",
        f"- 精确目录去重后: `{audit['summary']['exact_unique_total']}`",
        f"- family 去重后: `{audit['summary']['family_unique_total']}`",
        f"- 当前 runtime 可用: `{audit['runtime_snapshot']['resolved_count']}`",
        f"- extraDirs 镜像重复: `{audit['summary']['mirror_duplicate_exact_total']}` 个 exact skill，`{audit['summary']['mirror_duplicate_hash_identical_total']}` 个完全同 hash",
        "",
        "## 先回答 5 个问题",
        "",
        f"1. `96` 不是原始磁盘文件数。当前机器从文件系统可见的是 `{audit['summary']['exact_unique_total']}` 个 exact skill、`{audit['summary']['family_unique_total']}` 个 family；AutoClaw UI 的 `96 已安装` 更像是 app 内部再做了一层发现过滤后的展示值。当前可验证的直接状态文件没有暴露这层最终过滤表，所以这次报告把 `96` 定义为“UI 展示态”，而不是“磁盘事实”。",
        f"2. `53 可用` 的硬证据来自最新 `skillsSnapshot.resolvedSkills`，当前 session 解析成功的就是 `{audit['runtime_snapshot']['resolved_count']}` 个，其中来源是 `{audit['runtime_snapshot']['resolved_sources']}`。这说明“可用”看的是 runtime 解析成功，而不是安装目录总数。",
        f"3. extraDirs 的两条目录是纯镜像。两边各 `{audit['summary']['extra_dir_skill_counts'][0] if audit['summary']['extra_dir_skill_counts'] else 0}` 个 SKILL，镜像重叠 `{audit['summary']['mirror_duplicate_exact_total']}`，且同名项同 hash `{audit['summary']['mirror_duplicate_hash_identical_total']}`。",
        f"4. 语义重叠最明显的是 workflow/meta 家族和跨来源重名 family，尤其是 `{', '.join(item['family_key'] for item in audit['top_conflict_families'][:8])}`。",
        f"5. 长期建议默认保留 `{', '.join(item['family_key'] for item in audit['default_keep_set'])}`；默认禁用优先看 workflow/meta 与内容营销层。",
        "",
        "## 来源视图",
        "",
        render_markdown_table(["layer", "source_id", "skills", "families", "path"], source_rows),
        "",
        "## 去重视图",
        "",
        f"- exact 重复组数: `{len(audit['exact_duplicates'])}`",
        f"- family 重复组数: `{audit['summary']['family_multi_source_total']}`",
        f"- extraDirs 纯镜像 exact: `{audit['summary']['mirror_duplicate_exact_total']}`",
        "",
        "## 依赖视图",
        "",
        render_markdown_table(
            ["bucket", "families"],
            [[bucket, str(count)] for bucket, count in sorted(dependency_counter.items())],
        ),
        "",
        "## 能力簇视图",
        "",
        render_markdown_table(
            ["cluster", "families"],
            [[bucket, str(count)] for bucket, count in sorted(cluster_counter.items())],
        ),
        "",
        "## 冲突视图 Top 20",
        "",
        render_markdown_table(["family", "cluster", "action", "score", "AutoGLM overlap"], conflict_rows),
        "",
        "## 建议默认保留集",
        "",
        render_markdown_table(["family", "tier", "reason"], retain_rows),
        "",
        "## 必讲 family 单独解释",
        "",
        render_markdown_table(["family", "action", "tier", "dependency", "note"], special_rows),
        "",
    ]
    return "\n".join(lines).rstrip() + "\n"


def build_autoclaw_skill_audit(
    *,
    config_path: Path,
    session_index_path: Path,
    app_resources_root: Path,
) -> dict[str, Any]:
    source_specs = load_autoclaw_source_specs(config_path, app_resources_root)
    entries: list[dict[str, Any]] = []
    for spec in source_specs:
        entries.extend(scan_autoclaw_skill_source(spec))
    runtime_snapshot = load_autoclaw_runtime_snapshot(session_index_path)
    exact_duplicates = build_exact_duplicate_view(entries)
    family_profiles = build_autoclaw_family_profiles(entries, runtime_snapshot)
    mirror_duplicates = [
        item
        for item in exact_duplicates
        if sum(1 for source_id in item["source_ids"] if str(source_id).startswith("extra_mirror_")) > 1
    ]
    source_view = summarize_autoclaw_sources(entries, source_specs)
    family_multi_source_total = sum(1 for item in family_profiles if len(item["source_layers"]) > 1)
    default_keep_set = [
        item
        for item in family_profiles
        if item["recommendation"] == "保留启用"
        and item["family_key"] in AUTOGLM_CORE_FAMILIES.union({"github", "gh-issues", "weather", "healthcheck"})
    ]
    default_keep_set.sort(key=lambda item: item["family_key"])
    audit = {
        "generated_at": iso_now(),
        "config_path": str(config_path),
        "session_index_path": str(session_index_path),
        "source_view": source_view,
        "exact_duplicates": exact_duplicates,
        "family_profiles": family_profiles,
        "runtime_snapshot": runtime_snapshot,
        "top_conflict_families": family_profiles[:20],
        "default_keep_set": default_keep_set,
        "special_family_notes": build_autoclaw_special_family_notes(family_profiles),
        "summary": {
            "source_entries_total": len(entries),
            "exact_unique_total": len({entry["exact_name"] for entry in entries}),
            "family_unique_total": len({entry["family_key"] for entry in entries}),
            "mirror_duplicate_exact_total": len(mirror_duplicates),
            "mirror_duplicate_hash_identical_total": sum(1 for item in mirror_duplicates if item["hashes_identical"]),
            "family_multi_source_total": family_multi_source_total,
            "extra_dir_skill_counts": [item["skill_count"] for item in source_view if item["source_layer"] == "extraDirs mirror"],
        },
    }
    return audit


def command_audit_autoclaw_skills(args: argparse.Namespace) -> int:
    config_path = Path(args.config).expanduser().resolve() if args.config else AUTOCLAW_CONFIG_PATH
    session_index_path = Path(args.sessions).expanduser().resolve() if args.sessions else AUTOCLAW_SESSION_INDEX_PATH
    app_resources_root = Path(args.app_resources).expanduser().resolve() if args.app_resources else AUTOCLAW_APP_RESOURCES_ROOT
    audit = build_autoclaw_skill_audit(
        config_path=config_path,
        session_index_path=session_index_path,
        app_resources_root=app_resources_root,
    )
    output_root = Path(args.output_dir).expanduser().resolve() if args.output_dir else AUTOCLAW_AUDIT_CURRENT_ROOT
    clear_directory(output_root)
    write_json(output_root / "audit.json", audit)
    write_json(output_root / "family-profiles.json", audit["family_profiles"])
    write_json(output_root / "source-view.json", audit["source_view"])
    write_json(output_root / "exact-duplicates.json", audit["exact_duplicates"])
    report_path = output_root / "report.md"
    report_path.write_text(render_autoclaw_skill_audit_report(audit), encoding="utf-8")
    print(f"report: {report_path}")
    print(f"source_entries_total: {audit['summary']['source_entries_total']}")
    print(f"exact_unique_total: {audit['summary']['exact_unique_total']}")
    print(f"family_unique_total: {audit['summary']['family_unique_total']}")
    print(f"runtime_available: {audit['runtime_snapshot']['resolved_count']}")
    return 0


def build_autoclaw_self_use_profile(audit: dict[str, Any]) -> dict[str, Any]:
    profile_map = {item["family_key"]: item for item in audit["family_profiles"]}
    policy_rows: list[dict[str, Any]] = []
    entries_patch: dict[str, dict[str, bool]] = {}
    conditional_enable_patch: dict[str, dict[str, bool]] = {}
    missing_families = {
        "keep": [item for item in AUTOCLAW_STRONG_KEEP_FAMILIES if item not in profile_map],
        "conditional": [item for item in AUTOCLAW_STRONG_CONDITIONAL_FAMILIES if item not in profile_map],
    }
    for family_key, profile in sorted(profile_map.items()):
        if family_key in AUTOCLAW_STRONG_KEEP_FAMILIES:
            policy = "keep"
            enabled = True
        elif family_key in AUTOCLAW_STRONG_CONDITIONAL_FAMILIES:
            policy = "conditional"
            enabled = False
        else:
            policy = "disable"
            enabled = False
        config_skill_keys = normalize_list(profile.get("config_skill_keys"))
        for skill_key in config_skill_keys:
            entries_patch[skill_key] = {"enabled": enabled}
            if policy == "conditional":
                conditional_enable_patch[skill_key] = {"enabled": True}
        policy_rows.append(
            {
                "family_key": family_key,
                "policy": policy,
                "enabled_by_default": enabled,
                "config_skill_keys": config_skill_keys,
                "capability_cluster": profile["capability_cluster"],
                "dependency_bucket": profile["dependency_bucket"],
                "runtime_available": profile["runtime_available"],
                "reason": (
                    "第一阶段默认常驻保留集。"
                    if policy == "keep"
                    else ("第一阶段按需启用，不常驻。" if policy == "conditional" else "强收敛模式下默认关闭，减少冲突和误路由。")
                ),
            }
        )
    return {
        "generated_at": iso_now(),
        "mode": "strong_convergence",
        "policies": policy_rows,
        "keep_families": [row for row in policy_rows if row["policy"] == "keep"],
        "conditional_families": [row for row in policy_rows if row["policy"] == "conditional"],
        "disabled_families": [row for row in policy_rows if row["policy"] == "disable"],
        "skills_entries_patch": {"skills": {"entries": entries_patch}},
        "conditional_enable_patch": {"skills": {"entries": conditional_enable_patch}},
        "missing_families": missing_families,
    }


def scan_browser_agent_diagnosis(
    *,
    sessions_root: Path,
    runtime_skills_root: Path,
) -> dict[str, Any]:
    skill_dir = runtime_skills_root / "autoglm-browser-agent"
    relay_path = skill_dir / "dist" / "relay"
    mcp_server_path = skill_dir / "dist" / "mcp_server"
    recent_findings: list[dict[str, str]] = []
    for path in sorted(sessions_root.glob("*.jsonl"), key=lambda item: item.stat().st_mtime, reverse=True)[:20]:
        try:
            text = load_text(path)
        except Exception:
            continue
        for line in text.splitlines():
            for issue_id, pattern in BROWSER_AGENT_LOG_PATTERNS:
                if not re.search(pattern, line):
                    continue
                timestamp_match = re.search(r'"timestamp":"([^"]+)"', line)
                recent_findings.append(
                    {
                        "issue_id": issue_id,
                        "file": str(path),
                        "timestamp": timestamp_match.group(1) if timestamp_match else "",
                        "excerpt": re.sub(r"\s+", " ", line)[:300],
                    }
                )
    status = "healthy"
    reason = "No recent browser-agent blocker found in scanned session logs."
    finding_ids = {item["issue_id"] for item in recent_findings}
    if "shared_library_signature" in finding_ids:
        status = "blocked_binary_signature"
        reason = "Browser agent is blocked by a Python shared-library signature or compatibility error."
    elif "spawn_eacces" in finding_ids:
        status = "blocked_execution_permission"
        reason = "Browser agent binary exists but cannot be executed cleanly."
    elif "mcp_connection_closed" in finding_ids:
        status = "blocked_mcp_connection"
        reason = "Browser agent starts but the MCP server closes before becoming usable."
    elif not skill_dir.exists():
        status = "missing_skill"
        reason = "autoglm-browser-agent is not present in the managed runtime skill directory."
    elif shutil.which("mcporter") is None:
        status = "missing_mcporter"
        reason = "mcporter is not on PATH, so browser-agent runtime cannot be launched."
    return {
        "generated_at": iso_now(),
        "skill_dir": str(skill_dir),
        "installed": skill_dir.exists(),
        "relay_exists": relay_path.exists(),
        "mcp_server_exists": mcp_server_path.exists(),
        "mcporter_on_path": shutil.which("mcporter") is not None,
        "status": status,
        "reason": reason,
        "recent_findings": recent_findings[:10],
        "repair_actions": [
            "Check whether the packaged browser-agent binary needs re-download or re-signing.",
            "Re-run the browser-agent setup check before treating web execution as available.",
            "Do not count open-link fallback as browser-agent recovery.",
        ],
    }


def render_browser_agent_diagnosis(diagnosis: dict[str, Any]) -> str:
    rows = [
        ["installed", str(bool(diagnosis.get("installed")))],
        ["relay_exists", str(bool(diagnosis.get("relay_exists")))],
        ["mcp_server_exists", str(bool(diagnosis.get("mcp_server_exists")))],
        ["mcporter_on_path", str(bool(diagnosis.get("mcporter_on_path")))],
        ["status", str(diagnosis.get("status") or "unknown")],
    ]
    finding_rows = [
        [item.get("issue_id", ""), item.get("timestamp", ""), item.get("file", "")]
        for item in diagnosis.get("recent_findings", [])
    ]
    lines = [
        "# Browser Agent 故障诊断",
        "",
        f"- generated_at: `{diagnosis['generated_at']}`",
        f"- skill_dir: `{diagnosis['skill_dir']}`",
        f"- status: `{diagnosis['status']}`",
        f"- reason: {diagnosis['reason']}",
        "",
        render_markdown_table(["check", "value"], rows),
        "",
        "## Recent Findings",
        "",
        render_markdown_table(["issue", "timestamp", "file"], finding_rows),
        "",
        "## Repair Actions",
        "",
    ]
    lines.extend(f"- {item}" for item in normalize_list(diagnosis.get("repair_actions")))
    lines.append("")
    return "\n".join(lines)


def build_autoclaw_self_use_tracker(start_date: str | None = None) -> dict[str, Any]:
    start_dt = parse_datetime(start_date or iso_now())
    days = []
    for index in range(7):
        day_dt = start_dt + timedelta(days=index)
        days.append(
            {
                "day": index + 1,
                "date": day_dt.strftime("%Y-%m-%d"),
                "active_calls": 0,
                "misfires": 0,
                "missed_calls": 0,
                "skill_conflicts": 0,
                "chain_outcome": "",
                "checked_scenarios": [],
                "notes": "",
            }
        )
    return {
        "generated_at": iso_now(),
        "start_date": days[0]["date"],
        "end_date": days[-1]["date"],
        "thresholds": {
            "active_gt_misfire": True,
            "stable_short_chain_days_min": 3,
            "conflict_reduction": "last_three_avg < first_three_avg",
        },
        "scenarios": AUTOCLAW_EVAL_SCENARIOS,
        "days": days,
    }


def render_autoclaw_self_use_tracker_markdown(tracker: dict[str, Any]) -> str:
    rows = [
        [
            str(item["day"]),
            item["date"],
            str(item["active_calls"]),
            str(item["misfires"]),
            str(item["missed_calls"]),
            str(item["skill_conflicts"]),
            item.get("chain_outcome") or "",
            ", ".join(normalize_list(item.get("checked_scenarios"))),
        ]
        for item in tracker.get("days", [])
    ]
    lines = [
        "# AutoClaw 7 天自用追踪",
        "",
        f"- start_date: `{tracker.get('start_date') or ''}`",
        f"- end_date: `{tracker.get('end_date') or ''}`",
        "",
        render_markdown_table(
            ["day", "date", "active", "misfire", "missed", "conflicts", "chain", "scenarios"],
            rows,
        ),
        "",
        "## 判定门槛",
        "",
        "- 主动唤起次数总和 > 误唤起次数总和",
        "- 至少 3 天 `chain_outcome=shorter`",
        "- 后 3 天冲突均值 < 前 3 天冲突均值",
        "",
    ]
    return "\n".join(lines)


def render_autoclaw_self_use_tracker_csv(tracker: dict[str, Any]) -> str:
    lines = ["day,date,active_calls,misfires,missed_calls,skill_conflicts,chain_outcome,checked_scenarios,notes"]
    for item in tracker.get("days", []):
        row = [
            str(item["day"]),
            item["date"],
            str(item["active_calls"]),
            str(item["misfires"]),
            str(item["missed_calls"]),
            str(item["skill_conflicts"]),
            (item.get("chain_outcome") or "").replace(",", " "),
            "|".join(normalize_list(item.get("checked_scenarios"))).replace(",", " "),
            str(item.get("notes") or "").replace(",", " "),
        ]
        lines.append(",".join(row))
    return "\n".join(lines) + "\n"


def review_autoclaw_self_use_tracker(tracker: dict[str, Any]) -> dict[str, Any]:
    days = [item for item in tracker.get("days", []) if isinstance(item, dict)]
    active_total = sum(int(item.get("active_calls") or 0) for item in days)
    misfire_total = sum(int(item.get("misfires") or 0) for item in days)
    conflict_series = [int(item.get("skill_conflicts") or 0) for item in days]
    shorter_days = sum(1 for item in days if str(item.get("chain_outcome") or "").strip() == "shorter")
    first_three = conflict_series[:3]
    last_three = conflict_series[-3:] if len(conflict_series) >= 3 else conflict_series
    first_avg = round(sum(first_three) / len(first_three), 2) if first_three else 0.0
    last_avg = round(sum(last_three) / len(last_three), 2) if last_three else 0.0
    passed = active_total > misfire_total and shorter_days >= 3 and last_avg < first_avg
    return {
        "generated_at": iso_now(),
        "active_total": active_total,
        "misfire_total": misfire_total,
        "missed_total": sum(int(item.get("missed_calls") or 0) for item in days),
        "conflict_total": sum(conflict_series),
        "shorter_days": shorter_days,
        "first_three_conflict_avg": first_avg,
        "last_three_conflict_avg": last_avg,
        "passed": passed,
        "next_stage": "进入第二阶段：修执行层故障、再扩条件启用集。" if passed else "继续收缩，不扩 skill。",
    }


