def satellite_session_lane_status_path(run_dir: Path, lane: str) -> Path:
    return run_dir / f"lane-{normalize_slug_part(lane)}.json"


def satellite_session_local_bundle_dir(run_dir: Path, lane: str) -> Path:
    return ensure_dir(run_dir / "remote-lanes" / normalize_slug_part(lane))


def satellite_session_shell_result(
    *,
    lane: str,
    command_text: str,
    command_result: dict[str, Any],
) -> dict[str, Any]:
    status = "completed" if int(command_result.get("returncode", 1)) == 0 else "blocked_system"
    blocking_reason = "" if status == "completed" else truncate_text(
        str(command_result.get("stderr") or command_result.get("stdout") or "lane_command_failed").strip(),
        240,
    )
    return {
        "lane": lane,
        "status": status,
        "did_what": (
            f"Executed `{command_text}` and captured the command evidence for this lane."
            if status == "completed"
            else f"Attempted `{command_text}` but the command failed."
        ),
        "evidence_ref": ["command-result.json"],
        "blocking_reason": blocking_reason,
        "next_action": (
            ""
            if status == "completed"
            else "Inspect command-result.json, fix the remote blocker, and resume the session lane."
        ),
        "changed_files": [],
        "commands_run": [command_text],
    }


def satellite_session_codex_exec_failure_result(
    *,
    lane: str,
    exec_result: dict[str, Any],
) -> dict[str, Any]:
    raw_text = "\n".join(
        part.strip()
        for part in [
            str(exec_result.get("stderr") or ""),
            str(exec_result.get("stdout") or ""),
        ]
        if str(part or "").strip()
    ).strip()
    normalized = normalize_prompt(raw_text)
    quota_markers = [
        "usage limit",
        "upgrade to pro",
        "purchase more credits",
        "chatgpt.com/codex/settings/usage",
        "try again at",
    ]
    if any(marker in normalized for marker in quota_markers):
        return {
            "lane": lane,
            "status": "blocked_needs_user",
            "did_what": "Attempted to start the remote Codex worker, but the black-machine local Codex profile fell back to a quota-limited usage surface instead of the intended local API path.",
            "evidence_ref": ["codex-exec-result.json"],
            "blocking_reason": "remote_codex_local_quota_or_api_profile_required",
            "next_action": "On the black satellite, switch Codex CLI back to the intended local API/provider profile, then rerun this lane.",
            "changed_files": [],
            "commands_run": [],
        }
    auth_markers = [
        "401 unauthorized",
        "missing bearer",
        "basic authentication",
        "authentication in header",
        "authentication header",
        "api key",
        "apikey",
        "not logged in",
        "log in",
        "sign in",
        "auth.json",
        "config.toml",
        "keychain lookup failed",
        "errkcinteractionnotallowed",
        "errsecinteractionnotallowed",
        "interaction is not allowed with the security server",
        "interaction is not allowed with the security server.",
        "security server",
        "local login",
    ]
    if any(marker in normalized for marker in auth_markers):
        return {
            "lane": lane,
            "status": "blocked_needs_user",
            "did_what": "Attempted to start the remote Codex worker, but the black-machine local Codex auth/profile is not yet usable from this SSH session.",
            "evidence_ref": ["codex-exec-result.json"],
            "blocking_reason": "remote_codex_local_auth_required",
            "next_action": "On the black satellite, complete local Codex login or local API-key setup under the GUI user profile, then rerun this lane.",
            "changed_files": [],
            "commands_run": [],
        }
    missing_result_markers = [
        "no last agent message",
        "wrote empty content",
        "completed without a structured result",
        "structured output was not valid json",
        "structured result",
    ]
    if any(marker in normalized for marker in missing_result_markers):
        return {
            "lane": lane,
            "status": "blocked_system",
            "did_what": "Attempted to start the remote Codex worker, but it exited without writing the required structured readiness note.",
            "evidence_ref": ["codex-exec-result.json"],
            "blocking_reason": "remote_codex_structured_note_missing",
            "next_action": "Inspect codex-exec-result.json and rerun this lane after the black satellite can emit one valid JSON note.",
            "changed_files": [],
            "commands_run": [],
        }
    return {
        "lane": lane,
        "status": "blocked_system",
        "did_what": "Attempted to start the remote Codex worker, but it failed before returning a structured readiness note.",
        "evidence_ref": ["codex-exec-result.json"],
        "blocking_reason": truncate_text(raw_text or "codex_exec_failed", 240),
        "next_action": "Inspect codex-exec-result.json and rerun this lane after fixing the remote blocker.",
        "changed_files": [],
        "commands_run": [],
    }


def satellite_session_prepare_codex_home(
    *,
    execution_surface: str,
    default_codex_home: Path,
    worker_codex_home: Path,
) -> dict[str, Any]:
    if execution_surface == "gui_terminal":
        return {
            "effective_codex_home": str(default_codex_home.resolve()),
            "copied_codex_home_files": [],
            "auth_sanitization": {
                "applied": False,
                "reason": "reuse_local_gui_profile",
            },
        }

    ensure_dir(worker_codex_home)
    copied_codex_home_files: list[str] = []
    auth_sanitization: dict[str, Any] = {}
    auth_path = default_codex_home / "auth.json"
    if auth_path.exists():
        auth_payload = load_optional_json(auth_path)
        if isinstance(auth_payload, dict):
            worker_auth_payload = dict(auth_payload)
            auth_mode = str(worker_auth_payload.get("auth_mode") or "").strip().lower()
            api_key = str(worker_auth_payload.get("OPENAI_API_KEY") or "").strip()
            tokens = worker_auth_payload.get("tokens")
            if auth_mode == "apikey" and api_key.startswith("sk-or-") and isinstance(tokens, dict) and tokens:
                worker_auth_payload.pop("OPENAI_API_KEY", None)
                worker_auth_payload["auth_mode"] = "chatgpt"
                auth_sanitization = {
                    "applied": True,
                    "reason": "openrouter_api_key_conflicts_with_default_openai_worker",
                    "original_auth_mode": auth_mode,
                    "new_auth_mode": "chatgpt",
                    "removed_openai_api_key": True,
                }
            write_json(worker_codex_home / "auth.json", worker_auth_payload)
        else:
            shutil.copy2(auth_path, worker_codex_home / "auth.json")
        copied_codex_home_files.append("auth.json")
    return {
        "effective_codex_home": str(worker_codex_home.resolve()),
        "copied_codex_home_files": copied_codex_home_files,
        "auth_sanitization": auth_sanitization,
    }


def satellite_session_dispatch_lane(
    *,
    remote_info: dict[str, Any],
    run_dir: Path,
    session_run_id: str,
    created_at: str,
    run_mode: str,
    lane_spec: dict[str, Any],
    timeout: int,
) -> dict[str, Any]:
    lane = str(lane_spec.get("lane") or "").strip()
    lane_run_id = f"{session_run_id}-{lane}"
    lane_command = str(lane_spec.get("lane_command") or "").strip()
    probe = remote_info.get("probe") if isinstance(remote_info.get("probe"), dict) else {}
    codex_execution_surface = str(lane_spec.get("codex_execution_surface") or "").strip()
    if not codex_execution_surface and not lane_command and str(probe.get("client_mode") or "") == "vscode-agent":
        codex_execution_surface = "gui_terminal"
    argv = [
        "satellite-session-lane",
        "--session-run-id",
        session_run_id,
        "--lane",
        lane,
        "--task",
        str(lane_spec.get("task_text") or ""),
        "--run-id",
        lane_run_id,
        "--created-at",
        created_at,
        "--run-mode",
        run_mode,
    ]
    if lane_command:
        argv.extend(["--lane-command", lane_command])
    if not lane_command and codex_execution_surface:
        argv.extend(["--codex-execution-surface", codex_execution_surface])
    remote_result = tool_glue_run_remote_ai_da_guan_jia(remote_info, argv, timeout=timeout)
    parsed = tool_glue_parse_json_from_output(
        "\n".join(
            [
                str(remote_result.get("stdout") or "").strip(),
                str(remote_result.get("stderr") or "").strip(),
            ]
        )
    )
    should_export = True
    if not isinstance(parsed, dict):
        command_error = truncate_text(
            str(remote_result.get("stderr") or remote_result.get("stdout") or "remote_lane_output_parse_failed").strip(),
            240,
        )
        parsed = {
            "lane": lane,
            "status": "blocked_system" if int(remote_result.get("returncode", 1)) != 0 else "failed_partial",
            "did_what": "",
            "evidence_ref": [],
            "blocking_reason": command_error,
            "next_action": (
                "Inspect the remote stdout/stderr and rerun the lane after fixing the SSH/remote command blocker."
                if int(remote_result.get("returncode", 1)) != 0
                else "Inspect the remote stdout/stderr and rerun the lane after fixing the output contract."
            ),
            "changed_files": [],
            "commands_run": [lane_command] if lane_command else [],
            "remote_run_dir": "",
        }
        should_export = int(remote_result.get("returncode", 1)) == 0
    parsed["lane"] = lane
    parsed.setdefault("remote_run_dir", "")
    parsed.setdefault("did_what", "")
    parsed.setdefault("evidence_ref", [])
    parsed.setdefault("blocking_reason", "")
    parsed.setdefault("next_action", "")
    parsed.setdefault("changed_files", [])
    parsed.setdefault("commands_run", [lane_command] if lane_command else [])

    local_bundle_dir = satellite_session_local_bundle_dir(run_dir, lane)
    restored_files: list[str] = []
    export_summary: dict[str, Any] = {
        "lane": lane,
        "status": "skipped_due_to_remote_failure",
        "missing_files": [],
        "restored_files": restored_files,
        "local_bundle_dir": str(local_bundle_dir.resolve()),
        "remote_run_id": lane_run_id,
        "remote_run_dir": str(parsed.get("remote_run_dir") or ""),
    }
    if should_export:
        export_payload = tool_glue_export_remote_run_files(
            remote_info,
            run_id=lane_run_id,
            created_at=created_at,
            include_files=SATELLITE_SESSION_EXPORT_FILES,
        )
        export_summary["status"] = str(export_payload.get("status") or "")
        export_summary["missing_files"] = normalize_list(export_payload.get("missing_files"))
        if str(export_payload.get("status") or "") == "completed":
            restored_files = tool_glue_write_exported_run_files(local_bundle_dir, export_payload)
            export_summary["restored_files"] = restored_files
        else:
            if str(parsed.get("status") or "") == "completed":
                parsed["status"] = "failed_partial"
                parsed["blocking_reason"] = "remote_export_failed"
                parsed["next_action"] = "Re-export the remote lane bundle before treating this lane as verified."
            export_summary["blocking_reason"] = str(export_payload.get("blocking_reason") or "remote_export_failed")
    else:
        export_summary["blocking_reason"] = "remote_lane_not_executed"
    lane_payload = {
        "lane": lane,
        "manifest": {
            **lane_spec,
            "remote_run_id": lane_run_id,
            "created_at": created_at,
            "run_mode": run_mode,
            "execution_mode": "shell_command" if lane_command else str(lane_spec.get("default_execution") or "codex_exec"),
            "codex_execution_surface": codex_execution_surface or "headless",
        },
        "status": str(parsed.get("status") or "failed_partial"),
        "did_what": str(parsed.get("did_what") or ""),
        "evidence_ref": normalize_list(parsed.get("evidence_ref")),
        "blocking_reason": str(parsed.get("blocking_reason") or ""),
        "next_action": str(parsed.get("next_action") or ""),
        "changed_files": normalize_list(parsed.get("changed_files")),
        "commands_run": normalize_list(parsed.get("commands_run")),
        "remote_run_dir": str(parsed.get("remote_run_dir") or ""),
        "remote_result": remote_result,
        "export": export_summary,
    }
    write_json(satellite_session_lane_status_path(run_dir, lane), lane_payload)
    return lane_payload


def command_satellite_session_lane(args: argparse.Namespace) -> int:
    created_at = str(getattr(args, "created_at", None) or iso_now())
    run_id = str(getattr(args, "run_id", None) or allocate_run_id(created_at)).strip()
    run_dir = run_dir_for(run_id, created_at)
    lane = str(getattr(args, "lane", "") or "").strip()
    session_run_id = str(getattr(args, "session_run_id", "") or "").strip()
    task_text = str(getattr(args, "task", "") or "").strip()
    run_mode = str(getattr(args, "run_mode", "") or SATELLITE_SESSION_RUN_MODE_CHOICES[0]).strip()
    lane_command = str(getattr(args, "lane_command", "") or "").strip() or satellite_session_default_lane_command(lane)
    codex_execution_surface = str(getattr(args, "codex_execution_surface", "") or "headless").strip() or "headless"
    contract = satellite_session_lane_contract(lane)
    route_payload = {
        "run_id": run_id,
        "created_at": created_at,
        "run_kind": "satellite_session_lane",
        "task_text": task_text,
        "workflow_id": SATELLITE_SESSION_WORKFLOW_ID,
        "experiment_id": SATELLITE_SESSION_EXPERIMENT_ID,
        "human_boundary": "This remote lane may execute locally, but it must not perform final mirror/apply/publish/close-task actions.",
        "verification_targets": SATELLITE_SESSION_EXPORT_FILES,
        "satellite_session_lane": {
            "session_run_id": session_run_id,
            "lane": lane,
            "run_mode": run_mode,
            "lane_command": lane_command,
            "codex_execution_surface": codex_execution_surface,
            "purpose": str(contract.get("purpose") or ""),
        },
    }
    write_json(run_dir / "route.json", route_payload)
    manifest = {
        "session_run_id": session_run_id,
        "lane": lane,
        "title": str(contract.get("title") or lane),
        "purpose": str(contract.get("purpose") or ""),
        "default_execution": str(contract.get("default_execution") or ""),
        "lane_command": lane_command,
        "codex_execution_surface": codex_execution_surface,
        "run_mode": run_mode,
        "restrictions": normalize_list(contract.get("restrictions")),
    }
    write_json(run_dir / "lane-manifest.json", manifest)

    result_payload: dict[str, Any]
    if lane_command:
        command_result = run_command_capture(
            ["/bin/zsh", "-lc", lane_command],
            cwd=PROJECT_ROOT,
            timeout=int(getattr(args, "lane_timeout", 0) or SATELLITE_SESSION_DEFAULT_TIMEOUT),
        )
        write_json(run_dir / "command-result.json", command_result)
        result_payload = satellite_session_shell_result(
            lane=lane,
            command_text=lane_command,
            command_result=command_result,
        )
    else:
        prompt = satellite_session_lane_prompt(
            lane=lane,
            task_text=task_text,
            session_run_id=session_run_id,
            run_mode=run_mode,
            lane_command=lane_command,
        )
        exec_result = satellite_session_run_codex_exec_json(
            prompt,
            satellite_session_codex_schema(),
            cwd=PROJECT_ROOT,
            sandbox="workspace-write",
            timeout=int(getattr(args, "lane_timeout", 0) or SATELLITE_SESSION_DEFAULT_TIMEOUT),
            execution_surface=codex_execution_surface,
        )
        write_json(run_dir / "codex-exec-result.json", exec_result)
        parsed = exec_result.get("json") if isinstance(exec_result.get("json"), dict) else {}
        if int(exec_result.get("returncode", 1)) == 0 and isinstance(parsed, dict):
            result_payload = {
                "lane": lane,
                "status": str(parsed.get("status") or "failed_partial"),
                "did_what": str(parsed.get("did_what") or ""),
                "evidence_ref": normalize_list(parsed.get("evidence_ref")),
                "blocking_reason": str(parsed.get("blocking_reason") or ""),
                "next_action": str(parsed.get("next_action") or ""),
                "changed_files": normalize_list(parsed.get("changed_files")),
                "commands_run": normalize_list(parsed.get("commands_run")),
            }
        else:
            result_payload = satellite_session_codex_exec_failure_result(
                lane=lane,
                exec_result=exec_result,
            )

    result_payload["remote_run_dir"] = str(run_dir.resolve())
    write_json(run_dir / "lane-result.json", result_payload)
    worklog = {
        "run_id": run_id,
        "created_at": created_at,
        "run_kind": "satellite_session_lane",
        "session_run_id": session_run_id,
        "lane": lane,
        "status": str(result_payload.get("status") or ""),
        "did_what": str(result_payload.get("did_what") or ""),
        "blocking_reason": str(result_payload.get("blocking_reason") or ""),
        "next_action": str(result_payload.get("next_action") or ""),
        "evidence_ref": normalize_list(result_payload.get("evidence_ref")),
        "changed_files": normalize_list(result_payload.get("changed_files")),
        "commands_run": normalize_list(result_payload.get("commands_run")),
        "remote_run_dir": str(run_dir.resolve()),
    }
    write_json(run_dir / "worklog.json", worklog)
    summary_text = satellite_session_render_lane_summary(manifest, result_payload)
    (run_dir / "lane-summary.md").write_text(summary_text, encoding="utf-8")
    (run_dir / "worklog.md").write_text(summary_text, encoding="utf-8")

    print(json.dumps(result_payload, ensure_ascii=False))
    return 0 if str(result_payload.get("status") or "") in {"completed", "failed_partial", "blocked_needs_user"} else 1


def command_satellite_session(args: argparse.Namespace) -> int:
    resume_session = str(getattr(args, "resume_session", "") or "").strip()
    run_mode = str(getattr(args, "run_mode", "") or SATELLITE_SESSION_RUN_MODE_CHOICES[0]).strip() or SATELLITE_SESSION_RUN_MODE_CHOICES[0]
    lane_launch_mode = str(getattr(args, "lane_launch_mode", "") or "").strip()
    lane_count = int(getattr(args, "lane_count", SATELLITE_SESSION_DEFAULT_LANE_COUNT) or SATELLITE_SESSION_DEFAULT_LANE_COUNT)
    if lane_count != SATELLITE_SESSION_DEFAULT_LANE_COUNT:
        raise ValueError("satellite-session v1 requires --lane-count 3")
    if run_mode not in SATELLITE_SESSION_RUN_MODE_CHOICES:
        raise ValueError(f"unsupported --run-mode: {run_mode}")
    if lane_launch_mode and lane_launch_mode not in SATELLITE_SESSION_LAUNCH_MODE_CHOICES:
        raise ValueError(f"unsupported --lane-launch-mode: {lane_launch_mode}")

    if resume_session:
        run_dir = find_run_dir(resume_session)
        route_payload = load_optional_json(run_dir / "route.json")
        if not route_payload:
            raise FileNotFoundError(f"missing route.json for session {resume_session}")
        plan_payload = load_optional_json(run_dir / "satellite-session-plan.json")
        created_at = str(route_payload.get("created_at") or iso_now())
        run_id = str(route_payload.get("run_id") or resume_session)
        task_text = str(route_payload.get("task_text") or "").strip()
        requested_alias = str(
            getattr(args, "alias", "") or route_payload.get("satellite_session", {}).get("requested_alias") or SATELLITE_SESSION_DEFAULT_ALIAS
        ).strip()
        lane_launch_mode = (
            lane_launch_mode
            or str(plan_payload.get("lane_launch_mode") or route_payload.get("satellite_session", {}).get("lane_launch_mode") or "parallel").strip()
        )
        selected_lanes = satellite_session_selected_lanes(
            getattr(args, "selected_lanes", "") or plan_payload.get("selected_lanes") or route_payload.get("satellite_session", {}).get("selected_lanes", [])
        )
        lane_specs = plan_payload.get("lanes", []) if isinstance(plan_payload.get("lanes"), list) else route_payload.get("satellite_session", {}).get("lanes", [])
        lane_specs = [dict(item) for item in lane_specs if isinstance(item, dict) and str(item.get("lane") or "") in selected_lanes]
        existing_lane_payloads = {
            lane: load_optional_json(satellite_session_lane_status_path(run_dir, lane))
            for lane in selected_lanes
        }
    else:
        created_at = str(getattr(args, "created_at", None) or iso_now())
        run_id = str(getattr(args, "run_id", None) or allocate_run_id(created_at)).strip()
        run_dir = run_dir_for(run_id, created_at)
        task_text = str(getattr(args, "task", "") or "").strip()
        if not task_text:
            raise ValueError("--task is required unless --resume-session is used")
        requested_alias = str(getattr(args, "alias", "") or SATELLITE_SESSION_DEFAULT_ALIAS).strip() or SATELLITE_SESSION_DEFAULT_ALIAS
        lane_launch_mode = lane_launch_mode or "parallel"
        selected_lanes = satellite_session_selected_lanes(getattr(args, "selected_lanes", ""))
        lane_specs = satellite_session_build_lane_specs(
            task_text=task_text,
            main_command=str(getattr(args, "main_command", "") or ""),
            support_command=str(getattr(args, "support_command", "") or ""),
            verify_command=str(getattr(args, "verify_command", "") or ""),
            selected_lanes=selected_lanes,
        )
        existing_lane_payloads = {}

    resolution = resolve_satellite_assignment(requested_alias)
    source_id = str(resolution.get("resolved_source_id") or "").strip()
    source_row = tool_glue_connected_source_row(source_id) if source_id else {}
    remote_info = tool_glue_remote_host_metadata(source_id) if source_id else {}
    if lane_launch_mode not in SATELLITE_SESSION_LAUNCH_MODE_CHOICES:
        raise ValueError(f"unsupported --lane-launch-mode: {lane_launch_mode}")
    if satellite_session_prefers_staggered_launch(task_text, selected_lanes):
        lane_launch_mode = "staggered"
    elif satellite_session_requires_serialized_gui_codex(lane_specs, remote_info=remote_info):
        lane_launch_mode = "staggered"
    preflight = satellite_session_preflight(
        alias=requested_alias,
        lane_count=lane_count,
        run_mode=run_mode,
        resolution=resolution,
        source_row=source_row,
        remote_info=remote_info,
    )
    route_payload = satellite_session_route_payload(
        run_id=run_id,
        created_at=created_at,
        task_text=task_text,
        requested_alias=requested_alias,
        resolution=resolution,
        lane_specs=[dict(item) for item in lane_specs if isinstance(item, dict)],
        run_mode=run_mode,
        lane_count=lane_count,
        lane_launch_mode=lane_launch_mode,
    )
    write_json(run_dir / "route.json", route_payload)
    plan_payload = {
        "run_id": run_id,
        "created_at": created_at,
        "requested_alias": requested_alias,
        "resolved_satellite_id": str(resolution.get("resolved_satellite_id") or ""),
        "resolved_source_id": source_id,
        "dispatch_mode": str(resolution.get("dispatch_mode") or ""),
        "run_mode": run_mode,
        "lane_count": lane_count,
        "lane_launch_mode": lane_launch_mode,
        "selected_lanes": selected_lanes,
        "lanes": [dict(item) for item in lane_specs if isinstance(item, dict)],
        "resume_session": resume_session,
        "closure_owner": "main-hub",
    }
    write_json(run_dir / "satellite-session-plan.json", plan_payload)
    write_json(run_dir / "satellite-session-preflight.json", preflight)

    lane_payloads_by_lane = {lane: payload for lane, payload in existing_lane_payloads.items() if payload}
    lanes_to_dispatch = []
    for item in lane_specs:
        if not isinstance(item, dict):
            continue
        lane = str(item.get("lane") or "").strip()
        existing = lane_payloads_by_lane.get(lane, {})
        existing_status = str(existing.get("status") or "")
        if existing_status == "completed":
            continue
        lanes_to_dispatch.append(dict(item))

    if str(preflight.get("status") or "") == "completed" and lanes_to_dispatch:
        timeout = int(getattr(args, "lane_timeout", 0) or SATELLITE_SESSION_DEFAULT_TIMEOUT)
        if lane_launch_mode == "staggered":
            for lane_spec in lanes_to_dispatch:
                lane_payload = satellite_session_dispatch_lane(
                    remote_info=remote_info,
                    run_dir=run_dir,
                    session_run_id=run_id,
                    created_at=created_at,
                    run_mode=run_mode,
                    lane_spec=lane_spec,
                    timeout=timeout,
                )
                lane_payloads_by_lane[str(lane_payload.get("lane") or lane_spec.get("lane") or "")] = lane_payload
        else:
            with ThreadPoolExecutor(max_workers=len(lanes_to_dispatch)) as pool:
                futures = {
                    pool.submit(
                        satellite_session_dispatch_lane,
                        remote_info=remote_info,
                        run_dir=run_dir,
                        session_run_id=run_id,
                        created_at=created_at,
                        run_mode=run_mode,
                        lane_spec=lane_spec,
                        timeout=timeout,
                    ): str(lane_spec.get("lane") or "")
                    for lane_spec in lanes_to_dispatch
                }
                for future in as_completed(futures):
                    lane_payload = future.result()
                    lane_payloads_by_lane[str(lane_payload.get("lane") or futures[future])] = lane_payload

    ordered_lane_payloads = [
        lane_payloads_by_lane.get(lane, {"lane": lane, "status": "failed_partial", "did_what": "", "blocking_reason": "lane_not_started", "next_action": "", "remote_run_dir": ""})
        for lane in selected_lanes
    ]
    exported_refs = [
        payload.get("export", {})
        for payload in ordered_lane_payloads
        if isinstance(payload, dict) and isinstance(payload.get("export"), dict)
    ]
    write_json(run_dir / "exported-remote-bundles.json", {"items": exported_refs})
    overall_status = satellite_session_status_from_lanes(
        str(preflight.get("status") or ""),
        ordered_lane_payloads,
    )
    recap_payload = {
        "run_id": run_id,
        "created_at": created_at,
        "requested_alias": requested_alias,
        "resolved_source_id": source_id,
        "overall_status": overall_status,
        "preflight": preflight,
        "lanes": ordered_lane_payloads,
        "exported_remote_bundles": exported_refs,
    }
    write_json(run_dir / "satellite-session-recap.json", recap_payload)
    recap_text = satellite_session_render_recap(
        run_id=run_id,
        task_text=task_text,
        requested_alias=requested_alias,
        source_id=source_id,
        overall_status=overall_status,
        preflight=preflight,
        lane_results=ordered_lane_payloads,
    )
    (run_dir / "satellite-session-recap.md").write_text(recap_text + "\n", encoding="utf-8")
    worklog = {
        "run_id": run_id,
        "created_at": created_at,
        "run_kind": "satellite_session",
        "closure_state": overall_status,
        "requested_alias": requested_alias,
        "resolved_source_id": source_id,
        "preflight": preflight,
        "lane_results": ordered_lane_payloads,
        "exported_remote_bundles": exported_refs,
        "open_questions": [
            f"{item.get('lane', '')}: {item.get('blocking_reason', '')}"
            for item in ordered_lane_payloads
            if str(item.get("blocking_reason") or "").strip()
        ],
        "next_actions": [
            f"{item.get('lane', '')}: {item.get('next_action', '')}"
            for item in ordered_lane_payloads
            if str(item.get("next_action") or "").strip()
        ],
    }
    write_json(run_dir / "worklog.json", worklog)
    (run_dir / "worklog.md").write_text(recap_text + "\n", encoding="utf-8")

    print(f"run_id: {run_id}")
    print(f"run_dir: {run_dir}")
    print(f"requested_alias: {requested_alias}")
    print(f"resolved_source_id: {source_id or 'none'}")
    print(f"overall_status: {overall_status}")
    print(f"lanes_dispatched: {len(lanes_to_dispatch) if str(preflight.get('status') or '') == 'completed' else 0}")
    print(f"recap_path: {run_dir / 'satellite-session-recap.md'}")
    return 0 if overall_status in {"completed", "failed_partial", "blocked_needs_user"} else 1


def satellite_multimodel_resolve_force_model(value: str) -> str:
    normalized = normalize_prompt(value)
    compact = re.sub(r"[\s_]+", "", normalized)
    if normalized in SATELLITE_MULTIMODEL_FORCE_MODEL_ALIASES:
        return SATELLITE_MULTIMODEL_FORCE_MODEL_ALIASES[normalized]
    if compact in SATELLITE_MULTIMODEL_FORCE_MODEL_ALIASES:
        return SATELLITE_MULTIMODEL_FORCE_MODEL_ALIASES[compact]
    return ""


def satellite_multimodel_contains_any(normalized: str, markers: list[str]) -> bool:
    return any(marker in normalized for marker in markers)


def satellite_multimodel_route_task(
    *,
    task_text: str,
    image_path: str,
    need_search: bool,
    need_citations: bool,
    force_model: str,
) -> dict[str, Any]:
    normalized = normalize_prompt(task_text)
    forced_model = satellite_multimodel_resolve_force_model(force_model)
    explicit_search = bool(need_search or need_citations)
    search_markers = [
        "实时搜索",
        "联网搜索",
        "最新资讯",
        "最新消息",
        "latest",
        "search",
        "web search",
        "live search",
        "real-time",
        "实时 x",
        "引用",
        "citations",
        "sources",
    ]
    image_markers = [
        "image",
        "images",
        "photo",
        "picture",
        "screenshot",
        "图片",
        "照片",
        "截图",
        "看图",
        "识图",
        "视觉",
        "多模态",
    ]
    code_math_markers = [
        "code",
        "coding",
        "program",
        "bug",
        "refactor",
        "script",
        "python",
        "javascript",
        "typescript",
        "regex",
        "algorithm",
        "数学",
        "推导",
        "证明",
        "逻辑",
        "算一下",
        "求解",
        "结构化",
        "debug",
    ]
    kimi_markers = [
        "工作流",
        "拆解",
        "步骤",
        "执行计划",
        "agent",
        "代理",
        "协同",
        "中文场景",
        "中文 agent",
        "任务分解",
        "流程设计",
    ]
    claude_markers = [
        "rewrite",
        "editing",
        "essay",
        "long-form",
        "style",
        "voice",
        "narrative",
        "story",
        "长文",
        "改写",
        "润色",
        "文风",
        "写作",
        "文章",
        "叙事",
    ]
    has_chinese = bool(re.search(r"[\u4e00-\u9fff]", task_text))
    search_enabled = explicit_search or satellite_multimodel_contains_any(normalized, search_markers)
    if forced_model:
        selected_model = forced_model
        reason = f"Forced by --force-model={force_model.strip()}."
        route_family = "forced"
    elif image_path.strip() or satellite_multimodel_contains_any(normalized, image_markers):
        selected_model = "gemini25"
        reason = "Detected image or multimodal intent; route to Gemini 2.5 Pro first."
        route_family = "multimodal"
    elif search_enabled:
        selected_model = "gpt54"
        reason = "Detected live-search or citation demand; keep v1 on GPT-5.4 with Codex web search."
        route_family = "search"
    elif satellite_multimodel_contains_any(normalized, code_math_markers):
        selected_model = "gpt54"
        reason = "Detected code, math, logic, or structured-solving intent; route to GPT-5.4."
        route_family = "logic"
    elif has_chinese and satellite_multimodel_contains_any(normalized, kimi_markers):
        selected_model = "kimi"
        reason = "Detected Chinese workflow or agent-style decomposition intent; route to Kimi K2."
        route_family = "chinese_agent"
    elif satellite_multimodel_contains_any(normalized, claude_markers):
        selected_model = "claude4"
        reason = "Detected long-form writing, rewrite, or style-heavy drafting intent; route to Claude Sonnet 4."
        route_family = "writing"
    elif has_chinese:
        selected_model = "kimi"
        reason = "Detected a general Chinese-first task without stronger code or writing markers; route to Kimi K2."
        route_family = "chinese_default"
    else:
        selected_model = "gpt54"
        reason = "No stronger specialist signal detected; default to GPT-5.4."
        route_family = "default"
    config = dict(SATELLITE_MULTIMODEL_MODEL_CONFIG[selected_model])
    return {
        **config,
        "forced_model": forced_model,
        "reason": reason,
        "route_family": route_family,
        "search_enabled": search_enabled,
        "need_citations": bool(need_citations),
        "image_attached": bool(image_path.strip()),
    }


def satellite_multimodel_output_schema() -> dict[str, Any]:
    return {
        "type": "object",
        "additionalProperties": False,
        "properties": {
            "status": {"type": "string", "enum": SATELLITE_MULTIMODEL_STATUS_CHOICES},
            "response_text": {"type": "string"},
            "sources": {"type": "array", "items": {"type": "string"}},
            "blocking_reason": {"type": "string"},
            "next_action": {"type": "string"},
        },
        "required": ["status", "response_text", "sources", "blocking_reason", "next_action"],
    }


def satellite_multimodel_prompt(
    *,
    task_text: str,
    route: dict[str, Any],
    need_citations: bool,
    remote_images: list[str],
) -> str:
    lines = [
        "You are the execution worker for black-satellite-multimodel-router v1.",
        f"Selected model family: {route.get('label', route.get('model_id', 'unknown'))}",
        f"Routing reason: {route.get('reason', '')}",
        "",
        "Your job is to answer the user's task directly and truthfully.",
        "Return only structured JSON that matches the provided schema.",
        "",
        "Task:",
        task_text.strip(),
        "",
        "Hard rules:",
        "- If you can answer the task, set `status` to `completed` and put the full human-readable answer in `response_text`.",
        "- If the task is only partially solved but still useful, set `status` to `failed_partial` and explain the exact remaining gap in `next_action`.",
        "- If the task requires the human to intervene, set `status` to `blocked_needs_user` and name the exact blocker in `blocking_reason`.",
        "- If a system or tooling problem blocks completion, set `status` to `blocked_system` and name the blocker exactly.",
        "- Keep `sources` empty unless live search or citations were explicitly requested.",
        "- Do not wrap JSON in markdown fences.",
    ]
    if route.get("search_enabled"):
        lines.extend(
            [
                "",
                "Live web search is enabled for this run.",
                "- Use it when needed.",
                "- If you rely on web facts, include direct links in `sources`.",
            ]
        )
    if need_citations and not route.get("search_enabled"):
        lines.extend(
            [
                "",
                "Citations were requested but live search is not enabled for this run.",
                "- Only cite sources you can actually verify from the available execution surface.",
            ]
        )
    if remote_images:
        lines.extend(
            [
                "",
                "Attached remote image paths:",
                *[f"- {item}" for item in remote_images],
            ]
        )
    return "\n".join(lines).strip() + "\n"


def satellite_multimodel_remote_command(
    remote_info: dict[str, Any],
    argv: list[str],
    *,
    timeout: int = 120,
    input_text: str | None = None,
) -> dict[str, Any]:
    target = tool_glue_remote_target(remote_info)
    if not target:
        return {
            "command": [],
            "returncode": 1,
            "stdout": "",
            "stderr": "missing remote host target",
            "timed_out": False,
        }
    command = [
        str(SSH_WITH_CODEX_IDENTITIES),
        "-o",
        "BatchMode=yes",
        "-o",
        "ConnectTimeout=8",
        "-o",
        "StrictHostKeyChecking=accept-new",
        target,
        *argv,
    ]
    return run_command_capture(command, cwd=PROJECT_ROOT, timeout=timeout, input_text=input_text)


def satellite_multimodel_activate_provider(remote_info: dict[str, Any], model_id: str) -> dict[str, Any]:
    config = SATELLITE_MULTIMODEL_MODEL_CONFIG[model_id]
    remote_script = Path(str(remote_info.get("workspace_root") or "")) / "scripts" / "black_satellite_openrouter_remote.py"
    return satellite_multimodel_remote_command(
        remote_info,
        ["python3", str(remote_script), "model", str(config["provider_alias"])],
        timeout=120,
    )


def satellite_multimodel_probe_gemini_trust(remote_info: dict[str, Any]) -> dict[str, Any]:
    remote_script = Path(str(remote_info.get("workspace_root") or "")) / "scripts" / "black_satellite_openrouter_remote.py"
    return satellite_multimodel_remote_command(
        remote_info,
        ["python3", str(remote_script), "gemini", "--version"],
        timeout=10,
    )


def satellite_multimodel_probe_requires_gemini_trust(result: dict[str, Any]) -> bool:
    raw = "\n".join(
        part.strip()
        for part in [str(result.get("stdout") or ""), str(result.get("stderr") or "")]
        if part and str(part).strip()
    )
    normalized = normalize_prompt(raw)
    return any(marker in normalized for marker in SATELLITE_MULTIMODEL_TRUST_MARKERS)


def satellite_multimodel_map_remote_images(
    image_paths: list[str],
    *,
    remote_workspace_root: str,
) -> tuple[list[str], list[dict[str, str]]]:
    mapped: list[str] = []
    blockers: list[dict[str, str]] = []
    local_workspace_root = str(PROJECT_ROOT.resolve())
    for raw_path in image_paths:
        path = Path(raw_path).expanduser().resolve()
        if not path.exists():
            blockers.append(
                {
                    "path": str(path),
                    "reason": "local_image_missing",
                    "next_action": "Verify the image path exists before rerunning the router.",
                }
            )
            continue
        path_text = str(path)
        if path_text.startswith(local_workspace_root + os.sep) or path_text == local_workspace_root:
            suffix = path_text[len(local_workspace_root) :].lstrip("/")
            mapped.append(str(Path(remote_workspace_root) / suffix))
            continue
        blockers.append(
            {
                "path": path_text,
                "reason": "image_not_in_shared_workspace",
                "next_action": f"Move the image under {local_workspace_root} so the black satellite can read the same path.",
            }
        )
    return mapped, blockers


def satellite_multimodel_run_remote_codex_exec_json(
    remote_info: dict[str, Any],
    *,
    prompt: str,
    schema: dict[str, Any],
    search_enabled: bool,
    remote_images: list[str],
    timeout: int,
) -> dict[str, Any]:
    target = tool_glue_remote_target(remote_info)
    workspace_root = str(remote_info.get("workspace_root") or "").strip()
    if not target or not workspace_root:
        return {
            "command": [],
            "returncode": 1,
            "stdout": "",
            "stderr": "missing remote host target or workspace_root",
            "timed_out": False,
        }
    prompt_b64 = base64.b64encode(prompt.encode("utf-8")).decode("ascii")
    schema_b64 = base64.b64encode(json.dumps(schema, ensure_ascii=False).encode("utf-8")).decode("ascii")
    images_b64 = base64.b64encode(json.dumps(remote_images, ensure_ascii=False).encode("utf-8")).decode("ascii")
    remote_code = "\n".join(
        [
            "import base64",
            "import json",
            "import os",
            "import subprocess",
            "import tempfile",
            "",
            f"workspace_root = {workspace_root!r}",
            f"prompt = base64.b64decode({prompt_b64!r}).decode('utf-8')",
            f"schema = json.loads(base64.b64decode({schema_b64!r}).decode('utf-8'))",
            f"remote_images = json.loads(base64.b64decode({images_b64!r}).decode('utf-8'))",
            f"search_enabled = {bool(search_enabled)!r}",
            f"timeout_seconds = {int(timeout)!r}",
            "env = os.environ.copy()",
            "home = os.path.expanduser('~')",
            "env['PATH'] = ':'.join(part for part in [os.path.join(home, '.local', 'bin'), os.path.join(home, '.npm-global', 'bin'), '/opt/homebrew/bin', env.get('PATH', '')] if part)",
            "temp_root = tempfile.mkdtemp(prefix='satellite-multimodel-')",
            "schema_path = os.path.join(temp_root, 'schema.json')",
            "result_path = os.path.join(temp_root, 'result.json')",
            "with open(schema_path, 'w', encoding='utf-8') as handle:",
            "    json.dump(schema, handle, ensure_ascii=False, indent=2)",
            "command = ['codex']",
            "if search_enabled:",
            "    command.append('--search')",
            "command.append('exec')",
            "for image in remote_images:",
            "    command.extend(['-i', image])",
            "command.extend(['--sandbox', 'workspace-write', '--skip-git-repo-check', '--cd', workspace_root, '--output-schema', schema_path, '--output-last-message', result_path, '-'])",
            "payload = {'command': command}",
            "try:",
            "    completed = subprocess.run(command, input=prompt, text=True, capture_output=True, cwd=workspace_root, env=env, timeout=timeout_seconds)",
            "    payload.update({'returncode': completed.returncode, 'stdout': completed.stdout, 'stderr': completed.stderr})",
            "except subprocess.TimeoutExpired as exc:",
            "    payload.update({'returncode': 124, 'stdout': exc.stdout or '', 'stderr': exc.stderr or '', 'timed_out': True})",
            "if os.path.exists(result_path):",
            "    try:",
            "        with open(result_path, 'r', encoding='utf-8') as handle:",
            "            payload['json'] = json.load(handle)",
            "    except Exception as exc:",
            "        payload['json_error'] = str(exc)",
            "print(json.dumps(payload, ensure_ascii=False))",
        ]
    )
    result = satellite_multimodel_remote_command(
        remote_info,
        ["python3", "-"],
        timeout=timeout + 20,
        input_text=remote_code,
    )
    parsed = tool_glue_parse_json_from_output(
        "\n".join(
            [
                str(result.get("stdout") or "").strip(),
                str(result.get("stderr") or "").strip(),
            ]
        )
    )
    if isinstance(parsed, dict):
        parsed.setdefault("timed_out", bool(result.get("timed_out")))
        return parsed
    return result


def satellite_multimodel_gemini_trust_block(remote_info: dict[str, Any], probe_result: dict[str, Any]) -> dict[str, Any]:
    source_id = str(remote_info.get("source_id") or "")
    return {
        "status": "blocked_needs_user",
        "response_text": "",
        "sources": [],
        "blocking_reason": "remote_gemini_workspace_trust_required",
        "next_action": "Complete the one-time Gemini folder trust on the black satellite, then rerun the same router command.",
        "blocked_needs_user": True,
        "human_action_contract": {
            "go_where": f"黑色卫星 `{source_id or 'satellite-02'}` 的终端里，进入工作区 {remote_info.get('workspace_root') or '(unknown workspace)'}",
            "click_what": "运行 `gemini --version`，在提示页选择 `Trust folder (codex-ai-gua-jia-01)`。",
            "why_human": "这是 Gemini CLI 的一次性本地信任确认，必须由图形会话/真人授权完成。",
            "report_back": "回传看到的最终结果，理想情况下是 Gemini CLI 版本号或 trust 已完成的确认画面。",
        },
        "probe_result": probe_result,
    }


def satellite_multimodel_provider_switch_failure(
    *,
    attempted_model: str,
    attempted_result: dict[str, Any],
    fallback_model: str,
    fallback_result: dict[str, Any],
) -> dict[str, Any]:
    raw_attempt = truncate_text(
        str(attempted_result.get("stderr") or attempted_result.get("stdout") or "provider_switch_failed").strip(),
        240,
    )
    raw_fallback = truncate_text(
        str(fallback_result.get("stderr") or fallback_result.get("stdout") or "fallback_provider_switch_failed").strip(),
        240,
    )
    return {
        "status": "blocked_system",
        "response_text": "",
        "sources": [],
        "blocking_reason": f"provider_switch_failed::{attempted_model}::{raw_attempt} | fallback::{fallback_model}::{raw_fallback}",
        "next_action": "Inspect the remote provider switch outputs and restore one valid OpenRouter provider before rerunning the router.",
        "blocked_needs_user": False,
    }


def satellite_multimodel_codex_failure_payload(exec_result: dict[str, Any]) -> dict[str, Any]:
    classified = satellite_session_codex_exec_failure_result(lane="multimodel", exec_result=exec_result)
    return {
        "status": str(classified.get("status") or "blocked_system"),
        "response_text": "",
        "sources": [],
        "blocking_reason": str(classified.get("blocking_reason") or "remote_codex_exec_failed"),
        "next_action": str(classified.get("next_action") or ""),
        "blocked_needs_user": str(classified.get("status") or "") == "blocked_needs_user",
    }


def satellite_multimodel_render_result_markdown(result: dict[str, Any]) -> str:
    lines = [
        f"# Black Satellite Multimodel Router",
        "",
        f"- status: {result.get('status', '')}",
        f"- requested_model: {result.get('requested_model', '')}",
        f"- selected_model: {result.get('selected_model', '')}",
        f"- search_enabled: {result.get('search_enabled', False)}",
        f"- fallback_used: {result.get('fallback_used', False)}",
        f"- blocked_needs_user: {result.get('blocked_needs_user', False)}",
        "",
    ]
    if str(result.get("response_text") or "").strip():
        lines.extend(["## Response", "", str(result.get("response_text") or "").strip(), ""])
    if str(result.get("blocking_reason") or "").strip():
        lines.extend(["## Blocking Reason", "", str(result.get("blocking_reason") or "").strip(), ""])
    if str(result.get("next_action") or "").strip():
        lines.extend(["## Next Action", "", str(result.get("next_action") or "").strip(), ""])
    return "\n".join(lines).strip() + "\n"


def satellite_multimodel_write_result_bundle(
    *,
    run_dir: Path,
    route_payload: dict[str, Any],
    route_decision: dict[str, Any],
    result_payload: dict[str, Any],
) -> None:
    write_json(run_dir / "route.json", route_payload)
    write_json(run_dir / "router-decision.json", route_decision)
    write_json(run_dir / "router-result.json", result_payload)
    worklog = {
        "run_id": str(route_payload.get("run_id") or ""),
        "created_at": str(route_payload.get("created_at") or ""),
        "run_kind": "satellite_multimodel_router",
        "requested_satellite": str(route_payload.get("satellite_multimodel_router", {}).get("requested_satellite") or ""),
        "resolved_source_id": str(route_payload.get("satellite_multimodel_router", {}).get("resolved_source_id") or ""),
        "status": str(result_payload.get("status") or ""),
        "selected_model": str(result_payload.get("selected_model") or ""),
        "search_enabled": bool(result_payload.get("search_enabled")),
        "fallback_used": bool(result_payload.get("fallback_used")),
        "blocking_reason": str(result_payload.get("blocking_reason") or ""),
        "next_action": str(result_payload.get("next_action") or ""),
        "sources": normalize_list(result_payload.get("sources")),
    }
    write_json(run_dir / "worklog.json", worklog)
    (run_dir / "worklog.md").write_text(satellite_multimodel_render_result_markdown(result_payload), encoding="utf-8")


def command_satellite_multimodel_router(args: argparse.Namespace) -> int:
    created_at = str(getattr(args, "created_at", None) or iso_now())
    run_id = str(getattr(args, "run_id", None) or allocate_run_id(created_at)).strip()
    run_dir = run_dir_for(run_id, created_at)
    requested_satellite = str(getattr(args, "satellite", "") or RDAGENT_FIN_QUANT_DEFAULT_ALIAS).strip() or RDAGENT_FIN_QUANT_DEFAULT_ALIAS
    task_text = str(getattr(args, "task", "") or "").strip()
    if not task_text:
        raise ValueError("--task is required")
    image_paths = normalize_list(getattr(args, "image", []))
    route_decision = satellite_multimodel_route_task(
        task_text=task_text,
        image_path=image_paths[0] if image_paths else "",
        need_search=bool(getattr(args, "need_search", False)),
        need_citations=bool(getattr(args, "need_citations", False)),
        force_model=str(getattr(args, "force_model", "") or ""),
    )
    resolution = resolve_satellite_assignment(requested_satellite)
    source_id = str(resolution.get("resolved_source_id") or "").strip()
    remote_info = tool_glue_remote_host_metadata(source_id) if source_id else {}
    route_payload = {
        "run_id": run_id,
        "created_at": created_at,
        "run_kind": "satellite_multimodel_router",
        "task_text": task_text,
        "workflow_id": SATELLITE_MULTIMODEL_WORKFLOW_ID,
        "human_boundary": "Only interrupt for one-time Gemini workspace trust or irreplaceable local authorization blockers.",
        "satellite_multimodel_router": {
            "requested_satellite": requested_satellite,
            "resolved_source_id": source_id,
            "resolved_satellite_id": str(resolution.get("resolved_satellite_id") or ""),
            "dispatch_mode": str(resolution.get("dispatch_mode") or ""),
            "search_enabled": bool(route_decision.get("search_enabled")),
            "need_citations": bool(route_decision.get("need_citations")),
            "image_count": len(image_paths),
            "requested_force_model": str(getattr(args, "force_model", "") or ""),
        },
        "six_judgments": {
            "自治判断": "AI owns routing, provider switching, execution, and artifact capture; the human only steps in for one-time Gemini trust or external authorization blockers.",
            "全局最优判断": "Use the black satellite terminal path first, because it validates real remote execution faster than building a new frontstage.",
            "能力复用判断": "Reuse existing black satellite SSH and OpenRouter switch scripts instead of introducing a new control plane.",
            "验真判断": "Count only live SSH control, real provider activation output, and real structured Codex exec results.",
            "进化判断": "Persist route reason, actual model used, search flag, fallback use, and human-boundary events for the next iteration.",
            "当前最大失真": "Do not confuse a 7-model ambition with current live readiness; v1 is restricted to GPT-5.4, Claude, Gemini, and Kimi.",
        },
    }

    if not source_id or not remote_info:
        result_payload = {
            "status": "blocked_system",
            "response_text": "",
            "sources": [],
            "blocking_reason": "remote_satellite_unavailable",
            "next_action": f"Verify the requested satellite `{requested_satellite}` resolves to one connected source before rerunning.",
            "selected_model": str(route_decision.get("model_id") or ""),
            "requested_model": str(route_decision.get("model_id") or ""),
            "reason": str(route_decision.get("reason") or ""),
            "search_enabled": bool(route_decision.get("search_enabled")),
            "fallback_used": False,
            "blocked_needs_user": False,
            "run_id": run_id,
            "run_dir": str(run_dir.resolve()),
        }
        satellite_multimodel_write_result_bundle(run_dir=run_dir, route_payload=route_payload, route_decision=route_decision, result_payload=result_payload)
        print(json.dumps(result_payload, ensure_ascii=False, indent=2) if getattr(args, "json", False) else satellite_multimodel_render_result_markdown(result_payload).strip())
        return 1

    mapped_images, image_blockers = satellite_multimodel_map_remote_images(
        image_paths,
        remote_workspace_root=str(remote_info.get("workspace_root") or ""),
    )
    if image_blockers:
        blocker = image_blockers[0]
        result_payload = {
            "status": "blocked_needs_user",
            "response_text": "",
            "sources": [],
            "blocking_reason": str(blocker.get("reason") or "image_path_blocked"),
            "next_action": str(blocker.get("next_action") or ""),
            "selected_model": str(route_decision.get("model_id") or ""),
            "requested_model": str(route_decision.get("model_id") or ""),
            "reason": str(route_decision.get("reason") or ""),
            "search_enabled": bool(route_decision.get("search_enabled")),
            "fallback_used": False,
            "blocked_needs_user": True,
            "run_id": run_id,
            "run_dir": str(run_dir.resolve()),
            "image_blockers": image_blockers,
        }
        satellite_multimodel_write_result_bundle(run_dir=run_dir, route_payload=route_payload, route_decision=route_decision, result_payload=result_payload)
        print(json.dumps(result_payload, ensure_ascii=False, indent=2) if getattr(args, "json", False) else satellite_multimodel_render_result_markdown(result_payload).strip())
        return 0

    if bool(getattr(args, "dry_run", False)):
        result_payload = {
            "status": "completed",
            "response_text": "",
            "sources": [],
            "blocking_reason": "",
            "next_action": "",
            "selected_model": str(route_decision.get("model_id") or ""),
            "requested_model": str(route_decision.get("model_id") or ""),
            "reason": str(route_decision.get("reason") or ""),
            "search_enabled": bool(route_decision.get("search_enabled")),
            "fallback_used": False,
            "blocked_needs_user": False,
            "dry_run": True,
            "run_id": run_id,
            "run_dir": str(run_dir.resolve()),
            "resolved_source_id": source_id,
            "remote_images": mapped_images,
        }
        satellite_multimodel_write_result_bundle(run_dir=run_dir, route_payload=route_payload, route_decision=route_decision, result_payload=result_payload)
        print(json.dumps(result_payload, ensure_ascii=False, indent=2) if getattr(args, "json", False) else satellite_multimodel_render_result_markdown(result_payload).strip())
        return 0

    selected_model = str(route_decision.get("model_id") or "gpt54")
    if selected_model == "gemini25":
        gemini_probe = satellite_multimodel_probe_gemini_trust(remote_info)
        write_json(run_dir / "remote-gemini-trust-probe.json", gemini_probe)
        if satellite_multimodel_probe_requires_gemini_trust(gemini_probe):
            blocked_payload = satellite_multimodel_gemini_trust_block(remote_info, gemini_probe)
            result_payload = {
                **blocked_payload,
                "selected_model": selected_model,
                "requested_model": selected_model,
                "reason": str(route_decision.get("reason") or ""),
                "search_enabled": bool(route_decision.get("search_enabled")),
                "fallback_used": False,
                "run_id": run_id,
                "run_dir": str(run_dir.resolve()),
                "resolved_source_id": source_id,
            }
            satellite_multimodel_write_result_bundle(run_dir=run_dir, route_payload=route_payload, route_decision=route_decision, result_payload=result_payload)
            print(json.dumps(result_payload, ensure_ascii=False, indent=2) if getattr(args, "json", False) else satellite_multimodel_render_result_markdown(result_payload).strip())
            return 0

    primary_switch = satellite_multimodel_activate_provider(remote_info, selected_model)
    write_json(run_dir / "remote-provider-switch-primary.json", primary_switch)
    effective_model = selected_model
    fallback_used = False
    if int(primary_switch.get("returncode", 1)) != 0:
        fallback_model = str(route_decision.get("fallback_model") or "")
        fallback_switch = satellite_multimodel_activate_provider(remote_info, fallback_model) if fallback_model else {"returncode": 1, "stderr": "missing_fallback_model"}
        write_json(run_dir / "remote-provider-switch-fallback.json", fallback_switch)
        if fallback_model and int(fallback_switch.get("returncode", 1)) == 0:
            effective_model = fallback_model
            fallback_used = True
        else:
            blocked_payload = satellite_multimodel_provider_switch_failure(
                attempted_model=selected_model,
                attempted_result=primary_switch,
                fallback_model=fallback_model or "none",
                fallback_result=fallback_switch,
            )
            result_payload = {
                **blocked_payload,
                "selected_model": effective_model,
                "requested_model": selected_model,
                "reason": str(route_decision.get("reason") or ""),
                "search_enabled": bool(route_decision.get("search_enabled")),
                "fallback_used": False,
                "run_id": run_id,
                "run_dir": str(run_dir.resolve()),
                "resolved_source_id": source_id,
            }
            satellite_multimodel_write_result_bundle(run_dir=run_dir, route_payload=route_payload, route_decision=route_decision, result_payload=result_payload)
            print(json.dumps(result_payload, ensure_ascii=False, indent=2) if getattr(args, "json", False) else satellite_multimodel_render_result_markdown(result_payload).strip())
            return 1

    prompt = satellite_multimodel_prompt(
        task_text=task_text,
        route=route_decision,
        need_citations=bool(getattr(args, "need_citations", False)),
        remote_images=mapped_images,
    )
    exec_result = satellite_multimodel_run_remote_codex_exec_json(
        remote_info,
        prompt=prompt,
        schema=satellite_multimodel_output_schema(),
        search_enabled=bool(route_decision.get("search_enabled")),
        remote_images=mapped_images,
        timeout=int(getattr(args, "timeout", 0) or SATELLITE_SESSION_DEFAULT_TIMEOUT),
    )
    write_json(run_dir / "remote-codex-exec-result.json", exec_result)

    parsed = exec_result.get("json") if isinstance(exec_result.get("json"), dict) else None
    if int(exec_result.get("returncode", 1)) != 0 or not isinstance(parsed, dict):
        failure_payload = satellite_multimodel_codex_failure_payload(exec_result)
        result_payload = {
            **failure_payload,
            "selected_model": effective_model,
            "requested_model": selected_model,
            "reason": str(route_decision.get("reason") or ""),
            "search_enabled": bool(route_decision.get("search_enabled")),
            "fallback_used": fallback_used,
            "run_id": run_id,
            "run_dir": str(run_dir.resolve()),
            "resolved_source_id": source_id,
        }
        satellite_multimodel_write_result_bundle(run_dir=run_dir, route_payload=route_payload, route_decision=route_decision, result_payload=result_payload)
        print(json.dumps(result_payload, ensure_ascii=False, indent=2) if getattr(args, "json", False) else satellite_multimodel_render_result_markdown(result_payload).strip())
        return 0 if result_payload["status"] == "blocked_needs_user" else 1

    result_payload = {
        "status": str(parsed.get("status") or "completed"),
        "response_text": str(parsed.get("response_text") or ""),
        "sources": normalize_list(parsed.get("sources")),
        "blocking_reason": str(parsed.get("blocking_reason") or ""),
        "next_action": str(parsed.get("next_action") or ""),
        "selected_model": effective_model,
        "requested_model": selected_model,
        "reason": str(route_decision.get("reason") or ""),
        "search_enabled": bool(route_decision.get("search_enabled")),
        "fallback_used": fallback_used,
        "blocked_needs_user": str(parsed.get("status") or "") == "blocked_needs_user",
        "run_id": run_id,
        "run_dir": str(run_dir.resolve()),
        "resolved_source_id": source_id,
        "remote_images": mapped_images,
    }
    if result_payload["status"] == "completed" and not str(result_payload.get("response_text") or "").strip():
        result_payload["status"] = "blocked_system"
        result_payload["blocking_reason"] = "remote_codex_structured_note_missing"
        result_payload["next_action"] = "Inspect remote-codex-exec-result.json and rerun after the black satellite returns a non-empty structured answer."
    satellite_multimodel_write_result_bundle(run_dir=run_dir, route_payload=route_payload, route_decision=route_decision, result_payload=result_payload)
    if getattr(args, "json", False):
        print(json.dumps(result_payload, ensure_ascii=False, indent=2))
    else:
        if str(result_payload.get("response_text") or "").strip():
            print(str(result_payload.get("response_text") or "").rstrip())
            print("")
        print(json.dumps(
            {
                "selected_model": result_payload["selected_model"],
                "reason": result_payload["reason"],
                "search_enabled": result_payload["search_enabled"],
                "fallback_used": result_payload["fallback_used"],
                "blocked_needs_user": result_payload["blocked_needs_user"],
                "run_id": result_payload["run_id"],
            },
            ensure_ascii=False,
            indent=2,
        ))
    return 0 if result_payload["status"] in {"completed", "failed_partial", "blocked_needs_user"} else 1


