def command_deploy_rdagent_fin_quant(args: argparse.Namespace) -> int:
    requested_alias = str(getattr(args, "alias", "") or RDAGENT_FIN_QUANT_DEFAULT_ALIAS)
    runtime_host_override = str(getattr(args, "runtime_host", "") or "").strip()
    runtime_source_override = str(getattr(args, "runtime_source_id", "") or "").strip()
    if runtime_host_override or runtime_source_override:
        binding = build_satellite_rdagent_runtime_binding(
            requested_alias=requested_alias,
            runtime_host=runtime_host_override,
            runtime_user=str(getattr(args, "runtime_user", "") or ""),
            runtime_port=int(getattr(args, "runtime_port", RDAGENT_FIN_QUANT_DEFAULT_PORT) or RDAGENT_FIN_QUANT_DEFAULT_PORT),
            runtime_workspace_root=str(getattr(args, "runtime_workspace_root", "") or RDAGENT_FIN_QUANT_DEFAULT_WORKSPACE_ROOT),
            runtime_conda_home=str(getattr(args, "runtime_conda_home", "") or RDAGENT_FIN_QUANT_DEFAULT_CONDA_HOME),
            runtime_env_name=str(getattr(args, "runtime_env_name", "") or RDAGENT_FIN_QUANT_DEFAULT_ENV_NAME),
            runtime_data_root=str(getattr(args, "runtime_data_root", "") or RDAGENT_FIN_QUANT_DEFAULT_DATA_ROOT),
            os_name=str(getattr(args, "os_name", "") or "linux"),
            arch=str(getattr(args, "arch", "") or "x86_64"),
            runtime_source_id=runtime_source_override,
            runtime_label=str(getattr(args, "runtime_label", "") or "rd-agent-fin-quant-runtime"),
            notes=str(getattr(args, "notes", "") or ""),
        )
        rows = upsert_satellite_rdagent_runtime_binding(load_satellite_rdagent_runtime_bindings(), binding)
        write_json(SATELLITE_RDAGENT_RUNTIME_BINDINGS_PATH, rows)

    contract = build_rdagent_fin_quant_control_plane_contract(requested_alias)
    ensure_dir(SATELLITE_RDAGENT_DEPLOYMENTS_ROOT)
    created_at = iso_now()
    stamp = parse_datetime(created_at).strftime("%Y%m%d-%H%M%S")
    run_dir = SATELLITE_RDAGENT_DEPLOYMENTS_ROOT / parse_datetime(created_at).strftime("%Y-%m-%d") / f"deploy-{stamp}"
    ensure_dir(run_dir)
    write_json(run_dir / "control-plane-contract.json", contract)
    (run_dir / "control-plane-contract.md").write_text(
        render_rdagent_fin_quant_control_plane_markdown(contract),
        encoding="utf-8",
    )

    next_action = contract.get("next_action", {}) if isinstance(contract.get("next_action"), dict) else {}
    target = contract.get("recommended_target", {}) if isinstance(contract.get("recommended_target"), dict) else {}
    summary: dict[str, Any] = {
        "generated_at": created_at,
        "requested_alias": requested_alias,
        "control_plane_source_id": str(contract.get("control_plane", {}).get("resolved_source_id") or ""),
        "next_action": next_action,
        "recommended_target": target,
        "env_file": str(getattr(args, "env_file", "") or ""),
    }
    if str(next_action.get("status") or "") != "ready" or not str(target.get("host") or "").strip():
        summary["status"] = "blocked_needs_user"
        summary["blocking_reason"] = str(next_action.get("action_id") or "missing_runtime_target")
        write_json(run_dir / "deployment-summary.json", summary)
        (run_dir / "deployment-summary.md").write_text(json.dumps(summary, ensure_ascii=False, indent=2), encoding="utf-8")
        print(f"run_dir: {run_dir.resolve()}")
        print(f"status: {summary['status']}")
        print(f"blocking_reason: {summary['blocking_reason']}")
        return 1

    deploy_command = [
        str(RDAGENT_FIN_QUANT_DEPLOY_SCRIPT),
        "--host",
        str(target.get("host") or ""),
        "--port",
        str(target.get("port") or RDAGENT_FIN_QUANT_DEFAULT_PORT),
        "--workspace-root",
        str(target.get("workspace_root") or RDAGENT_FIN_QUANT_DEFAULT_WORKSPACE_ROOT),
        "--conda-home",
        str(target.get("conda_home") or RDAGENT_FIN_QUANT_DEFAULT_CONDA_HOME),
        "--env-name",
        str(target.get("env_name") or RDAGENT_FIN_QUANT_DEFAULT_ENV_NAME),
        "--data-root",
        str(target.get("data_root") or RDAGENT_FIN_QUANT_DEFAULT_DATA_ROOT),
    ]
    if str(target.get("user") or "").strip():
        deploy_command.extend(["--user", str(target.get("user") or "")])
    env_file = str(getattr(args, "env_file", "") or "").strip()
    if env_file:
        deploy_command.extend(["--env-file", env_file])
    deploy_result = run_shell_command_capture(deploy_command, cwd=PROJECT_ROOT, timeout=int(getattr(args, "deploy_timeout", 0) or 1800))
    summary["deploy_command"] = deploy_command
    summary["deploy_result"] = deploy_result

    verify_result: dict[str, Any] = {}
    verify_command: list[str] = []
    if not bool(getattr(args, "skip_verify", False)):
        verify_command = [
            str(RDAGENT_FIN_QUANT_VERIFY_SCRIPT),
            "--host",
            str(target.get("host") or ""),
            "--port",
            str(target.get("port") or RDAGENT_FIN_QUANT_DEFAULT_PORT),
            "--workspace-root",
            str(target.get("workspace_root") or RDAGENT_FIN_QUANT_DEFAULT_WORKSPACE_ROOT),
            "--conda-home",
            str(target.get("conda_home") or RDAGENT_FIN_QUANT_DEFAULT_CONDA_HOME),
            "--env-name",
            str(target.get("env_name") or RDAGENT_FIN_QUANT_DEFAULT_ENV_NAME),
            "--data-root",
            str(target.get("data_root") or RDAGENT_FIN_QUANT_DEFAULT_DATA_ROOT),
            "--ui-check-mode",
            str(getattr(args, "ui_check_mode", "") or "warn"),
            "--health-check-mode",
            str(getattr(args, "health_check_mode", "") or "warn"),
            "--smoke-check-mode",
            str(getattr(args, "smoke_check_mode", "") or "warn"),
        ]
        if str(target.get("user") or "").strip():
            verify_command.extend(["--user", str(target.get("user") or "")])
        for flag, value in [
            ("--health-command", str(getattr(args, "health_command", "") or "")),
            ("--ui-command", str(getattr(args, "ui_command", "") or "")),
            ("--smoke-command", str(getattr(args, "smoke_command", "") or "")),
        ]:
            if value.strip():
                verify_command.extend([flag, value])
        verify_result = run_shell_command_capture(verify_command, cwd=PROJECT_ROOT, timeout=int(getattr(args, "verify_timeout", 0) or 1800))
    summary["verify_command"] = verify_command
    summary["verify_result"] = verify_result

    deploy_rc = int(deploy_result.get("returncode", 1))
    verify_rc = int(verify_result.get("returncode", 0)) if verify_result else 0
    if deploy_rc == 0 and verify_rc == 0:
        summary["status"] = "completed"
        summary["blocking_reason"] = ""
    else:
        summary["status"] = "blocked_system"
        summary["blocking_reason"] = "deploy_failed" if deploy_rc != 0 else "verify_failed"

    write_json(run_dir / "deployment-summary.json", summary)
    (run_dir / "deployment-summary.md").write_text(json.dumps(summary, ensure_ascii=False, indent=2), encoding="utf-8")
    print(f"run_dir: {run_dir.resolve()}")
    print(f"status: {summary['status']}")
    print(f"target_host: {target.get('host', '')}")
    print(f"blocking_reason: {summary['blocking_reason'] or 'none'}")
    return 0 if summary["status"] == "completed" else 1


